INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('82efdbaa-46e7-5eed-968c-d4f3a9d355f3', 'arabic-5eme', 'المفاعيل والحال', 'أتعرّف المفعول فيه (ظرف الزمان والمكان) والمفعول المطلق (المؤكِّد للفعل) والمفعول لأجله (السبب)، والحال التي تبيّن هيئة صاحبها، وأُعربها جميعًا منصوبةً', '# 🗺️ المفاعيل والحال — تتمّاتُ المعنى المنصوبة

> 💡 «الفعلُ والفاعلُ والمفعولُ به نواةُ الجملة؛ ثمّ تأتي تتمّاتٌ منصوبةٌ تجيبُ: متى؟ أين؟ كم؟ لماذا؟ وكيف؟»

تعلّمتَ المفعولَ به. والآن نفتحُ بابَ **المتمّمات المنصوبة** الأخرى: المفعول فيه، والمفعول المطلق، والمفعول لأجله، والحال. كلُّها **منصوبةٌ**، وكلُّها تزيدُ المعنى وضوحًا وثراءً. هيّا نجمعُها في خريطةٍ واحدة.

## 🏰 المفعول فيه (الظرف)

**المفعول فيه** اسمٌ منصوبٌ يدلُّ على **زمان** الفعل أو **مكانه**، ويتضمّنُ معنى «في».

- **ظرف زمان**: صباحًا، مساءً، ليلًا، يومَ، حينَ، ساعةَ.
- **ظرف مكان**: فوقَ، تحتَ، أمامَ، خلفَ، يمينَ، شمالَ، بينَ، عندَ.

*مثال: «وصلَ القطارُ صباحًا.» «صباحًا» مفعولٌ فيه (ظرف زمان) منصوب.*
*مثال: «وقفَ الحارسُ أمامَ البابِ.» «أمامَ» مفعولٌ فيه (ظرف مكان) منصوب.*

## ⚡ المفعول المطلق

**المفعول المطلق** مصدرٌ منصوبٌ من لفظ الفعل، يُذكرُ لـ**تأكيده** أو بيان **نوعه** أو **عدده**.

- **للتوكيد**: «فرحَ الطفلُ فرحًا.» (فرحًا تؤكّدُ الفعل).
- **لبيان النوع**: «سارَ سيرَ الواثقِ.» (تبيّنُ نوعَ السير).
- **لبيان العدد**: «دقَّ الجرسُ دقّتينِ.» (تبيّنُ العدد).

*علامتُه: مصدرٌ من جنس الفعل، منصوب.*

## 🔮 المفعول لأجله

**المفعول لأجله** مصدرٌ منصوبٌ يبيّنُ **سببَ** وقوع الفعل، يجيبُ عن سؤال «لماذا؟».

*مثال: «وقفَ التلاميذُ احترامًا للمعلّمِ.» «احترامًا» مفعولٌ لأجله (سببُ الوقوف) منصوب.*
*مثال: «سافرَ طلبًا للعلمِ.» «طلبًا» سببُ السفر.*

> 🗡️ سرُّ التمييز: اسأل «لماذا؟»؛ فإن وجدتَ مصدرًا يبيّنُ السببَ فهو مفعولٌ لأجله. «وقفَ احترامًا» = وقفَ **لأجلِ** الاحترام.

## 🛡️ الحال

**الحال** وصفٌ منصوبٌ يبيّنُ **هيئةَ** صاحبه (الفاعل أو المفعول) حين وقوع الفعل، ويجيبُ عن سؤال «كيف؟».

*مثال: «رجعَ الجنديُّ منتصرًا.» «منتصرًا» حالٌ تبيّنُ هيئةَ الجنديّ حين رجوعه.*
*مثال: «شربَ الطفلُ الماءَ صافيًا.» «صافيًا» حالٌ تبيّنُ هيئةَ الماء.*

- **صاحب الحال** يكون غالبًا معرفةً، و**الحال** نكرةٌ منصوبة.
- الحالُ تجيبُ «كيف كان؟» حين الفعل.

## 🧮 خريطةُ المتمّمات المنصوبة

| المتمّم | يجيبُ عن | مثال |
| --- | --- | --- |
| **المفعول فيه** | متى؟ أين؟ | سافرَ **ليلًا** / جلسَ **تحتَ** الشجرةِ |
| **المفعول المطلق** | كيف فعل بالضبط؟ كم؟ | فرحَ **فرحًا** / دقَّ **دقّتينِ** |
| **المفعول لأجله** | لماذا؟ | قامَ **إجلالًا** للضيفِ |
| **الحال** | كيف كان صاحبُه؟ | جاءَ **مسرعًا** |

> ⚠️ الفخّ الشائع: الخلطُ بين الحال والمفعول لأجله. الحالُ تبيّنُ **الهيئة** (كيف؟ → مسرعًا)، والمفعول لأجله يبيّنُ **السبب** (لماذا؟ → خوفًا). وانتبه: المفعول المطلق **مصدرٌ من لفظ الفعل**؛ فليس كلُّ منصوبٍ مفعولًا مطلقًا.

> 🏆 أحسنت أيّها الرسّامُ الماهر! رسمتَ خريطةَ المتمّمات المنصوبة: المفعول فيه (متى/أين)، والمطلق (التوكيد والعدد)، ولأجله (السبب)، والحال (الهيئة). أثرِ جُملَك بها فتصيرُ دقيقةً جميلة!', '# 📜 ملخّص: المفاعيل والحال

- **المفعول فيه (الظرف)**: اسمٌ منصوبٌ يدلّ على زمان الفعل أو مكانه ويتضمّن معنى «في»، مثل «سافرَ ليلًا» و«جلسَ تحتَ الشجرةِ».
- **المفعول المطلق**: مصدرٌ منصوبٌ من لفظ الفعل، يؤكّدُه أو يبيّنُ نوعَه أو عدده، مثل «فرحَ فرحًا» و«دقَّ دقّتينِ».
- **المفعول لأجله**: مصدرٌ منصوبٌ يبيّنُ سببَ الفعل (يجيبُ عن «لماذا؟»)، مثل «وقفَ احترامًا للمعلّمِ».
- **الحال**: وصفٌ منصوبٌ نكرةٌ يبيّنُ هيئةَ صاحبه (الفاعل أو المفعول) حين الفعل (يجيبُ عن «كيف؟»)، مثل «رجعَ الجنديُّ منتصرًا».
- **كلُّها منصوبة**، وكلُّها تتمّاتٌ تزيدُ المعنى وضوحًا.
- **الفخّ**: الحالُ تبيّنُ الهيئة (كيف؟) والمفعول لأجله يبيّنُ السبب (لماذا؟)؛ والمفعول المطلق مصدرٌ من لفظ الفعل لا أيُّ منصوب.', 5)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('1f55b2e3-8e5b-5718-9153-a8a2c8e081ff', 'arabic-5eme', 'كان وأخواتها وإنّ وأخواتها', 'أتعرّف النواسخ التي تدخل على الجملة الاسميّة: كان وأخواتها (ترفع المبتدأ اسمًا لها وتنصب الخبر)، وإنّ وأخواتها (تنصب المبتدأ اسمًا لها وترفع الخبر)، وأُعرب اسمَها وخبرَها', '# 🔮 كان وأخواتها وإنّ وأخواتها — النواسخ تقلبُ الجملة

> 💡 «الجملةُ الاسميّةُ مبتدأٌ وخبرٌ مرفوعان؛ فإذا دخلتها ناسخةٌ قلبت موازينَها: واحدةٌ تنصبُ الخبر، وأخرى تنصبُ الاسم.»

عرفتَ الجملةَ الاسميّة: مبتدأٌ مرفوعٌ وخبرٌ مرفوع («السماءُ صافيةٌ»). لكن هناك كلماتٌ إذا دخلت عليها **غيّرت إعرابَها**؛ تُسمّى **النواسخ**. وهي فريقان: **كان وأخواتها** (أفعال)، و**إنّ وأخواتها** (حروف). هيّا نتعلّم كيف تقلبُ كلٌّ منهما الجملة.

## 🏰 كان وأخواتها (الأفعال الناسخة)

**كان وأخواتها** أفعالٌ ناقصةٌ تدخلُ على الجملة الاسميّة فـ**ترفعُ المبتدأ اسمًا لها**، و**تنصبُ الخبر خبرًا لها**.

*مثال: «السماءُ صافيةٌ» (مبتدأٌ وخبرٌ مرفوعان).*
*← «كانتِ السماءُ صافيةً.» «السماءُ» اسمُ كان مرفوع، «صافيةً» خبرُ كان منصوب.*

أخواتُها: **كان، أصبحَ، أمسى، أضحى، ظلَّ، باتَ، صارَ، ليسَ، ما زالَ، ما فتئَ، ما دامَ**.

- بعضُها يدلُّ على **اقتران الخبر بزمنٍ**: كان (الماضي)، أصبح (الصباح)، أمسى (المساء)، بات (الليل)، ظلّ (النهار).
- **صارَ** تدلّ على التحوّل، **ليسَ** على النفي، **ما زالَ/ما فتئَ** على الاستمرار.

> 🗡️ قاعدةُ كان: ما كان مرفوعًا (المبتدأ) يبقى مرفوعًا اسمًا لها، وما كان خبرًا **يُنصَب**. «الجوُّ باردٌ» ← «أصبحَ الجوُّ باردًا».

## ⚡ إنّ وأخواتها (الحروف الناسخة)

**إنّ وأخواتها** حروفٌ تدخلُ على الجملة الاسميّة فـ**تنصبُ المبتدأ اسمًا لها**، و**ترفعُ الخبر خبرًا لها**. (عكسُ عمل كان!)

*مثال: «العلمُ نورٌ» (مبتدأٌ وخبرٌ مرفوعان).*
*← «إنّ العلمَ نورٌ.» «العلمَ» اسمُ إنّ منصوب، «نورٌ» خبرُ إنّ مرفوع.*

أخواتُها ومعانيها:
- **إنّ، أنّ**: للتوكيد.
- **لكنّ**: للاستدراك.
- **كأنّ**: للتشبيه.
- **ليتَ**: للتمنّي.
- **لعلّ**: للترجّي والإشفاق.

> 🛡️ قاعدةُ إنّ: المبتدأ (المرفوع) **يُنصَب** اسمًا لها، والخبرُ يبقى مرفوعًا. «الطالبُ مجتهدٌ» ← «إنّ الطالبَ مجتهدٌ».

## 🧮 جدولُ المقارنة

| الناسخ | عملُه في الاسم | عملُه في الخبر |
| --- | --- | --- |
| **كان وأخواتها** (أفعال) | ترفعُه (اسمُها مرفوع) | تنصبُه (خبرُها منصوب) |
| **إنّ وأخواتها** (حروف) | تنصبُه (اسمُها منصوب) | ترفعُه (خبرُها مرفوع) |

*تذكّر: كان **ترفعُ ثمّ تنصبُ**، وإنّ **تنصبُ ثمّ ترفعُ**.*

> ⚠️ الفخّ الشائع: عكسُ العمل. لا تقل «إنّ العلمُ نورًا»! الصواب «إنّ العلمَ نورٌ» (الاسمُ منصوبٌ والخبرُ مرفوع). وكذلك «كان الجوُّ باردٌ» خطأ؛ الصواب «كان الجوُّ باردًا» (الخبرُ منصوب). راقِب أيُّهما فعلٌ (كان) وأيُّهما حرفٌ (إنّ).

> 🏆 أحسنت أيّها الساحر! صرتَ تعرفُ النواسخ: كان وأخواتها ترفعُ الاسمَ وتنصبُ الخبر، وإنّ وأخواتها تنصبُ الاسمَ وترفعُ الخبر. اقلبِ الجملةَ بثقةٍ وأعرِبها صحيحةً!', '# 📜 ملخّص: كان وأخواتها وإنّ وأخواتها

- **النواسخ** كلماتٌ تدخل على الجملة الاسميّة فتغيّرُ إعرابها؛ فريقان: كان وأخواتها (أفعال) وإنّ وأخواتها (حروف).
- **كان وأخواتها**: ترفعُ المبتدأ **اسمًا لها** وتنصبُ الخبر **خبرًا لها**، مثل «كانتِ السماءُ صافيةً».
- **أخوات كان**: كان، أصبحَ، أمسى، أضحى، ظلَّ، باتَ، صارَ، ليسَ، ما زالَ، ما فتئَ، ما دامَ.
- **إنّ وأخواتها**: تنصبُ المبتدأ **اسمًا لها** وترفعُ الخبر **خبرًا لها** (عكسُ كان)، مثل «إنّ العلمَ نورٌ».
- **أخوات إنّ**: إنّ وأنّ (توكيد)، لكنّ (استدراك)، كأنّ (تشبيه)، ليتَ (تمنٍّ)، لعلّ (ترجٍّ).
- **القاعدة**: كان ترفعُ ثمّ تنصبُ، وإنّ تنصبُ ثمّ ترفعُ.
- **الفخّ**: لا نعكسُ العمل: «إنّ العلمَ نورٌ» لا «العلمُ نورًا»، و«كان الجوُّ باردًا» لا «باردٌ».', 6)
ON CONFLICT (id) DO UPDATE SET
