  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order) VALUES
  ('eb28b668-2a4c-57aa-b6bf-3e730fedc84e', 'arabic-5eme', 'الصرف: الفعل المجرّد والمزيد والميزان الصرفيّ', 'أميّز الفعل الثلاثيّ المجرّد (حروفُه أصليّة) من المزيد (طرأت عليه زيادة)، وأزِنُ الفعل على الميزان الصرفيّ (فعل)، وأتعرّف أوزان المزيد مثل فعّل وأفعل وفاعل وتفعّل وانفعل واستفعل', '# ⚖️ الصرف: المجرّد والمزيد — ميزانُ الكلمات

> 💡 «لكلّ فعلٍ هيكلٌ من حروفٍ أصليّة؛ فإن زدتَ عليه حرفًا تغيّر وزنُه ومعناه. والميزانُ الصرفيُّ يكشفُ الأصلَ من الزائد.»

في **الصرف** ندرسُ بنيةَ الكلمة: ممّ تتكوّن؟ وما الأصليُّ فيها وما الزائد؟ أداتُنا هي **الميزان الصرفيّ**: ثلاثةُ حروفٍ نموذجيّة **ف ع ل** نزِنُ بها الأفعال. هيّا نتعلّم كيف نزِنُ ونميّزُ المجرّدَ من المزيد.

## 🏰 الفعل الثلاثيّ المجرّد

**الفعل الثلاثيّ المجرّد** هو فعلٌ حروفُه **كلُّها أصليّة** (ثلاثةٌ)، لا زيادةَ فيه.

*مثال: كَتَبَ، نَصَرَ، فَتَحَ، جَلَسَ.*

وزنُه على الميزان: **فَعَلَ** (الكافُ تقابلُ الفاء، والتاءُ العين، والباءُ اللام).

| الفعل | ف | ع | ل |
| --- | --- | --- | --- |
| كَتَبَ | كَ | تَ | بَ |
| جَلَسَ | جَ | لَ | سَ |

## ⚡ الميزان الصرفيّ: كيف نزِنُ؟

نقابلُ حروفَ الفعل الأصليّة بحروف الميزان **ف ع ل** بالترتيب:
- الحرفُ الأوّل ← **الفاء**.
- الحرفُ الثاني ← **العين**.
- الحرفُ الثالث ← **اللام**.

ونضبطُ الميزانَ بنفس حركات الفعل. *كَتَبَ ← فَعَلَ. عَلِمَ ← فَعِلَ. كَرُمَ ← فَعُلَ.*

> 🗡️ قاعدةُ الوزن: ننقلُ حركاتِ الفعل إلى الميزان كما هي، ونزيدُ في الميزان مثلَ ما زِيدَ في الفعل تمامًا.

## 🔮 الفعل الثلاثيّ المزيد

**الفعل المزيد** هو فعلٌ ثلاثيٌّ **طرأت عليه زيادةٌ** (حرفٌ أو أكثر) لتغيير المعنى. نعرفُه بأنّ حروفه أكثرُ من ثلاثة.

نزِنُه بزيادة **نفس الحرف الزائد** في الميزان:
- **بزيادة حرفٍ واحد**: قدَّمَ ← فعَّل، أقبلَ ← أفعَل، ساعدَ ← فاعَل.
- **بزيادة حرفين**: تقدّمَ ← تفعّل، تراسلَ ← تفاعل، انتصرَ ← افتعل، انسحبَ ← انفعل، اصفرَّ ← افعَلَّ.
- **بزيادة ثلاثة أحرف**: استقبلَ ← استفعَل.

> 🛡️ سرُّ الوزن مع الزيادة: الحرفُ الزائدُ يُكتبُ في الميزان **كما هو** (الهمزة، التاء، السين، النون…)، أمّا الحرفُ المضاعَفُ (الشدّة) فنزنُه بتكرار حرف الميزان: «قدَّم» العينُ مشدّدةٌ ← **فعَّل**.

## 🧮 جدولُ الأوزان

| الفعل | الوزن | نوع الزيادة |
| --- | --- | --- |
| نَصَرَ | فَعَلَ | مجرّد (لا زيادة) |
| علَّمَ | فعَّلَ | تضعيف العين |
| أكرمَ | أفعَلَ | همزةٌ في الأوّل |
| قاتلَ | فاعَلَ | ألفٌ بعد الفاء |
| تعلّمَ | تفعَّلَ | تاءٌ + تضعيف |
| انكسرَ | انفعَلَ | همزةُ وصل + نون |
| استخرجَ | استفعَلَ | همزةُ وصل + سين + تاء |

> ⚠️ الفخّ الشائع: الخلطُ في موضع الزيادة. في «استقبل» (استفعل) السينُ والتاءُ والهمزةُ زوائد، والأصلُ «ق ب ل». ولا تعُدَّ حرفًا أصليًّا زائدًا: في «جلس» لا زيادةَ فهو مجرّدٌ على فعَل. وانتبه: الحركاتُ تُنقلُ كما هي.

> 🏆 أحسنت أيّها الصائغ! صرتَ تزِنُ الأفعالَ على ف ع ل، وتميّزُ المجرّدَ (ثلاثةُ أحرفٍ أصليّة) من المزيد (طرأت عليه زيادة)، وتعرفُ أوزانَه: فعّل، أفعل، فاعل، تفعّل، انفعل، استفعل. صُغِ الكلماتِ بميزانك الدقيق!', '# 📜 ملخّص: الصرف — المجرّد والمزيد والميزان الصرفيّ

- **الفعل الثلاثيّ المجرّد**: حروفُه كلُّها أصليّة (ثلاثة)، لا زيادةَ فيه، وزنُه **فَعَلَ**، مثل كَتَبَ ونَصَرَ.
- **الميزان الصرفيّ**: نقابلُ الحرفَ الأوّل بالفاء، والثاني بالعين، والثالث باللام، وننقلُ الحركاتِ كما هي.
- **الفعل المزيد**: ثلاثيٌّ طرأت عليه زيادةٌ لتغيير المعنى، حروفُه أكثرُ من ثلاثة.
- **أوزانٌ بزيادة حرف**: فعَّل (قدَّم)، أفعَل (أقبل)، فاعَل (ساعد).
- **أوزانٌ بزيادة حرفين**: تفعَّل (تقدّم)، تفاعل (تراسل)، افتعل (انتصر)، انفعل (انسحب)، افعَلَّ (اصفرَّ).
- **بزيادة ثلاثة أحرف**: استفعَل (استقبل).
- **القاعدة**: نزيدُ في الميزان مثلَ الزيادة في الفعل، والحرفُ المشدّدُ نزنُه بتكرار حرف الميزان.', 7)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
