INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('81586604-38e9-518f-a60d-14ee5dd321b1', '4855eba1-31f2-5be2-ae64-35b2d6cacb5b', 'ما الفكرة العامّة لنصٍّ يحكي كيف أنقذَ كلبٌ وفيٌّ طفلًا سقطَ في النهر، فحمله إلى أهله؟', '[{"id":"a","text":"وصفُ النهر في الصيف"},{"id":"b","text":"وفاءُ كلبٍ ينقذُ طفلًا من الغرق"},{"id":"c","text":"أنواعُ الأسماك في النهر"},{"id":"d","text":"لعبُ الأطفال قُربَ الماء"}]'::jsonb, 'b', 'الفكرة العامّة تلخّصُ موضوع النصّ كلِّه في جملةٍ: النصُّ يدورُ حول كلبٍ وفيٍّ أنقذَ طفلًا. الباقي تفاصيلُ صغيرةٌ لا تمثّلُ الموضوع الشامل.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
