INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('72da6b70-7f65-5c36-b15e-940c3fb54ecd', '4855eba1-31f2-5be2-ae64-35b2d6cacb5b', 'في جملة «ارتعشت يدا الطفلِ وتصبّبَ جبينُه عرقًا»، ماذا نستنتجُ عن حال الطفل؟', '[{"id":"a","text":"أنّه نائمٌ"},{"id":"b","text":"أنّه فرحٌ"},{"id":"c","text":"أنّه خائفٌ"},{"id":"d","text":"أنّه جائعٌ"}]'::jsonb, 'c', 'الكاتبُ لم يقل «خائف» صراحةً، لكنّ ارتعاشَ اليدين وتصبّبَ العرق قرينتان تدلّان على الخوف. هذا هو الفهمُ الضمنيّ بجمع القرائن.', 4)
