INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0e1c4d43-3460-5a88-b3ba-f8d8512daf44', '4855eba1-31f2-5be2-ae64-35b2d6cacb5b', 'ما الفرقُ بين الفكرة العامّة والفكرة الجزئيّة؟', '[{"id":"a","text":"لا فرقَ بينهما"},{"id":"b","text":"الجزئيّةُ تشملُ النصَّ كلَّه والعامّةُ خاصّةٌ بفقرة"},{"id":"c","text":"كلتاهما تخصُّ فقرةً واحدة"},{"id":"d","text":"العامّةُ تشملُ النصَّ كلَّه والجزئيّةُ تخصُّ فقرةً واحدة"}]'::jsonb, 'd', 'الفكرة العامّة هي موضوع النصّ كلِّه، أمّا الفكرة الجزئيّة فتخصُّ فقرةً واحدةً وتخدمُ الفكرة العامّة. مجموعُ الجزئيّات يبني العامّة.', 5)
