INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d7042105-1793-5b14-b576-67cedd42ac98', '0ff35ad8-3c82-53d9-a74d-738c95412a88', 'اقرأ: «خرجَ سميرٌ صباحًا إلى الحديقة، فوجدَ عصفورًا صغيرًا سقطَ من عشّه، فحمله برفقٍ وأعاده إلى أمّه.» مَن بطلُ هذا النصّ؟', '[{"id":"a","text":"سميرٌ"},{"id":"b","text":"العصفورُ الكبير"},{"id":"c","text":"أمُّ سميرٍ"},{"id":"d","text":"البستانيُّ"}]'::jsonb, 'a', 'البطلُ هو الشخصيّةُ التي تقومُ بالعمل الرئيسيّ. سميرٌ هو الذي خرجَ وحملَ العصفورَ وأعاده، فهو بطلُ النصّ.', 1)
