INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7af4d7fc-2e94-5fba-be82-5c16bcc518e6', '0ff35ad8-3c82-53d9-a74d-738c95412a88', 'من جملة «حمله برفقٍ وأعاده إلى أمّه»، ماذا نستنتجُ عن سميرٍ؟', '[{"id":"a","text":"أنّه رحيمٌ ويحبُّ الحيوان"},{"id":"b","text":"أنّه خائفٌ من العصفور"},{"id":"c","text":"أنّه يكرهُ الحديقة"},{"id":"d","text":"أنّه نائمٌ"}]'::jsonb, 'a', 'حملُه العصفورَ «برفقٍ» وإعادتُه إلى أمّه قرينتان تدلّان على الرحمة وحبّ الحيوان، وإن لم يقل النصُّ ذلك صراحةً.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bb67be3d-4db2-5acb-a6dc-bdab292c8dac', '0ff35ad8-3c82-53d9-a74d-738c95412a88', 'أيُّ ترتيبٍ صحيحٌ لأحداث النصّ؟', '[{"id":"a","text":"أعاد العصفورَ ← خرجَ ← وجدَه"},{"id":"b","text":"خرجَ سميرٌ ← وجدَ العصفورَ ← أعاده إلى أمّه"},{"id":"c","text":"وجدَ العصفورَ ← أعاده ← خرجَ"},{"id":"d","text":"أعاده ← وجدَه ← خرجَ"}]'::jsonb, 'b', 'نتتبّعُ روابط الزمن: أوّلًا «خرجَ»، ثمّ «وجدَ» العصفورَ، وأخيرًا «أعاده» إلى أمّه. هذا هو التسلسلُ الصحيح.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('1ac029aa-56e3-5357-8304-36d0cb52480f', 'd1bccf61-005c-5371-b50f-f310425217ed', 'arabic-5eme', '⚔️ زعيم الفصل ⭐⭐⭐: حارسُ النصّ الطويل (صعب)', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
