  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6de0352c-a0ef-5624-a2e8-7c5966394a8a', '1ac029aa-56e3-5357-8304-36d0cb52480f', 'اقرأ: «كانت ليلى تخافُ الظلامَ. وذاتَ ليلةٍ انطفأ المصباحُ فجأةً. تذكّرت أنّ الشجاعةَ تُغلبُ بها المخاوفُ، فأشعلت شمعةً صغيرةً وابتسمت.» ما الفكرة العامّة؟', '[{"id":"a","text":"وصفُ المصباح"},{"id":"b","text":"أنواعُ الشموع"},{"id":"c","text":"كيف تغلبت ليلى على خوفها من الظلام"},{"id":"d","text":"موعدُ نوم ليلى"}]'::jsonb, 'c', 'النصُّ كلُّه يدورُ حول انتصار ليلى على خوفها بالشجاعة. الوصفُ والأنواعُ والموعدُ تفاصيلُ هامشيّةٌ أو غيرُ موجودة، لا تمثّلُ الموضوع.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1a5b579d-9d6d-5233-bbae-6a057ff5666b', '1ac029aa-56e3-5357-8304-36d0cb52480f', 'في النصّ نفسه، ما العقدةُ (المشكلةُ التي ظهرت)؟', '[{"id":"a","text":"انطفاءُ المصباح فجأةً"},{"id":"b","text":"نومُ ليلى مبكّرًا"},{"id":"c","text":"خروجُها إلى الحديقة"},{"id":"d","text":"شراءُ شمعةٍ جديدة"}]'::jsonb, 'a', 'العقدةُ هي الحدثُ الذي يقلبُ الموقفَ ويُحدثُ التوتّر. انطفاءُ المصباح فجأةً وليلى تخافُ الظلامَ هو العقدةُ التي بُنيت عليها القصّة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bed51c42-c103-52eb-8635-37ae763ba41c', '1ac029aa-56e3-5357-8304-36d0cb52480f', 'كيف حُلّت العقدةُ في النصّ؟', '[{"id":"a","text":"بكاءُ ليلى ونومُها"},{"id":"b","text":"خروجُها هاربةً"},{"id":"c","text":"نداءُ أمّها"},{"id":"d","text":"إشعالُها شمعةً بشجاعةٍ وابتسامُها"}]'::jsonb, 'd', 'الحلُّ هو نهايةُ القصّة التي تُزيلُ التوتّر. تذكّرت ليلى الشجاعةَ فأشعلت شمعةً وابتسمت، فهذا هو الحلّ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('50d96901-6a22-537f-b7b3-94e33fb1270d', '1ac029aa-56e3-5357-8304-36d0cb52480f', 'من قولها «تذكّرت أنّ الشجاعةَ تُغلبُ بها المخاوفُ»، ماذا نستنتجُ؟', '[{"id":"a","text":"أنّ ليلى تكرهُ الشموع"},{"id":"b","text":"أنّ ليلى قرّرت أن تواجه خوفها لا أن تستسلم له"},{"id":"c","text":"أنّ ليلى نسيت كلَّ شيء"},{"id":"d","text":"أنّ المصباح عاد يعمل"}]'::jsonb, 'b', 'تذكُّرها أنّ الشجاعة تغلبُ المخاوفَ، ثمّ فعلُها (إشعالُ الشمعة)، قرينتان على أنّها قرّرت المواجهة لا الاستسلام. هذا فهمٌ ضمنيٌّ بربط القرينة بالفعل.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ef072101-7ab7-5d0e-a540-dc30921cb9fa', '1ac029aa-56e3-5357-8304-36d0cb52480f', 'أيُّ عنوانٍ أنسبُ لهذا النصّ؟', '[{"id":"a","text":"رحلةٌ إلى البحر"},{"id":"b","text":"يومٌ في السوق"},{"id":"c","text":"شمعةُ الشجاعة"},{"id":"d","text":"ألوانُ الفصول"}]'::jsonb, 'c', 'العنوانُ الجيّدُ يلمّحُ إلى الفكرة العامّة. «شمعةُ الشجاعة» تجمعُ بين أداة الحلّ (الشمعة) ومعناه (الشجاعة)، فهو الأنسبُ. الباقي بعيدٌ عن الموضوع.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b96dbed0-2f69-5b3f-9b51-ce020fad61d4', '1ac029aa-56e3-5357-8304-36d0cb52480f', 'ما الفرقُ بين «رأي الكاتب» و«رأي الشخصيّة» في نصٍّ سرديّ؟', '[{"id":"a","text":"رأيُ الكاتب هو موقفُه الذي يقصدُ إيصالَه، ورأيُ الشخصيّة قولٌ على لسانها داخل القصّة"},{"id":"b","text":"لا فرقَ، هما الشيءُ نفسُه"},{"id":"c","text":"رأيُ الكاتب يُكتبُ في الغلاف فقط"},{"id":"d","text":"رأيُ الشخصيّة دائمًا خطأ"}]'::jsonb, 'a', 'قد تقولُ شخصيّةٌ في القصّة قولًا لا يوافقُه الكاتبُ. فلا نَنسبُ كلَّ ما في النصّ إلى الكاتب؛ نميّزُ بين موقفه ومقولات شخصياته. الخلطُ بينهما خطأٌ شائع.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('07a44b40-db31-5d39-af28-68faaba1a7a4', 'd1bccf61-005c-5371-b50f-f310425217ed', 'arabic-5eme', '📝 مراجعة ⭐⭐: أدواتُ القارئ (متوسط)', 2, 75, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
