INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('504cfda8-0a3b-5d63-b31d-36400eb25afe', '07a44b40-db31-5d39-af28-68faaba1a7a4', 'أيُّ هذه الأدوات تدلُّ على نهاية الأحداث في القصّة؟', '[{"id":"a","text":"أوّلًا"},{"id":"b","text":"في البداية"},{"id":"c","text":"ثمّ"},{"id":"d","text":"في النهاية"}]'::jsonb, 'd', '«في النهاية» رابطُ زمنٍ يدلُّ على آخر الأحداث. أمّا «أوّلًا» و«في البداية» فللبداية، و«ثمّ» للوسط.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('73b591a3-4e0e-5af3-ae96-1da38caa4cfc', '07a44b40-db31-5d39-af28-68faaba1a7a4', 'الفهمُ الضمنيُّ هو أن:', '[{"id":"a","text":"نعيدَ كتابة النصّ"},{"id":"b","text":"نعدَّ كلماتِ النصّ"},{"id":"c","text":"نستنتجَ ما لمّحَ إليه الكاتبُ دون أن يصرّح به"},{"id":"d","text":"نحفظَ النصَّ غيبًا"}]'::jsonb, 'c', 'الفهمُ الضمنيُّ هو جمعُ القرائن لكشف ما لم يُذكر صراحةً. أمّا إعادةُ الكتابة والعدُّ والحفظُ فأعمالٌ أخرى لا علاقة لها بالاستنتاج.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cfa7104f-d69e-537b-97f9-2c4fa677e713', '07a44b40-db31-5d39-af28-68faaba1a7a4', 'اقرأ: «دخلَ الفصلَ فابتسمَ التلاميذُ وصفّقوا له بحرارةٍ.» ماذا نستنتجُ؟', '[{"id":"a","text":"أنّ التلاميذَ غاضبون"},{"id":"b","text":"أنّ التلاميذَ سعداءُ بقدومه ويحبّونه"},{"id":"c","text":"أنّ الفصلَ فارغٌ"},{"id":"d","text":"أنّ الدرسَ انتهى"}]'::jsonb, 'b', 'الابتسامُ والتصفيقُ بحرارةٍ قرينتان تدلّان على الفرح والمحبّة. نستنتجُ أنّ التلاميذَ سعداءُ بقدومه، وإن لم يُقل ذلك صراحةً.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3d458d1b-fff2-5dd9-9d65-3de9aafbf54a', '07a44b40-db31-5d39-af28-68faaba1a7a4', 'ما الذي يربطُ الفكرةَ الجزئيّةَ بالفكرة العامّة؟', '[{"id":"a","text":"الفكرةُ الجزئيّةُ تخدمُ الفكرةَ العامّةَ، ومجموعُ الجزئيّات يبني العامّة"},{"id":"b","text":"لا علاقةَ بينهما"},{"id":"c","text":"الفكرةُ العامّةُ تخصُّ فقرةً واحدةً فقط"},{"id":"d","text":"الفكرةُ الجزئيّةُ تشملُ النصَّ كلَّه"}]'::jsonb, 'a', 'كلُّ فقرةٍ لها فكرةٌ جزئيّةٌ تخدمُ موضوعَ النصّ؛ فإذا جمعتَ الجزئيّاتِ بنيتَ الفكرةَ العامّة. الخياراتُ الأخرى تقلبُ هذا المعنى.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('69466006-3680-5e5b-ab2e-56199263b85f', '07a44b40-db31-5d39-af28-68faaba1a7a4', 'لماذا لا نحكمُ على موضوع النصّ من أوّل سطرٍ فقط؟', '[{"id":"a","text":"لأنّ السطرَ الأوّلَ لا يُقرأ"},{"id":"b","text":"لأنّ النصوصَ كلَّها قصيرة"},{"id":"c","text":"لأنّ العنوانَ يكفي وحده"},{"id":"d","text":"لأنّ النصَّ الطويلَ قد يبدأ بفكرةٍ ثمّ يطوّرها أو يغيّرها"}]'::jsonb, 'd', 'النصُّ الطويلُ قد يستهلُّ بفكرةٍ ثمّ ينتقلُ إلى أخرى، فالحكمُ المتسرّعُ من أوّل سطرٍ خطأ. نقرأ النصَّ كاملًا قبل تحديد الفكرة العامّة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('71267bf6-d6d4-5620-a755-ebc558eaab15', '07a44b40-db31-5d39-af28-68faaba1a7a4', 'اقرأ: «أمسكَ الحقيبةَ وركضَ نحو المحطّةِ، فانطلقت الحافلةُ أمامَ عينيه.» ما العقدةُ؟', '[{"id":"a","text":"شراءُ الحقيبة"},{"id":"b","text":"نومُه في البيت"},{"id":"c","text":"فواتُ الحافلةِ عليه رغمَ ركضِه"},{"id":"d","text":"وصولُه مبكّرًا"}]'::jsonb, 'c', 'العقدةُ مشكلةٌ تُحدثُ توتّرًا. ركضَ نحو المحطّة لكنّ الحافلةَ انطلقت أمامه ففاتته؛ هذا هو الحدثُ المعقِّد. الخياراتُ الأخرى لا توتّرَ فيها أو لم تُذكر.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('98cf4fed-3aad-50a1-928a-91d5338033de', 'd1bccf61-005c-5371-b50f-f310425217ed', 'arabic-5eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: سيّدُ الفهم العميق', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
