INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5be86c30-d958-5bda-a60d-09014c3b8e3e', '98cf4fed-3aad-50a1-928a-91d5338033de', 'اقرأ: «نظرَ الفلاحُ إلى السماء الملبّدة بالغيوم، فابتسمَ ورفعَ يديه شاكرًا، ثمّ أسرعَ يجهّزُ المحراثَ.» لماذا ابتسمَ الفلاحُ؟', '[{"id":"a","text":"لأنّه يكرهُ المطر"},{"id":"b","text":"لأنّ الغيومَ تبشّرُ بمطرٍ ينفعُ زرعَه"},{"id":"c","text":"لأنّه انتهى من العمل"},{"id":"d","text":"لأنّ المحراثَ جديد"}]'::jsonb, 'b', 'الفلاحُ يحتاجُ المطرَ لزرعه؛ فالغيومُ تبشّرُ به، لذلك ابتسمَ وشكرَ وأسرعَ يجهّزُ المحراثَ استعدادًا. نربطُ القرائنَ (الغيوم + الشكر + تجهيز المحراث) لنستنتجَ السبب.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e9569121-d4c9-5c35-9d8e-82ec98122a5c', '98cf4fed-3aad-50a1-928a-91d5338033de', 'في النصّ نفسه، ما الذي نستنتجُه من إسراعه يجهّزُ المحراثَ بعد رؤية الغيوم؟', '[{"id":"a","text":"أنّه سيسافرُ بعيدًا"},{"id":"b","text":"أنّه قرّر النومَ"},{"id":"c","text":"أنّه يكرهُ الزراعة"},{"id":"d","text":"أنّه يستعدُّ للحرث والبذر قبل نزول المطر"}]'::jsonb, 'd', 'تجهيزُ المحراث عملٌ زراعيٌّ يسبقُ الحرثَ والبذر. إسراعُه بعد رؤية الغيوم يدلُّ على أنّه يستعدُّ لاستثمار المطر القادم. القرينةُ (المحراث) تكشفُ النيّة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2d0dfe49-2d9d-5e3e-8d76-e86679ea1516', '98cf4fed-3aad-50a1-928a-91d5338033de', 'اقرأ جملتين: (1) «قال المعلّمُ: الكسلُ آفةٌ.» (2) «كان التلميذُ كسولًا فندِمَ.» أيُّهما يحملُ رأيًا مباشرًا عن الكسل؟', '[{"id":"a","text":"الجملة (1)، لأنّها قولٌ صريحٌ يحكمُ على الكسل بأنّه آفة"},{"id":"b","text":"الجملة (2) فقط"},{"id":"c","text":"كلتاهما لا رأيَ فيهما"},{"id":"d","text":"لا يمكنُ معرفةُ ذلك"}]'::jsonb, 'a', 'الجملة (1) حكمٌ صريحٌ مباشرٌ على الكسل («آفة»). أمّا (2) فتحكي حدثًا (ندمَ التلميذ) نستنتجُ منه الموقفَ ضمنًا. الرأيُ المباشرُ في (1).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ca76ccaa-390c-5567-b057-c5b86e9223ba', '98cf4fed-3aad-50a1-928a-91d5338033de', 'اقرأ: «أوّلًا فتحَ النافذةَ، ثمّ سمعَ صوتًا غريبًا، فخرجَ ليتفقّدَ الأمرَ، وأخيرًا اطمأنَّ وعادَ.» أيُّ ترتيبٍ يطابقُ النصّ؟', '[{"id":"a","text":"سمعَ الصوتَ ← عادَ ← فتحَ النافذةَ"},{"id":"b","text":"خرجَ ← اطمأنَّ ← فتحَ النافذةَ"},{"id":"c","text":"فتحَ النافذةَ ← سمعَ صوتًا ← خرجَ ليتفقّدَ ← اطمأنَّ وعادَ"},{"id":"d","text":"اطمأنَّ ← خرجَ ← سمعَ ← فتحَ"}]'::jsonb, 'c', 'روابطُ الزمن ترشدُنا: «أوّلًا» فتحَ، «ثمّ» سمعَ، «فخرجَ» ليتفقّد، «وأخيرًا» اطمأنَّ وعادَ. هذا هو التسلسلُ المطابقُ للنصّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a9414e27-d033-5b44-9277-ec70807deaba', '98cf4fed-3aad-50a1-928a-91d5338033de', 'نصٌّ يصفُ مدينةً ثمّ يحكي زيارةَ طفلٍ لها وما رآه فيها. ما النمطُ الغالبُ على هذا النصّ؟', '[{"id":"a","text":"نصٌّ حجاجيٌّ يدافعُ عن رأي"},{"id":"b","text":"نصٌّ يمزجُ الوصفَ (المدينة) بالسرد (زيارة الطفل وأحداثها)"},{"id":"c","text":"نصٌّ رياضيٌّ فيه أرقامٌ فقط"},{"id":"d","text":"قائمةُ مشترياتٍ"}]'::jsonb, 'b', 'وصفُ المدينة نمطٌ وصفيٌّ، وحكايةُ زيارة الطفل وأحداثها نمطٌ سرديٌّ؛ فالنصُّ يمزجُ النمطين. لا حجاجَ فيه ولا أرقامَ ولا قائمة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('60ebbf91-1c9d-5bea-b134-0684fba585e0', '98cf4fed-3aad-50a1-928a-91d5338033de', 'اقرأ: «ابتعدَ عن الكتاب، ونظرَ إلى اللوحِ طويلًا، ثمّ عضَّ قلمَه وأطرقَ.» ما الحالةُ التي تلمّحُ إليها هذه القرائنُ؟', '[{"id":"a","text":"الفرحُ الشديد"},{"id":"b","text":"النعاسُ والنوم"},{"id":"c","text":"الحَيرةُ والتفكيرُ في حلِّ مسألةٍ صعبة"},{"id":"d","text":"الغضبُ من صديقه"}]'::jsonb, 'c', 'النظرُ الطويلُ إلى اللوح، وعضُّ القلم، والإطراقُ قرائنُ مجتمعةٌ تدلُّ على الحَيرة والتفكير العميق في حلٍّ، لا على الفرح أو النوم أو الغضب. نجمعُ القرائنَ لنستنتجَ الحالة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('4514829a-cc9a-516e-9b5c-9c64fc9f5e93', 'd1bccf61-005c-5371-b50f-f310425217ed', 'arabic-5eme', '🛡️ تدريب ⭐⭐⭐: فهمُ المقروء (مراجعة شاملة)', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e42dfa5d-ff15-5674-984f-35825fa9d317', '4514829a-cc9a-516e-9b5c-9c64fc9f5e93', 'السؤالُ «مَن بطلُ القصّة؟» يكشفُ لنا عن:', '[{"id":"a","text":"الشخصيات"},{"id":"b","text":"الزمان"},{"id":"c","text":"المكان"},{"id":"d","text":"عددُ الفقرات"}]'::jsonb, 'a', 'سؤالُ «مَن؟» يكشفُ الشخصياتِ ومنها البطل. أمّا «متى» فللزمان، و«أين» للمكان، وعددُ الفقرات شيءٌ آخر.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('750f216c-1565-51ec-a1e1-d8975353e9d1', '4514829a-cc9a-516e-9b5c-9c64fc9f5e93', 'الترتيبُ المعتادُ لأحداث القصّة هو:', '[{"id":"a","text":"حلٌّ ← عقدةٌ ← بدايةٌ"},{"id":"b","text":"عقدةٌ ← بدايةٌ ← حلٌّ"},{"id":"c","text":"حلٌّ ← بدايةٌ ← عقدةٌ"},{"id":"d","text":"بدايةٌ ← عقدةٌ ← حلٌّ"}]'::jsonb, 'd', 'القصّةُ تبدأُ ببدايةٍ تُعرّفُ الموقفَ، ثمّ تظهرُ عقدةٌ (مشكلة)، ثمّ يأتي الحلُّ في النهاية. هذا هو التسلسلُ المعتاد.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dcb82737-abfb-5505-83ee-cc35fb2d4c8a', '4514829a-cc9a-516e-9b5c-9c64fc9f5e93', 'اقرأ: «وقفَ أمامَ الجمهورِ، فجفّ ريقُه وارتجفت ركبتاه، لكنّه أكملَ كلمتَه بصوتٍ ثابت.» ماذا نستنتجُ؟', '[{"id":"a","text":"أنّه لم يحضرِ المناسبةَ"},{"id":"b","text":"أنّه كان نائمًا"},{"id":"c","text":"أنّه شعرَ برهبةٍ لكنّه تغلّبَ عليها وأكملَ بثبات"},{"id":"d","text":"أنّه غادرَ المسرحَ فورًا"}]'::jsonb, 'c', 'جفافُ الريق وارتجافُ الركبتين قرينتا رهبةٍ، لكنّ إكمالَه بصوتٍ ثابت يدلُّ على تغلّبه عليها. نجمعُ القرينتين المتقابلتين فنفهمُ الموقفَ كاملًا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2dec21d9-df50-593b-bfed-9668a3b9b844', '4514829a-cc9a-516e-9b5c-9c64fc9f5e93', 'ما الفرقُ بين الفكرة العامّة والعنوان؟', '[{"id":"a","text":"العنوانُ يلخّصُ النصَّ كلَّه دائمًا بدقّةٍ تامّة"},{"id":"b","text":"الفكرةُ العامّةُ موضوعُ النصّ في جملةٍ، والعنوانُ يلمّحُ إليها وقد لا يكفي وحده"},{"id":"c","text":"هما الشيءُ نفسُه تمامًا"},{"id":"d","text":"العنوانُ لا علاقةَ له بالموضوع"}]'::jsonb, 'b', 'الفكرةُ العامّةُ تلخّصُ الموضوعَ في جملةٍ، والعنوانُ إشارةٌ مختصرةٌ تلمّحُ إليها لكنّها قد لا تغطّيها كلَّها. فليسا متطابقين تمامًا ولا منفصلين تمامًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('96e57f21-3f55-546d-abb0-359108b7e72f', '4514829a-cc9a-516e-9b5c-9c64fc9f5e93', 'اقرأ: «ادّخرَ مالَه شهرًا، وفي العيد اشترى لأمّه هديّةً وابتسمَ وهو يراها تفرح.» ما الفكرةُ التي يوحي بها النصّ؟', '[{"id":"a","text":"برُّ الطفل بأمّه وسعادتُه بإسعادها"},{"id":"b","text":"غلاءُ الأسعار في العيد"},{"id":"c","text":"طريقةُ صناعة الهدايا"},{"id":"d","text":"موعدُ فتح المتجر"}]'::jsonb, 'a', 'ادّخارُه شهرًا ثمّ شراؤه هديّةً لأمّه وفرحُه بفرحها قرائنُ تدلُّ على البرّ ومحبّة الإسعاد. هذه هي الفكرةُ الموحى بها، لا الأسعارُ ولا الصناعةُ ولا الموعد.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e7e47b23-cf35-59f2-9bf0-7d4270115c04', '4514829a-cc9a-516e-9b5c-9c64fc9f5e93', 'نصٌّ يقول الكاتبُ في خاتمته: «وهكذا يبقى الصدقُ أجملَ ما يتحلّى به الإنسان.» ما هذه الجملةُ بالنسبة للنصّ؟', '[{"id":"a","text":"تفصيلةٌ هامشيّةٌ لا قيمةَ لها"},{"id":"b","text":"اسمُ إحدى الشخصيات"},{"id":"c","text":"وصفٌ للمكان"},{"id":"d","text":"خلاصةُ النصّ ورأيُ الكاتب الذي يريدُ إيصالَه (العبرة)"}]'::jsonb, 'd', 'الجملةُ الختاميّةُ تحملُ العبرةَ ورأيَ الكاتب الصريحَ في موضوعه (قيمةُ الصدق)، فهي خلاصةُ النصّ لا تفصيلةٌ ولا اسمُ شخصيّةٍ ولا وصفُ مكان.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('f6845b7e-bcc8-5d82-8c49-4cbcfa75f91a', 'f732c7e4-935d-5afb-af06-2193fe343a4c', 'arabic-5eme', 'اختبار فهم الدرس ⭐ (فهم)', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('588c41b7-c551-57e1-aa7b-0fe0385995df', 'f6845b7e-bcc8-5d82-8c49-4cbcfa75f91a', 'في الجملة الاسميّة، ما المسند إليه وما المسند؟', '[{"id":"a","text":"المسند إليه الفعل، والمسند الفاعل"},{"id":"b","text":"لا مسند فيها"},{"id":"c","text":"المسند إليه المبتدأ، والمسند الخبر"},{"id":"d","text":"كلاهما المبتدأ"}]'::jsonb, 'c', 'في الجملة الاسميّة نتحدّثُ عن المبتدأ (مسند إليه) ونُخبرُ عنه بالخبر (مسند). فالمسند إليه المبتدأ والمسند الخبر.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e1ceb06a-25d3-5453-8b54-4514bfc6a274', 'f6845b7e-bcc8-5d82-8c49-4cbcfa75f91a', 'في جملة «طلعَ الفجرُ»، ما المسند إليه؟', '[{"id":"a","text":"الفجرُ"},{"id":"b","text":"طلعَ"},{"id":"c","text":"لا مسند إليه"},{"id":"d","text":"الفجرُ وطلعَ معًا"}]'::jsonb, 'a', 'هي جملةٌ فعليّة؛ المسند إليه فيها هو الفاعل «الفجرُ» (المحدَّثُ عنه)، والمسند هو الفعل «طلعَ».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('075596d9-faa4-51cd-97a6-e389a0e8dea4', 'f6845b7e-bcc8-5d82-8c49-4cbcfa75f91a', 'الجملة الصغرى هي التي:', '[{"id":"a","text":"خبرُها جملةٌ كاملة"},{"id":"b","text":"خبرُها كلمةٌ مفردة (لا جملة)"},{"id":"c","text":"لا خبر فيها"},{"id":"d","text":"تبدأ بحرف"}]'::jsonb, 'b', 'الجملة الصغرى نواةٌ بسيطةٌ: مسندٌ ومسندٌ إليه، وخبرُها كلمةٌ مفردةٌ لا جملة، مثل «القمرُ منيرٌ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('781a3fad-2897-5e5d-8f11-05c3f2c1c98e', 'f6845b7e-bcc8-5d82-8c49-4cbcfa75f91a', 'في جملة «الحديقةُ أزهارُها متفتّحةٌ»، ما إعرابُ «أزهارُها»؟', '[{"id":"a","text":"فاعلٌ"},{"id":"b","text":"مفعولٌ به"},{"id":"c","text":"حرفُ جرّ"},{"id":"d","text":"مبتدأٌ ثانٍ في الجملة الصغرى الواقعة خبرًا"}]'::jsonb, 'd', '«الحديقةُ» مبتدأٌ أوّل، وخبرُه جملةٌ صغرى «أزهارُها متفتّحةٌ»، فيها «أزهارُها» مبتدأٌ ثانٍ و«متفتّحةٌ» خبرُه. لا فعلَ هنا فلا فاعل.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('452c2868-6cb3-51b5-b0eb-182a946371e0', 'f6845b7e-bcc8-5d82-8c49-4cbcfa75f91a', 'أيُّ هذه الجمل جملةٌ كبرى؟', '[{"id":"a","text":"البحرُ هادئٌ"},{"id":"b","text":"نامَ الطفلُ"},{"id":"c","text":"التلميذُ يكتبُ درسَه"},{"id":"d","text":"القمرُ منيرٌ"}]'::jsonb, 'c', '«التلميذُ يكتبُ درسَه»: مبتدأٌ «التلميذُ» وخبرُه جملةٌ فعليّةٌ صغرى «يكتبُ درسَه»، ففيها جملةٌ داخلَ جملةٍ فهي كبرى. الباقي خبرُه مفردٌ فهي صغرى.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('ae8866f4-51d4-5857-999d-f48a3995f284', 'f732c7e4-935d-5afb-af06-2193fe343a4c', 'arabic-5eme', '⭐ تمرين: أمسكُ نواةَ الجملة (سهل)', 1, 50, 10, 'practice', 'admin', 1)
