INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9edfe25f-3f47-5d7d-95a0-2e1f38ae825a', 'ae8866f4-51d4-5857-999d-f48a3995f284', 'في جملة «الجوُّ صافٍ»، ما المسند إليه؟', '[{"id":"a","text":"الجوُّ"},{"id":"b","text":"صافٍ"},{"id":"c","text":"لا مسند إليه"},{"id":"d","text":"الجوُّ صافٍ معًا"}]'::jsonb, 'a', 'المسند إليه هو المحدَّثُ عنه (المبتدأ في الاسميّة). نتحدّثُ عن «الجوِّ»، فهو المسند إليه، و«صافٍ» مسندٌ (خبر).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2e42e1f2-b540-5bbc-83b7-cfa1bad73bb9', 'ae8866f4-51d4-5857-999d-f48a3995f284', 'في جملة «الجوُّ صافٍ»، ما المسند؟', '[{"id":"a","text":"الجوُّ"},{"id":"b","text":"حرفُ جرّ"},{"id":"c","text":"صافٍ"},{"id":"d","text":"لا مسند"}]'::jsonb, 'c', 'المسند هو ما نُخبرُ به عن المسند إليه (الخبر في الاسميّة). أخبرنا عن الجوّ بأنّه «صافٍ»، فهو المسند.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a75b7780-fd02-5304-a5eb-3120e5b15869', 'ae8866f4-51d4-5857-999d-f48a3995f284', 'في جملة «جرى الحصانُ»، ما المسند (في الجملة الفعليّة)؟', '[{"id":"a","text":"الحصانُ"},{"id":"b","text":"جرى"},{"id":"c","text":"لا مسند"},{"id":"d","text":"الحصانُ وجرى معًا"}]'::jsonb, 'b', 'في الجملة الفعليّة المسندُ هو الفعل. «جرى» فعلٌ أُسنِدَ إلى الفاعل «الحصانُ» (المسند إليه).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2ed0430b-002a-5d36-8756-4f0336f10db8', 'ae8866f4-51d4-5857-999d-f48a3995f284', 'أيُّ هذه الجمل جملةٌ صغرى (خبرُها كلمةٌ مفردة)؟', '[{"id":"a","text":"الشجرةُ أوراقُها خضراءُ"},{"id":"b","text":"الطالبُ يحلُّ المسألةَ"},{"id":"c","text":"البستانُ أزهارُه كثيرةٌ"},{"id":"d","text":"الماءُ باردٌ"}]'::jsonb, 'd', '«الماءُ باردٌ»: مبتدأٌ وخبرٌ مفرد، فهي جملةٌ صغرى. الباقي خبرُه جملةٌ (أوراقُها خضراءُ / يحلُّ المسألةَ / أزهارُه كثيرةٌ) فهي كبرى.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d92182cc-4c1d-5d52-8afd-d56a4b33c389', 'ae8866f4-51d4-5857-999d-f48a3995f284', 'في جملة «العصفورُ يبني عشَّه»، ما المبتدأ؟', '[{"id":"a","text":"العصفورُ"},{"id":"b","text":"يبني"},{"id":"c","text":"عشَّه"},{"id":"d","text":"لا مبتدأ"}]'::jsonb, 'a', '«العصفورُ» مبتدأٌ (مسند إليه)، وخبرُه جملةٌ فعليّةٌ «يبني عشَّه». فهي جملةٌ كبرى مبتدؤها «العصفورُ».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e45ad16b-057c-5202-8dea-d7e4a24a6ff5', 'ae8866f4-51d4-5857-999d-f48a3995f284', 'في جملة «التلميذةُ كتابُها جديدٌ»، ما إعرابُ «كتابُها»؟', '[{"id":"a","text":"خبرٌ للتلميذة"},{"id":"b","text":"فاعلٌ"},{"id":"c","text":"مبتدأٌ ثانٍ، وخبرُه «جديدٌ»"},{"id":"d","text":"مفعولٌ به"}]'::jsonb, 'c', '«التلميذةُ» مبتدأٌ أوّل، وخبرُه جملةٌ صغرى «كتابُها جديدٌ»، فيها «كتابُها» مبتدأٌ ثانٍ و«جديدٌ» خبرُه. لا فعلَ فلا فاعل.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a40cbe6f-f925-53d7-aa7a-4d0a6ea7c733', 'f732c7e4-935d-5afb-af06-2193fe343a4c', 'arabic-5eme', '⚔️ زعيم الفصل ⭐⭐⭐: حارسُ الإسناد (صعب)', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
