INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cb713b07-9b68-5134-b2a3-281e8343db1a', 'a40cbe6f-f925-53d7-aa7a-4d0a6ea7c733', 'ما الركنان اللذان يقومُ عليهما كلُّ مركّبٍ إسناديّ؟', '[{"id":"a","text":"حرفٌ واسم"},{"id":"b","text":"مسندٌ ومسندٌ إليه"},{"id":"c","text":"فعلان"},{"id":"d","text":"نعتٌ ومنعوت"}]'::jsonb, 'b', 'المركّب الإسناديّ (الجملة) يقومُ على ركنين: مسندٌ إليه (المحدَّثُ عنه) ومسندٌ (ما نُسنِدُه إليه). هذا أساسُ كلّ جملةٍ مفيدة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5e124c3c-21bc-535a-afba-f615f0534c35', 'a40cbe6f-f925-53d7-aa7a-4d0a6ea7c733', 'في جملة «المجتهدُ ينجحُ»، حدّد المسند إليه والمسند.', '[{"id":"a","text":"المسند إليه: ينجحُ، المسند: المجتهدُ"},{"id":"b","text":"لا إسناد في الجملة"},{"id":"c","text":"كلاهما المجتهدُ"},{"id":"d","text":"المسند إليه: المجتهدُ، والمسند: جملةُ «ينجحُ»"}]'::jsonb, 'd', '«المجتهدُ» مبتدأٌ (مسند إليه)، وخبرُه جملةٌ فعليّةٌ «ينجحُ» (مسند). فهي جملةٌ كبرى مسندُ إليها «المجتهدُ» ومسندُها جملةُ «ينجحُ».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f5812068-1035-5c18-bc8c-d050c87af4e7', 'a40cbe6f-f925-53d7-aa7a-4d0a6ea7c733', 'أيُّ جملةٍ منها جملةٌ كبرى؟', '[{"id":"a","text":"النملةُ صبرُها عظيمٌ"},{"id":"b","text":"الشمسُ ساطعةٌ"},{"id":"c","text":"الطريقُ طويلٌ"},{"id":"d","text":"البابُ مفتوحٌ"}]'::jsonb, 'a', '«النملةُ صبرُها عظيمٌ»: مبتدأٌ أوّل «النملةُ» وخبرُه جملةٌ اسميّةٌ صغرى «صبرُها عظيمٌ»، فهي كبرى. الباقي خبرُه مفردٌ فهي صغرى.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b8db2deb-d12c-59d0-9d8d-1e66630498e7', 'a40cbe6f-f925-53d7-aa7a-4d0a6ea7c733', 'في جملة «الحديقةُ تفوحُ منها الأزهارُ»، ما إعرابُ جملة «تفوحُ منها الأزهارُ»؟', '[{"id":"a","text":"مبتدأٌ"},{"id":"b","text":"نعتٌ"},{"id":"c","text":"خبرٌ للمبتدأ «الحديقةُ» (جملةٌ فعليّةٌ في محلّ رفع)"},{"id":"d","text":"حالٌ"}]'::jsonb, 'c', '«الحديقةُ» مبتدأ، وجملةُ «تفوحُ منها الأزهارُ» فعليّةٌ وقعت خبرًا له (في محلّ رفع خبر). فهي جملةٌ كبرى، والرابطُ الضميرُ في «منها».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d55dfbb0-48b4-500f-8588-8293a7c1fb85', 'a40cbe6f-f925-53d7-aa7a-4d0a6ea7c733', 'لماذا تُعَدُّ «المعلّمُ صوتُه واضحٌ» جملةً كبرى لا صغرى؟', '[{"id":"a","text":"لأنّها تبدأ بفعل"},{"id":"b","text":"لأنّ خبر المبتدأ «المعلّمُ» جملةٌ اسميّةٌ «صوتُه واضحٌ» لا كلمةٌ مفردة"},{"id":"c","text":"لأنّها سؤالٌ"},{"id":"d","text":"لأنّها بلا مبتدأ"}]'::jsonb, 'b', 'خبرُ «المعلّمُ» ليس مفردًا بل جملةٌ صغرى «صوتُه واضحٌ» (مبتدأٌ ثانٍ + خبر)، وفيها ضميرٌ يعودُ على المعلّم. فالجملةُ كبرى.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e805965e-5fa3-503a-afec-7d6ebfd3bc43', 'a40cbe6f-f925-53d7-aa7a-4d0a6ea7c733', 'في جملة «الطفلانِ يلعبانِ»، ما المسند إليه؟', '[{"id":"a","text":"يلعبانِ"},{"id":"b","text":"لا مسند إليه"},{"id":"c","text":"ألفُ الاثنين فقط"},{"id":"d","text":"الطفلانِ (مبتدأٌ)، وخبرُه جملةُ «يلعبانِ»"}]'::jsonb, 'd', '«الطفلانِ» مبتدأٌ مثنّى (مسند إليه)، وخبرُه جملةٌ فعليّةٌ «يلعبانِ» (فعلٌ وفاعلُه ألفُ الاثنين). فهي جملةٌ كبرى مسندُ إليها «الطفلانِ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('39bb4d73-5726-5f2b-82dc-f00d590d9ebc', 'f732c7e4-935d-5afb-af06-2193fe343a4c', 'arabic-5eme', '📝 مراجعة ⭐⭐: المسند والصغرى والكبرى (متوسط)', 2, 75, 15, 'practice', 'admin', 3)
