INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('800ceb4a-2c96-5b78-808e-80b80081a0b4', '39bb4d73-5726-5f2b-82dc-f00d590d9ebc', 'في الجملة الفعليّة، المسند إليه هو:', '[{"id":"a","text":"المفعولُ به"},{"id":"b","text":"الفعلُ"},{"id":"c","text":"الفاعلُ"},{"id":"d","text":"حرفُ الجرّ"}]'::jsonb, 'c', 'في الجملة الفعليّة المسندُ إليه هو الفاعل (المحدَّثُ عنه)، والمسندُ هو الفعل. فالفاعلُ هو المسند إليه.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('92c2077b-60d3-5634-884f-d706391a88a4', '39bb4d73-5726-5f2b-82dc-f00d590d9ebc', 'الجملة الكبرى هي جملةٌ اسميّةٌ:', '[{"id":"a","text":"خبرُها جملةٌ (صغرى) لا كلمةٌ مفردة"},{"id":"b","text":"لا خبر فيها"},{"id":"c","text":"تتكوّن من كلمةٍ واحدة"},{"id":"d","text":"تبدأ بحرف جرّ"}]'::jsonb, 'a', 'الجملة الكبرى مبتدؤها اسمٌ وخبرُها **جملةٌ** كاملةٌ (اسميّةٌ أو فعليّة) لا كلمةٌ مفردة، وفيها رابطٌ يعودُ على المبتدأ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6e250da2-bc30-551a-becd-33405fb489cc', '39bb4d73-5726-5f2b-82dc-f00d590d9ebc', 'في جملة «القطارُ يصلُ متأخّرًا»، الجملة الواقعة خبرًا هي:', '[{"id":"a","text":"القطارُ"},{"id":"b","text":"متأخّرًا فقط"},{"id":"c","text":"لا جملة فيها"},{"id":"d","text":"يصلُ متأخّرًا (جملةٌ فعليّة)"}]'::jsonb, 'd', '«القطارُ» مبتدأ، وخبرُه الجملةُ الفعليّةُ «يصلُ متأخّرًا» (فعلٌ وفاعلٌ مستترٌ هو + حال). فالجملةُ كبرى وخبرُها جملةٌ فعليّة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0bfa64d5-adf2-59b0-8b1c-f582028992df', '39bb4d73-5726-5f2b-82dc-f00d590d9ebc', 'ما الرابطُ الذي يربطُ جملةَ الخبر بالمبتدأ في الجملة الكبرى «الوردةُ لونُها أحمرُ»؟', '[{"id":"a","text":"حرفُ الواو"},{"id":"b","text":"الضميرُ «ها» في «لونُها» العائدُ على الوردة"},{"id":"c","text":"لا رابطَ فيها"},{"id":"d","text":"كلمةُ «أحمر»"}]'::jsonb, 'b', 'جملةُ الخبر «لونُها أحمرُ» تربطُها بالمبتدأ «الوردةُ» قرينةُ الضمير «ها» في «لونُها» العائدِ على الوردة. هذا الرابطُ شرطٌ في الجملة الكبرى.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f653e3ac-63a1-5b4b-8860-e468de798bb6', '39bb4d73-5726-5f2b-82dc-f00d590d9ebc', 'ميّز الجملةَ الكبرى من الصغرى: (1) «الجنديُّ شجاعٌ» (2) «الجنديُّ يحرسُ الحدودَ».', '[{"id":"a","text":"(1) كبرى و(2) صغرى"},{"id":"b","text":"كلتاهما كبرى"},{"id":"c","text":"(1) صغرى (خبرُها مفرد) و(2) كبرى (خبرُها جملةٌ فعليّة)"},{"id":"d","text":"كلتاهما صغرى"}]'::jsonb, 'c', '(1) «الجنديُّ شجاعٌ» خبرُها مفردٌ «شجاعٌ» فهي صغرى. (2) «الجنديُّ يحرسُ الحدودَ» خبرُها جملةٌ فعليّةٌ «يحرسُ الحدودَ» فهي كبرى.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9acdbbeb-b22f-5651-87b6-a2c56bade112', '39bb4d73-5726-5f2b-82dc-f00d590d9ebc', 'في جملة «المدينةُ شوارعُها نظيفةٌ»، ما إعرابُ «نظيفةٌ»؟', '[{"id":"a","text":"خبرُ المبتدأ الثاني «شوارعُها» (في الجملة الصغرى الواقعة خبرًا)"},{"id":"b","text":"فاعلٌ"},{"id":"c","text":"مفعولٌ به"},{"id":"d","text":"خبرُ المبتدأ الأوّل «المدينةُ» مباشرةً"}]'::jsonb, 'a', '«المدينةُ» مبتدأٌ أوّل، خبرُه جملةٌ صغرى «شوارعُها نظيفةٌ»: «شوارعُها» مبتدأٌ ثانٍ و«نظيفةٌ» خبرُه. فـ«نظيفةٌ» خبرُ المبتدأ الثاني لا الأوّل.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('ae648ce2-640f-5ba7-99f5-e17fe8c952e8', 'f732c7e4-935d-5afb-af06-2193fe343a4c', 'arabic-5eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: مهندسُ الجملة', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5b8c0d45-a158-54e5-b48e-ec24bc0bbeb1', 'ae648ce2-640f-5ba7-99f5-e17fe8c952e8', 'في جملة «الأطفالُ يلعبونَ في الساحةِ»، ما إعرابُ «الأطفالُ» وما خبرُه؟', '[{"id":"a","text":"الأطفالُ مفعولٌ به، وخبرُه «الساحةِ»"},{"id":"b","text":"الأطفالُ فاعلٌ مقدّم"},{"id":"c","text":"الأطفالُ حالٌ"},{"id":"d","text":"الأطفالُ مبتدأ، وخبرُه جملةُ «يلعبونَ في الساحةِ» (فعليّةٌ في محلّ رفع)"}]'::jsonb, 'd', '«الأطفالُ» مبتدأٌ جمعٌ، وخبرُه الجملةُ الفعليّةُ «يلعبونَ في الساحةِ» (فعلٌ وفاعلُه واوُ الجماعة + جارٌّ ومجرور). فهي جملةٌ كبرى، والرابطُ واوُ الجماعة العائدةُ على الأطفال.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b0089eb7-3e62-525b-92e1-d865e777969a', 'ae648ce2-640f-5ba7-99f5-e17fe8c952e8', 'حوّل «نجحَ التلميذُ» إلى جملةٍ كبرى مبتدؤها «التلميذُ».', '[{"id":"a","text":"التلميذُ التلميذُ نجحَ"},{"id":"b","text":"التلميذُ نجحَ (مبتدأٌ وخبرُه جملةُ «نجحَ»)"},{"id":"c","text":"هل نجحَ التلميذُ؟"},{"id":"d","text":"في التلميذِ نجاحٌ"}]'::jsonb, 'b', 'نقدّمُ المبتدأ «التلميذُ» ونجعلُ الفعلَ خبرًا له: «التلميذُ نجحَ»، فالخبرُ جملةٌ فعليّةٌ «نجحَ» (فاعلُها مستترٌ هو يعودُ على التلميذ). فصارت كبرى.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e7609b12-8be8-5376-a762-2b6eb3a5a9c2', 'ae648ce2-640f-5ba7-99f5-e17fe8c952e8', 'في جملة «البلبلُ صوتُه يطربُ السامعينَ»، كم جملةً صغرى داخلَ الخبر؟', '[{"id":"a","text":"جملتان: «صوتُه ...» اسميّةٌ تحوي جملةً فعليّةً «يطربُ السامعينَ» خبرًا للمبتدأ الثاني"},{"id":"b","text":"لا جملةَ صغرى أصلًا"},{"id":"c","text":"جملةٌ واحدةٌ اسميّةٌ فقط بلا فعل"},{"id":"d","text":"ثلاثُ جملٍ فعليّة"}]'::jsonb, 'a', '«البلبلُ» مبتدأٌ أوّل، خبرُه جملةٌ «صوتُه يطربُ السامعينَ»: «صوتُه» مبتدأٌ ثانٍ وخبرُه جملةٌ فعليّةٌ «يطربُ السامعينَ». فداخلَ الخبر إسنادٌ اسميٌّ يحوي إسنادًا فعليًّا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('51ba471b-5be0-58ad-84cf-f6edfc5d836a', 'ae648ce2-640f-5ba7-99f5-e17fe8c952e8', 'أيُّ تحليلٍ صحيحٌ لجملة «الكتابُ غلافُه ممزّقٌ»؟', '[{"id":"a","text":"«غلافُه» فاعلٌ و«ممزّقٌ» مفعولٌ به"},{"id":"b","text":"الجملةُ فعليّةٌ تبدأ بفعلٍ محذوف"},{"id":"c","text":"«الكتابُ» مبتدأٌ أوّل، و«غلافُه ممزّقٌ» جملةٌ اسميّةٌ صغرى في محلّ رفع خبر، والرابطُ ضميرُ «ه»"},{"id":"d","text":"«ممزّقٌ» خبرُ «الكتابُ» مباشرةً والجملةُ صغرى"}]'::jsonb, 'c', '«الكتابُ» مبتدأٌ أوّل، خبرُه جملةٌ صغرى «غلافُه ممزّقٌ» (مبتدأٌ ثانٍ + خبر) في محلّ رفع خبرٍ للأوّل، والرابطُ ضميرُ «ه» العائدُ على الكتاب. فهي كبرى.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('941f8825-0091-504b-8dfd-d9a44803786b', 'ae648ce2-640f-5ba7-99f5-e17fe8c952e8', 'ما الفرقُ الجوهريُّ بين «العاملُ نشيطٌ» و«العاملُ يعملُ بنشاطٍ»؟', '[{"id":"a","text":"لا فرقَ، كلتاهما صغرى"},{"id":"b","text":"الأولى فعليّةٌ والثانية اسميّة"},{"id":"c","text":"كلتاهما كبرى"},{"id":"d","text":"الأولى صغرى (خبرُها مفردٌ «نشيطٌ») والثانية كبرى (خبرُها جملةٌ فعليّةٌ «يعملُ بنشاطٍ»)"}]'::jsonb, 'd', '«العاملُ نشيطٌ» خبرُها مفردٌ «نشيطٌ» فهي صغرى. «العاملُ يعملُ بنشاطٍ» خبرُها جملةٌ فعليّةٌ «يعملُ بنشاطٍ» فهي كبرى. الفرقُ في نوع الخبر: مفردٌ أم جملة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5f25a44a-5c6e-5545-ac52-1e02b7c485eb', 'ae648ce2-640f-5ba7-99f5-e17fe8c952e8', 'في جملة «هؤلاءِ التلاميذُ كتبُهم منظّمةٌ»، ما المبتدأ الأوّل وما خبرُه؟', '[{"id":"a","text":"المبتدأ «منظّمةٌ» وخبرُه «كتبُهم»"},{"id":"b","text":"المبتدأ اسمُ الإشارة «هؤلاءِ» (و«التلاميذُ» بدلٌ منه)، وخبرُه جملةُ «كتبُهم منظّمةٌ»"},{"id":"c","text":"لا مبتدأ في الجملة"},{"id":"d","text":"المبتدأ «كتبُهم» والجملةُ صغرى"}]'::jsonb, 'b', '«هؤلاءِ» اسمُ إشارةٍ مبتدأٌ، و«التلاميذُ» بدلٌ منه، وخبرُ المبتدأ جملةٌ اسميّةٌ صغرى «كتبُهم منظّمةٌ» (مبتدأٌ ثانٍ + خبر) في محلّ رفع، والرابطُ ضميرُ «هم». فالجملةُ كبرى.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('3df701b9-4511-5ff6-a972-4b0d90da6fea', 'f732c7e4-935d-5afb-af06-2193fe343a4c', 'arabic-5eme', '🛡️ تدريب ⭐⭐⭐: الإسناد والجملتان (مراجعة شاملة)', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
