  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d76405c8-d7a4-5703-8946-42271bfc3dec', '3df701b9-4511-5ff6-a972-4b0d90da6fea', 'المسندُ في الجملة الاسميّة هو:', '[{"id":"a","text":"الخبرُ"},{"id":"b","text":"المبتدأُ"},{"id":"c","text":"حرفُ الجرّ"},{"id":"d","text":"المفعولُ"}]'::jsonb, 'a', 'في الجملة الاسميّة المسندُ هو الخبر (ما نُخبرُ به عن المبتدأ)، والمسندُ إليه هو المبتدأ (المحدَّثُ عنه).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4b091bb1-2641-509b-a281-8155c14c06e2', '3df701b9-4511-5ff6-a972-4b0d90da6fea', 'الجملةُ التي خبرُها كلمةٌ مفردةٌ تُسمّى:', '[{"id":"a","text":"كبرى"},{"id":"b","text":"استفهاميّة"},{"id":"c","text":"صغرى"},{"id":"d","text":"أمريّة"}]'::jsonb, 'c', 'الجملةُ ذاتُ الخبر المفرد (لا الجملة) هي الجملةُ الصغرى، مثل «السماءُ صافيةٌ». أمّا التي خبرُها جملةٌ فهي الكبرى.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('721fd4b7-e2b0-58d3-b51d-1c5c8d65cb08', '3df701b9-4511-5ff6-a972-4b0d90da6fea', 'في جملة «الفلاحُ يحصدُ القمحَ»، الجملةُ الواقعةُ خبرًا للمبتدأ هي:', '[{"id":"a","text":"الفلاحُ"},{"id":"b","text":"القمحَ فقط"},{"id":"c","text":"لا جملةَ خبريّة"},{"id":"d","text":"يحصدُ القمحَ (جملةٌ فعليّةٌ في محلّ رفع خبر)"}]'::jsonb, 'd', '«الفلاحُ» مبتدأ، وخبرُه الجملةُ الفعليّةُ «يحصدُ القمحَ» (فعلٌ وفاعلٌ مستترٌ هو + مفعول). فهي كبرى وخبرُها جملةٌ فعليّة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cacee87c-3be8-50c5-ac00-cefbd53eac48', '3df701b9-4511-5ff6-a972-4b0d90da6fea', 'لماذا «أخوكَ خلقُه كريمٌ» جملةٌ كبرى؟', '[{"id":"a","text":"لأنّها تبدأ بفعل"},{"id":"b","text":"لأنّ خبر المبتدأ «أخوكَ» جملةٌ اسميّةٌ «خلقُه كريمٌ» فيها ضميرٌ يعودُ عليه"},{"id":"c","text":"لأنّها استفهام"},{"id":"d","text":"لأنّها بلا خبر"}]'::jsonb, 'b', 'خبرُ «أخوكَ» جملةٌ صغرى «خلقُه كريمٌ» (مبتدأٌ ثانٍ + خبر) لا كلمةٌ مفردة، والرابطُ ضميرُ «ه». فهي كبرى.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('377e7c50-dc78-529c-9c7d-81c288d5ddb1', '3df701b9-4511-5ff6-a972-4b0d90da6fea', 'في جملة «النجومُ تتلألأُ في السماءِ»، حدّد المبتدأ وخبرَه بدقّة.', '[{"id":"a","text":"المبتدأ «النجومُ» وخبرُه جملةُ «تتلألأُ في السماءِ» (فعليّةٌ في محلّ رفع)، والرابطُ ضميرٌ مستترٌ في الفعل"},{"id":"b","text":"المبتدأ «تتلألأُ» وخبرُه «النجومُ»"},{"id":"c","text":"«السماءِ» مبتدأ و«النجومُ» خبر"},{"id":"d","text":"لا مبتدأ ولا خبر"}]'::jsonb, 'a', '«النجومُ» مبتدأ، وخبرُه الجملةُ الفعليّةُ «تتلألأُ في السماءِ» (فعلٌ وفاعلُه ضميرٌ مستترٌ هي يعودُ على النجوم + جارٌّ ومجرور). فهي كبرى، والرابطُ الضميرُ المستتر.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('96fc9c93-ddd1-504d-ad46-b67e55da5385', '3df701b9-4511-5ff6-a972-4b0d90da6fea', 'ميّز: (1) «الزهرةُ عطرُها فوّاحٌ» (2) «الزهرةُ فوّاحةٌ». أيُّ التحليلين صحيح؟', '[{"id":"a","text":"كلتاهما صغرى بلا فرق"},{"id":"b","text":"(1) صغرى و(2) كبرى"},{"id":"c","text":"(1) كبرى (خبرُها جملةٌ «عطرُها فوّاحٌ») و(2) صغرى (خبرُها مفردٌ «فوّاحةٌ»)"},{"id":"d","text":"كلتاهما فعليّة"}]'::jsonb, 'c', '(1) خبرُ «الزهرةُ» جملةٌ «عطرُها فوّاحٌ» ففيها إسنادٌ داخلَ إسنادٍ فهي كبرى. (2) خبرُ «الزهرةُ» مفردٌ «فوّاحةٌ» فهي صغرى. العبرةُ بنوع الخبر.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('3d060c62-45af-5d29-a740-184dffe7953d', '8f5ea9ea-0054-5621-8eef-dff7c09854e5', 'arabic-5eme', 'اختبار فهم الدرس ⭐ (فهم)', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
