  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('999cee9a-f49b-5973-8bbe-71aa33bb0377', '3d060c62-45af-5d29-a740-184dffe7953d', 'الفعل اللازم هو الذي:', '[{"id":"a","text":"يحتاجُ مفعولين"},{"id":"b","text":"يتمُّ معناه بفاعله وحده، لا يحتاجُ مفعولًا به"},{"id":"c","text":"يكون دائمًا في الماضي"},{"id":"d","text":"لا فاعل له"}]'::jsonb, 'b', 'الفعل اللازم يكتفي بفاعله ويتمُّ معناه دونه مفعولٍ به، مثل «نامَ الطفلُ». لا علاقةَ ذلك بالزمن ولا بعدد المفاعيل.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('49242ca6-ded2-53ce-95f1-27a5beb6a2d7', '3d060c62-45af-5d29-a740-184dffe7953d', 'في جملة «شربَ الطفلُ الحليبَ»، ما المفعول به؟', '[{"id":"a","text":"الحليبَ"},{"id":"b","text":"الطفلُ"},{"id":"c","text":"شربَ"},{"id":"d","text":"لا مفعول به"}]'::jsonb, 'a', 'المفعول به هو ما وقعَ عليه الفعل. شربَ ماذا؟ «الحليبَ»، فهو المفعول به المنصوب. أمّا «الطفلُ» ففاعلٌ مرفوع.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
