INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('59d18626-5f64-532a-8e6e-166b7e41e9c2', '3d060c62-45af-5d29-a740-184dffe7953d', 'ما علامةُ نصب المفعول به المفرد الأصليّة؟', '[{"id":"a","text":"الضمّة"},{"id":"b","text":"الكسرة"},{"id":"c","text":"الفتحة"},{"id":"d","text":"السكون"}]'::jsonb, 'c', 'المفعول به منصوبٌ دائمًا، وعلامةُ نصبه الأصليّة الفتحة، مثل «فتحَ البابَ». (وفي الجموع والمثنّى علاماتٌ فرعيّة.)', 3)
