  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('956519a0-474a-5223-814e-284d8dd14130', '3d060c62-45af-5d29-a740-184dffe7953d', 'في جملة «منحَ المعلّمُ التلميذَ جائزةً»، كم مفعولًا به؟', '[{"id":"a","text":"لا مفعول به"},{"id":"b","text":"مفعولٌ واحد"},{"id":"c","text":"ثلاثة مفاعيل"},{"id":"d","text":"مفعولان: التلميذَ وجائزةً"}]'::jsonb, 'd', '«منحَ» يتعدّى إلى مفعولين: منح مَن؟ «التلميذَ»، ومنحه ماذا؟ «جائزةً». فهما مفعولان منصوبان.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c27fd366-6315-51f9-b3bd-26ca09149257', '3d060c62-45af-5d29-a740-184dffe7953d', 'أيُّ هذه الأفعال لازمٌ (يكتفي بفاعله)؟', '[{"id":"a","text":"كتبَ"},{"id":"b","text":"جلسَ"},{"id":"c","text":"أكلَ"},{"id":"d","text":"قرأَ"}]'::jsonb, 'b', '«جلسَ» يتمُّ بفاعله: «جلسَ الضيفُ» معنًى تامٌّ بلا مفعول. أمّا كتبَ وأكلَ وقرأَ فتطلبُ مفعولًا به (كتبَ ماذا؟…).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('ce02aab9-0f5a-5f8d-a512-05acf3c97bfc', '8f5ea9ea-0054-5621-8eef-dff7c09854e5', 'arabic-5eme', '⭐ تمرين: لازمٌ أم متعدٍّ؟ (سهل)', 1, 50, 10, 'practice', 'admin', 1)
