INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('73adc915-401f-50c4-b3c2-8e7f0aa6ab2d', 'ce02aab9-0f5a-5f8d-a512-05acf3c97bfc', 'في جملة «نامَ الطفلُ»، نوعُ الفعل «نامَ» هو:', '[{"id":"a","text":"متعدٍّ لمفعولين"},{"id":"b","text":"متعدٍّ لمفعولٍ واحد"},{"id":"c","text":"لازمٌ (يكتفي بفاعله)"},{"id":"d","text":"حرفٌ"}]'::jsonb, 'c', '«نامَ الطفلُ» معنًى تامٌّ بفاعله وحده؛ «نامَ ماذا؟» لا جواب. فالفعلُ لازمٌ لا يحتاجُ مفعولًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8699ff3e-dfc1-5ba8-9032-dae609e2dd88', 'ce02aab9-0f5a-5f8d-a512-05acf3c97bfc', 'في جملة «قطفَ الولدُ الوردةَ»، ما المفعول به؟', '[{"id":"a","text":"الوردةَ"},{"id":"b","text":"الولدُ"},{"id":"c","text":"قطفَ"},{"id":"d","text":"لا مفعول به"}]'::jsonb, 'a', 'قطفَ ماذا؟ «الوردةَ»، فهي المفعول به المنصوب بالفتحة. أمّا «الولدُ» ففاعلٌ مرفوع.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0cadd30f-d6c7-524c-abfe-9f332b69f20a', 'ce02aab9-0f5a-5f8d-a512-05acf3c97bfc', 'أيُّ هذه الجمل فعلُها متعدٍّ (يطلبُ مفعولًا)؟', '[{"id":"a","text":"ذهبَ المسافرُ"},{"id":"b","text":"ركبَ الفارسُ الحصانَ"},{"id":"c","text":"وقفَ الجنديُّ"},{"id":"d","text":"ضحكَ الطفلُ"}]'::jsonb, 'b', '«ركبَ الفارسُ الحصانَ»: ركبَ ماذا؟ «الحصانَ» مفعولٌ به، فالفعلُ متعدٍّ. أمّا ذهبَ ووقفَ وضحكَ فلازمةٌ تكتفي بفاعلها.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e803a310-95de-579d-993f-4c491156000b', 'ce02aab9-0f5a-5f8d-a512-05acf3c97bfc', 'في جملة «كتبَ سعيدٌ الرسالةَ»، ما إعرابُ «سعيدٌ»؟', '[{"id":"a","text":"مفعولٌ به منصوب"},{"id":"b","text":"حرفُ جرّ"},{"id":"c","text":"مبتدأٌ"},{"id":"d","text":"فاعلٌ مرفوع"}]'::jsonb, 'd', '«سعيدٌ» هو من قامَ بالكتابة، فهو الفاعل المرفوع (بالضمّة). و«الرسالةَ» مفعولٌ به منصوب. لا نخلط بين الفاعل والمفعول.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('df34168e-119b-56e0-a70b-caf911b3f74f', 'ce02aab9-0f5a-5f8d-a512-05acf3c97bfc', 'في جملة «ألبسَ الأبُ ابنَه معطفًا»، ما المفعولان؟', '[{"id":"a","text":"الأبُ ومعطفًا"},{"id":"b","text":"لا مفعول فيها"},{"id":"c","text":"ابنَه ومعطفًا"},{"id":"d","text":"الأبُ وابنَه"}]'::jsonb, 'c', '«ألبسَ» يتعدّى إلى مفعولين: ألبس مَن؟ «ابنَه»، وألبسه ماذا؟ «معطفًا». فهما المفعولان المنصوبان، و«الأبُ» فاعلٌ مرفوع.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('63ab37c4-8e42-5d4e-ba66-5d6c19e08f62', 'ce02aab9-0f5a-5f8d-a512-05acf3c97bfc', 'في جملة «جلسَ المعلّمُ على الكرسيِّ»، هل «الكرسيِّ» مفعولٌ به؟', '[{"id":"a","text":"لا؛ «جلسَ» فعلٌ لازم، و«على الكرسيِّ» جارٌّ ومجرور لا مفعولٌ به"},{"id":"b","text":"نعم، هو مفعولٌ به منصوب"},{"id":"c","text":"نعم، هو فاعلٌ ثانٍ"},{"id":"d","text":"نعم، هو مفعولٌ به مرفوع"}]'::jsonb, 'a', '«جلسَ» لازمٌ يكتفي بفاعله، و«على الكرسيِّ» جارٌّ ومجرور (مجرورٌ بالكسرة) لا مفعولٌ به. الفخّ الشائع عدُّ كلّ ما بعد الفعل مفعولًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('4267ee46-f842-5fea-9c4b-810464abd066', '8f5ea9ea-0054-5621-8eef-dff7c09854e5', 'arabic-5eme', '⚔️ زعيم الفصل ⭐⭐⭐: حارسُ المفعول (صعب)', 3, 120, 30, 'boss', 'admin', 2)
