INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e0f562cd-e9e3-50c0-a9e5-ebf90235fc51', '4267ee46-f842-5fea-9c4b-810464abd066', 'كيف نعرفُ أنّ الفعلَ متعدٍّ؟', '[{"id":"a","text":"إذا كان في الماضي"},{"id":"b","text":"إذا لم يكن له فاعل"},{"id":"c","text":"إذا انتهى بتاء"},{"id":"d","text":"إذا وجدنا جوابًا لسؤال «ماذا؟» بعد الفعل والفاعل (مفعولٌ به)"}]'::jsonb, 'd', 'الفعلُ المتعدّي يطلبُ مفعولًا به؛ فإذا سألنا «ماذا؟» بعد الفعل والفاعل ووجدنا جوابًا، فالفعلُ متعدٍّ. وإلّا فهو لازم.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9a11ea28-a74a-58d9-8ccd-896ba6a08b9c', '4267ee46-f842-5fea-9c4b-810464abd066', 'في جملة «شكرَ الناظرُ المعلّماتِ»، ما إعرابُ «المعلّماتِ»؟', '[{"id":"a","text":"فاعلٌ مرفوع بالضمّة"},{"id":"b","text":"مفعولٌ به منصوب بالكسرة (جمعُ مؤنّثٍ سالم)"},{"id":"c","text":"مبتدأٌ"},{"id":"d","text":"مجرورٌ بحرف جرّ"}]'::jsonb, 'b', '«المعلّماتِ» مفعولٌ به، وهو جمعُ مؤنّثٍ سالم يُنصبُ بالكسرة نيابةً عن الفتحة. فعلامةُ نصبه الكسرة لا الفتحة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('996a2c65-ffe9-522b-a4fb-a2fa5c4dbf33', '4267ee46-f842-5fea-9c4b-810464abd066', 'في جملة «ظنَّ سعيدٌ الامتحانَ سهلًا»، حدّد المفعولين.', '[{"id":"a","text":"سعيدٌ والامتحانَ"},{"id":"b","text":"لا مفعول فيها"},{"id":"c","text":"الامتحانَ (أوّل) وسهلًا (ثانٍ)"},{"id":"d","text":"سعيدٌ وسهلًا"}]'::jsonb, 'c', '«ظنَّ» من أفعال القلوب يتعدّى إلى مفعولين: المفعول الأوّل «الامتحانَ» والثاني «سهلًا»، وكلاهما منصوب. و«سعيدٌ» فاعلٌ مرفوع.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4a2318fd-1307-5cc4-a44e-9910acb6a101', '4267ee46-f842-5fea-9c4b-810464abd066', 'في جملة «استقبلَ التلاميذُ ضيوفَهم بالترحابِ»، أعرب «ضيوفَهم» و«بالترحابِ».', '[{"id":"a","text":"«ضيوفَهم» مفعولٌ به منصوب بالفتحة، و«بالترحابِ» جارٌّ ومجرور (ليس مفعولًا به)"},{"id":"b","text":"كلاهما مفعولٌ به"},{"id":"c","text":"«ضيوفَهم» فاعلٌ و«بالترحابِ» مفعول"},{"id":"d","text":"«ضيوفَهم» مبتدأ و«بالترحابِ» خبر"}]'::jsonb, 'a', '«ضيوفَهم» وقعَ عليه الاستقبالُ فهو مفعولٌ به منصوبٌ بالفتحة. و«بالترحابِ» جارٌّ ومجرور يبيّنُ الكيفيّة، وليس مفعولًا به. لا نخلط بينهما.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7be607e1-0065-5aff-8b9b-a83a1bef0839', '4267ee46-f842-5fea-9c4b-810464abd066', 'أيُّ جملةٍ فعلُها متعدٍّ إلى مفعولين؟', '[{"id":"a","text":"سافرَ الحجّاجُ"},{"id":"b","text":"نبتَ الزرعُ"},{"id":"c","text":"جرى النهرُ"},{"id":"d","text":"كسا الغنيُّ الفقيرَ ثوبًا"}]'::jsonb, 'd', '«كسا» يتعدّى إلى مفعولين: كسا مَن؟ «الفقيرَ»، وكساه ماذا؟ «ثوبًا». أمّا سافرَ ونبتَ وجرى فأفعالٌ لازمةٌ تكتفي بفاعلها.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
