  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3ffabc04-f6e9-5209-8230-7be502754d96', '4267ee46-f842-5fea-9c4b-810464abd066', 'في جملة «فتحَ العمّالُ الأبوابَ»، ما علامةُ نصب المفعول به «الأبوابَ»؟', '[{"id":"a","text":"الضمّة"},{"id":"b","text":"الفتحة (جمعُ تكسيرٍ يُنصبُ بالفتحة)"},{"id":"c","text":"الكسرة"},{"id":"d","text":"الياء"}]'::jsonb, 'b', '«الأبوابَ» جمعُ تكسير، وجمعُ التكسير يُنصبُ بالفتحة (العلامة الأصليّة). فعلامةُ نصبه الفتحة لا الكسرة ولا الياء.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

