INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('de04934a-1f39-5a74-8dfc-85b9dfab55b1', 'b04f1154-518e-5b0b-a0ff-4fc2995db552', 'المفعول به دائمًا:', '[{"id":"a","text":"منصوبٌ"},{"id":"b","text":"مرفوعٌ"},{"id":"c","text":"مجزومٌ"},{"id":"d","text":"مبنيٌّ على الضمّ"}]'::jsonb, 'a', 'المفعول به اسمٌ وقعَ عليه فعلُ الفاعل، وحكمُه النصبُ دائمًا (بالفتحة أصلًا، وبعلاماتٍ فرعيّةٍ في الجموع والمثنّى).', 1)
