INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('19b9e254-9171-5174-9584-bb4352cc3ec8', 'b04f1154-518e-5b0b-a0ff-4fc2995db552', 'أيُّ فعلٍ منها لازمٌ؟', '[{"id":"a","text":"أكلَ"},{"id":"b","text":"شربَ"},{"id":"c","text":"وصلَ"},{"id":"d","text":"حملَ"}]'::jsonb, 'c', '«وصلَ» يتمُّ بفاعله: «وصلَ القطارُ» معنًى تامٌّ بلا مفعول، فهو لازم. أمّا أكلَ وشربَ وحملَ فمتعدّيةٌ تطلبُ مفعولًا.', 2)
