INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('61573f78-3758-5d37-af14-6afe0b254c7c', 'b04f1154-518e-5b0b-a0ff-4fc2995db552', 'في جملة «أعطى الجدُّ الحفيدَ نقودًا»، ما المفعول به الثاني؟', '[{"id":"a","text":"الجدُّ"},{"id":"b","text":"الحفيدَ"},{"id":"c","text":"أعطى"},{"id":"d","text":"نقودًا"}]'::jsonb, 'd', '«أعطى» يتعدّى إلى مفعولين: الأوّل «الحفيدَ» (مَن أُعطي) والثاني «نقودًا» (ما أُعطي). فالمفعول الثاني «نقودًا» منصوبٌ بالفتحة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
