INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c1c8162b-79d4-5755-b923-1dd04a3933a0', 'b04f1154-518e-5b0b-a0ff-4fc2995db552', 'في جملة «يحترمُ الطلابُ أساتذتَهم»، ما إعرابُ «أساتذتَهم»؟', '[{"id":"a","text":"فاعلٌ مرفوع"},{"id":"b","text":"مفعولٌ به منصوب بالفتحة"},{"id":"c","text":"مبتدأٌ"},{"id":"d","text":"مجرورٌ"}]'::jsonb, 'b', 'وقعَ الاحترامُ على «أساتذتَهم»، فهي مفعولٌ به منصوبٌ بالفتحة (مفردُ «أساتذة» جمعُ تكسير). و«الطلابُ» فاعلٌ مرفوع.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e9a4140f-9577-55ec-aa91-e44b2a29e256', 'b04f1154-518e-5b0b-a0ff-4fc2995db552', 'في جملة «رجعَ المسافرونَ إلى ديارِهم سالمينَ»، أين المفعول به (إن وُجد)؟', '[{"id":"a","text":"«ديارِهم» مفعولٌ به"},{"id":"b","text":"«المسافرونَ» مفعولٌ به"},{"id":"c","text":"«سالمينَ» مفعولٌ به"},{"id":"d","text":"لا مفعول به؛ «رجعَ» فعلٌ لازم، و«إلى ديارِهم» جارٌّ ومجرور و«سالمينَ» حال"}]'::jsonb, 'd', '«رجعَ» لازمٌ لا يطلبُ مفعولًا. «إلى ديارِهم» جارٌّ ومجرور، و«سالمينَ» حالٌ منصوبٌ بالياء. فلا مفعولَ به في الجملة. الفخّ الشائع تسميةُ الجارّ والمجرور أو الحال مفعولًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ee6fc48c-edf1-5a62-a61e-6c1cc0419561', 'b04f1154-518e-5b0b-a0ff-4fc2995db552', 'حوّل «الفلاحُ يسقي» إلى جملةٍ فعلُها متعدٍّ بإضافة مفعولٍ به مناسب.', '[{"id":"a","text":"الفلاحُ يسقي الزرعَ"},{"id":"b","text":"الفلاحُ يسقي في"},{"id":"c","text":"يسقي الفلاحُ الفلاحُ"},{"id":"d","text":"هل يسقي الفلاحُ؟"}]'::jsonb, 'a', '«يسقي» فعلٌ متعدٍّ يطلبُ مفعولًا؛ نُكملُه بمفعولٍ منصوبٍ مناسب: «يسقي الزرعَ». الخياراتُ الأخرى ناقصةٌ أو خاطئة (حرفٌ بلا مجرور، أو تكرار، أو استفهام).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('b7c0be7d-3b01-5c7e-9d00-43857466ff5f', '8f5ea9ea-0054-5621-8eef-dff7c09854e5', 'arabic-5eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: سيّدُ الأفعال', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c1f0c220-8659-5785-b297-4aa3f4211d90', 'b7c0be7d-3b01-5c7e-9d00-43857466ff5f', 'في جملة «وهبَ التاجرُ المسجدَ سجّادًا»، أعرب الكلمات الثلاث بعد الفعل.', '[{"id":"a","text":"ثلاثتُها مفاعيل"},{"id":"b","text":"«التاجرُ» فاعلٌ مرفوع، و«المسجدَ» مفعولٌ به أوّل منصوب، و«سجّادًا» مفعولٌ به ثانٍ منصوب"},{"id":"c","text":"«التاجرُ» مفعولٌ و«المسجدَ» فاعل"},{"id":"d","text":"لا فاعل ولا مفعول"}]'::jsonb, 'b', '«وهبَ» يتعدّى إلى مفعولين. «التاجرُ» فاعلٌ مرفوع، و«المسجدَ» مفعولٌ به أوّل (مَن وُهب)، و«سجّادًا» مفعولٌ به ثانٍ (ما وُهب)، وكلاهما منصوب.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('87655027-17b0-526d-880c-e6d3f94cb126', 'b7c0be7d-3b01-5c7e-9d00-43857466ff5f', 'ميّز اللازمَ من المتعدّي: «سقطَ الكتابُ» و«أسقطَ الطفلُ الكتابَ».', '[{"id":"a","text":"كلاهما لازم"},{"id":"b","text":"كلاهما متعدٍّ"},{"id":"c","text":"«سقطَ» متعدٍّ و«أسقطَ» لازم"},{"id":"d","text":"«سقطَ» لازمٌ (سقطَ الكتابُ)، و«أسقطَ» متعدٍّ (أسقطَ … الكتابَ)"}]'::jsonb, 'd', '«سقطَ» لازمٌ يكتفي بفاعله. وبزيادة الهمزة صار «أسقطَ» متعدّيًا يطلبُ مفعولًا «الكتابَ». الهمزةُ هنا همزةُ تعدية تنقلُ الفعلَ من اللزوم إلى التعدية.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e834653c-a9a1-594d-bbdd-299a4a894b82', 'b7c0be7d-3b01-5c7e-9d00-43857466ff5f', 'في جملة «علّمَ الأستاذُ الطلابَ النحوَ»، ما نوعُ الفعل «علّمَ» من حيث التعدية؟', '[{"id":"a","text":"متعدٍّ إلى مفعولين: «الطلابَ» و«النحوَ»"},{"id":"b","text":"لازمٌ"},{"id":"c","text":"متعدٍّ إلى مفعولٍ واحدٍ فقط"},{"id":"d","text":"بلا فاعل"}]'::jsonb, 'a', '«علّمَ» يتعدّى إلى مفعولين: علّم مَن؟ «الطلابَ»، وعلّمهم ماذا؟ «النحوَ». فهما مفعولان منصوبان، و«الأستاذُ» فاعلٌ مرفوع.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('165a08a6-7e0f-54ba-a4e5-f96b4dfd414c', 'b7c0be7d-3b01-5c7e-9d00-43857466ff5f', 'في جملة «منَحَ الوطنُ أبناءَه المخلصينَ أوسمةً»، أعرب «المخلصينَ».', '[{"id":"a","text":"مفعولٌ به ثانٍ"},{"id":"b","text":"فاعلٌ ثانٍ"},{"id":"c","text":"نعتٌ لـ«أبناءَه» منصوبٌ بالياء (جمعُ مذكّرٍ سالم)"},{"id":"d","text":"حالٌ مرفوع"}]'::jsonb, 'c', '«أبناءَه» مفعولٌ به أوّل، و«المخلصينَ» نعتٌ له يتبعُه في النصب، وهو جمعُ مذكّرٍ سالم يُنصبُ بالياء. أمّا المفعول الثاني فهو «أوسمةً». فـ«المخلصينَ» نعتٌ منصوبٌ لا مفعول.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('321e5d22-cc85-593a-b9cf-8c38e627d043', 'b7c0be7d-3b01-5c7e-9d00-43857466ff5f', 'في جملة «باتَ الحارسُ يقظًا»، هل «يقظًا» مفعولٌ به؟ ولماذا؟', '[{"id":"a","text":"لا؛ «يقظًا» مفعولٌ به منصوب"},{"id":"b","text":"لا؛ «باتَ» فعلٌ ناقص (من أخوات كان)، و«يقظًا» خبرُها منصوبٌ لا مفعولٌ به"},{"id":"c","text":"نعم، هو مفعولٌ به لأنّه منصوب"},{"id":"d","text":"نعم، لأنّ «باتَ» فعلٌ متعدٍّ"}]'::jsonb, 'b', '«باتَ» من أخوات كان (فعلٌ ناقص) يرفعُ المبتدأ اسمًا له («الحارسُ») وينصبُ الخبر («يقظًا»). فـ«يقظًا» خبرُ باتَ المنصوب لا مفعولٌ به. النصبُ وحده لا يجعلُه مفعولًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('45c5c01b-e22d-5225-9d5f-7b4bdad88926', 'b7c0be7d-3b01-5c7e-9d00-43857466ff5f', 'أيُّ جملةٍ خلت من المفعول به تمامًا؟', '[{"id":"a","text":"زرعَ الفلاحُ القمحَ"},{"id":"b","text":"قرأَ الطالبُ الكتابَ"},{"id":"c","text":"ابتسمَ الطفلُ فرحًا في الحديقةِ"},{"id":"d","text":"بنى المهندسُ الجسرَ"}]'::jsonb, 'c', '«ابتسمَ» فعلٌ لازم؛ «فرحًا» مفعولٌ لأجله و«في الحديقةِ» جارٌّ ومجرور، فلا مفعولَ به. أمّا زرعَ وقرأَ وبنى فمتعدّيةٌ ولها مفاعيلُ (القمحَ، الكتابَ، الجسرَ).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

