  ('688b90b6-4966-5fe7-9942-6fb9bb6692e0', '8f5ea9ea-0054-5621-8eef-dff7c09854e5', 'arabic-5eme', '🛡️ تدريب ⭐⭐⭐: الأفعال والمفعول (مراجعة شاملة)', 3, 120, 30, 'boss', 'admin', 5)
