INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('acc4ef19-f024-5769-a30d-c04d75a652f3', '688b90b6-4966-5fe7-9942-6fb9bb6692e0', 'الفعل المتعدّي هو الذي:', '[{"id":"a","text":"يكتفي بفاعله"},{"id":"b","text":"لا فاعل له"},{"id":"c","text":"يتعدّى فاعلَه إلى مفعولٍ به"},{"id":"d","text":"يكون أمرًا فقط"}]'::jsonb, 'c', 'الفعل المتعدّي لا يكتفي بفاعله بل يتجاوزُه إلى مفعولٍ به يقعُ عليه أثرُ الفعل، مثل «كتبَ الدرسَ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('143ad76a-7b6d-57a2-97d5-bddc0a52e334', '688b90b6-4966-5fe7-9942-6fb9bb6692e0', 'في جملة «حصدَ الفلاحونَ القمحَ»، ما الفاعل؟', '[{"id":"a","text":"الفلاحونَ"},{"id":"b","text":"القمحَ"},{"id":"c","text":"حصدَ"},{"id":"d","text":"لا فاعل"}]'::jsonb, 'a', '«الفلاحونَ» هم من قاموا بالحصاد، فهم الفاعل المرفوع بالواو (جمعُ مذكّرٍ سالم). و«القمحَ» مفعولٌ به منصوب.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e244b8fa-40b2-59f0-9637-8ec8bd707a0b', '688b90b6-4966-5fe7-9942-6fb9bb6692e0', 'في جملة «سمّى الأبُ ابنَه خالدًا»، كم مفعولًا، وما هما؟', '[{"id":"a","text":"مفعولٌ واحد: ابنَه"},{"id":"b","text":"لا مفعول"},{"id":"c","text":"مفعولٌ واحد: خالدًا"},{"id":"d","text":"مفعولان: ابنَه وخالدًا"}]'::jsonb, 'd', '«سمّى» يتعدّى إلى مفعولين: سمّى مَن؟ «ابنَه»، وسمّاه ماذا؟ «خالدًا». فهما مفعولان منصوبان، و«الأبُ» فاعلٌ مرفوع.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f5c1fa46-409c-5b06-9612-786422069589', '688b90b6-4966-5fe7-9942-6fb9bb6692e0', 'في جملة «خرجَ التلاميذُ من القاعةِ مسرعينَ»، أين المفعول به؟', '[{"id":"a","text":"«القاعةِ» مفعولٌ به"},{"id":"b","text":"لا مفعول به؛ «خرجَ» لازمٌ، و«من القاعةِ» جارٌّ ومجرور و«مسرعينَ» حال"},{"id":"c","text":"«مسرعينَ» مفعولٌ به"},{"id":"d","text":"«التلاميذُ» مفعولٌ به"}]'::jsonb, 'b', '«خرجَ» فعلٌ لازم. «من القاعةِ» جارٌّ ومجرور، و«مسرعينَ» حالٌ منصوبٌ بالياء. فلا مفعولَ به في الجملة. الفخّ تسميةُ الجارّ والمجرور أو الحال مفعولًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9ea03184-2c53-5228-89c9-918b7ebe79fe', '688b90b6-4966-5fe7-9942-6fb9bb6692e0', 'في جملة «أرى المعلّمُ التلاميذَ التجربةَ ناجحةً»، ما عددُ مفاعيل «أرى»؟', '[{"id":"a","text":"لا مفاعيل"},{"id":"b","text":"مفعولٌ واحد"},{"id":"c","text":"ثلاثةُ مفاعيل: التلاميذَ، التجربةَ، ناجحةً"},{"id":"d","text":"مفعولان فقط"}]'::jsonb, 'c', '«أرى» من الأفعال التي تتعدّى إلى ثلاثة مفاعيل: «التلاميذَ» و«التجربةَ» و«ناجحةً»، وكلُّها منصوبة. و«المعلّمُ» فاعلٌ مرفوع.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('424d8ca0-13aa-5f6e-a1af-a4139932fdf1', '688b90b6-4966-5fe7-9942-6fb9bb6692e0', 'في جملة «كافأَ المديرُ الفائزينَ»، ما علامةُ نصب المفعول به «الفائزينَ»؟', '[{"id":"a","text":"الياء (جمعُ مذكّرٍ سالم يُنصبُ بالياء)"},{"id":"b","text":"الفتحة"},{"id":"c","text":"الضمّة"},{"id":"d","text":"الكسرة"}]'::jsonb, 'a', '«الفائزينَ» مفعولٌ به وهو جمعُ مذكّرٍ سالم، يُنصبُ بالياء نيابةً عن الفتحة. فعلامةُ نصبه الياء لا الفتحة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

