INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1daf9ea3-98dc-501c-8f10-0410ec54288a', '79a60beb-c9fb-596c-b2df-f6c6b391cad3', 'الفعل المبنيّ للمجهول هو الذي:', '[{"id":"a","text":"ذُكِرَ فاعلُه"},{"id":"b","text":"لا مفعول له"},{"id":"c","text":"حُذِفَ فاعلُه وقامَ غيرُه مقامَه"},{"id":"d","text":"يكون في المستقبل"}]'::jsonb, 'c', 'المبنيّ للمجهول فعلٌ حُذف فاعلُه، فناب عنه المفعولُ به (نائب الفاعل) وارتفع. مثل «كُسِرَ الزجاجُ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
