INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c355f4af-6b6b-5b0e-83d2-8d4f9ac0da2c', '0cf4c3ee-7fc4-5fb5-a5b8-2e17ca8477a0', 'حوّل «أكلَ الضيفُ التفاحةَ» إلى المبنيّ للمجهول.', '[{"id":"a","text":"أكلَ التفاحةَ"},{"id":"b","text":"يأكلُ الضيفُ"},{"id":"c","text":"أَكَلَ الضيفُ"},{"id":"d","text":"أُكِلَتِ التفاحةُ"}]'::jsonb, 'd', 'نحذفُ الفاعلَ ونبني الفعلَ للمجهول «أُكِلَتْ» (مع تاء التأنيث لأنّ النائب مؤنّث)، ونرفعُ «التفاحةُ» نائبَ فاعل: «أُكِلَتِ التفاحةُ».', 4)
