INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('58bbd890-471d-52a4-ad9e-99006dde9fab', '0cf4c3ee-7fc4-5fb5-a5b8-2e17ca8477a0', 'أيُّ جملةٍ فعلُها مبنيٌّ للمجهول؟', '[{"id":"a","text":"بنى العمّالُ الجسرَ"},{"id":"b","text":"حصدَ الفلاحُ القمحَ"},{"id":"c","text":"فُتِحَتِ الأبوابُ"},{"id":"d","text":"قرأَ الطالبُ القصّةَ"}]'::jsonb, 'c', '«فُتِحَتِ الأبوابُ» فعلُها «فُتِحَتْ» مضمومُ الأوّل مكسورُ ما قبل الآخر، وحُذف فاعلُه، فهو مبنيٌّ للمجهول. الباقي فاعلُه مذكورٌ فهو للمعلوم.', 6)
