INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4fdd648d-e1b8-5267-8a19-a21b2f3cba48', 'f5e95aba-0add-5101-810d-a0285af767fe', 'لماذا قد نبني الفعلَ للمجهول؟', '[{"id":"a","text":"لإضافة فاعلين"},{"id":"b","text":"لتحويل الجملة إلى استفهام"},{"id":"c","text":"لجعل الفعل أمرًا"},{"id":"d","text":"للجهل بالفاعل أو لعدم أهمّيّته أو لإخفائه"}]'::jsonb, 'd', 'نبني الفعلَ للمجهول حين نجهلُ الفاعلَ، أو لا تهمُّنا معرفتُه، أو نريدُ إخفاءه؛ فنحذفُه ويقومُ نائبُ الفاعل مقامَه.', 1)
