INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cb27285c-ea71-5613-918a-b26375d5f410', 'f5e95aba-0add-5101-810d-a0285af767fe', 'في جملة «مُنِحَ المتفوّقونَ جوائزَ»، أعرب «المتفوّقونَ».', '[{"id":"a","text":"مفعولٌ به منصوب بالياء"},{"id":"b","text":"نائب فاعلٍ مرفوع بالواو (جمعُ مذكّرٍ سالم)"},{"id":"c","text":"فاعلٌ ظاهر"},{"id":"d","text":"مجرورٌ بحرف جرّ"}]'::jsonb, 'b', '«المتفوّقونَ» نائبُ فاعلٍ (كان مفعولًا أوّل)، وهو جمعُ مذكّرٍ سالم يُرفعُ بالواو. والمفعول الثاني «جوائزَ» يبقى منصوبًا.', 2)
