INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e695f130-cac3-5706-8f7b-a4f848e044da', 'f5e95aba-0add-5101-810d-a0285af767fe', 'حوّل «يحترمُ الناسُ العالِمَ» إلى المبنيّ للمجهول.', '[{"id":"a","text":"يحترمُ العالِمَ"},{"id":"b","text":"احترمَ الناسُ"},{"id":"c","text":"يُحترَمُ العالِمُ"},{"id":"d","text":"هل يحترمُ الناسُ العالِمَ؟"}]'::jsonb, 'c', 'نحذفُ الفاعلَ «الناسُ»، ونبني المضارعَ للمجهول «يُحترَمُ» (ضمُّ الأوّل وفتحُ ما قبل الآخر)، ونرفعُ «العالِمُ» نائبَ فاعل: «يُحترَمُ العالِمُ».', 3)
