INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('faf8bada-2952-5216-88e4-f5d3dd3701e5', 'f5e95aba-0add-5101-810d-a0285af767fe', 'في جملة «كُوفِئَ المجتهدونَ تكريمًا لهم»، ما إعرابُ «تكريمًا»؟', '[{"id":"a","text":"مفعولٌ لأجله منصوب (وليس نائبَ فاعلٍ)"},{"id":"b","text":"نائب فاعلٍ مرفوع"},{"id":"c","text":"فاعلٌ"},{"id":"d","text":"مبتدأٌ"}]'::jsonb, 'a', 'نائبُ الفاعل هو «المجتهدونَ» المرفوع. أمّا «تكريمًا» فمفعولٌ لأجله منصوبٌ يبيّنُ سببَ المكافأة، لا نائبَ فاعل. الفخّ الخلطُ بين النصب المتبقّي ونائب الفاعل.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
