  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('23e8627e-7615-5324-874f-a97e98e7c0cf', 'f5e95aba-0add-5101-810d-a0285af767fe', 'ما الخطأُ في قول: «فُتِحَ البابَ»؟', '[{"id":"a","text":"لا خطأَ فيه"},{"id":"b","text":"الفعلُ غيرُ مبنيٍّ للمجهول"},{"id":"c","text":"يجبُ حذفُ الفعل"},{"id":"d","text":"نائبُ الفاعل يجبُ رفعُه: «فُتِحَ البابُ» لا «البابَ»"}]'::jsonb, 'd', 'بعد بناء الفعل للمجهول يرتفعُ المفعولُ نائبَ فاعل، فالصواب «فُتِحَ البابُ» بالرفع لا «البابَ» بالنصب. هذا أشهرُ أخطاء المجهول.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('305798cc-6e9a-51b4-8631-11cc9df59306', 'f5e95aba-0add-5101-810d-a0285af767fe', 'في جملة «يُعَلَّمُ الأطفالُ القراءةَ»، حدّد نائبَ الفاعل والمفعول الباقي.', '[{"id":"a","text":"نائب الفاعل: القراءةَ، والمفعول: الأطفالُ"},{"id":"b","text":"نائب الفاعل: الأطفالُ (مرفوع)، والمفعول الباقي: القراءةَ (منصوب)"},{"id":"c","text":"لا نائب فاعل في الجملة"},{"id":"d","text":"كلاهما مرفوع"}]'::jsonb, 'b', '«علّمَ» يتعدّى إلى مفعولين؛ لمّا بُني للمجهول ناب المفعولُ الأوّل «الأطفالُ» عن الفاعل فارتفع، وبقي الثاني «القراءةَ» منصوبًا.', 6)
