INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ce916680-4924-5f56-a0e4-78c111708352', '2350474f-c25c-521b-8814-fc0091fdf3a2', 'حوّل «بنى المهندسونَ القصرَ» إلى المبنيّ للمجهول.', '[{"id":"a","text":"بُنِيَ القصرُ"},{"id":"b","text":"بنى القصرَ"},{"id":"c","text":"يبني المهندسونَ"},{"id":"d","text":"بَنى المهندسونَ"}]'::jsonb, 'a', 'نحذفُ الفاعلَ، ونبني الماضيَ الناقصَ للمجهول «بُنِيَ»، ونرفعُ المفعولَ نائبَ فاعل: «بُنِيَ القصرُ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0a82bcf4-9e03-5617-84db-93b4d0782abd', '2350474f-c25c-521b-8814-fc0091fdf3a2', 'في جملة «عُولِجَ المريضُ في المستشفى»، أعرب «المريضُ» و«المستشفى».', '[{"id":"a","text":"كلاهما نائب فاعل"},{"id":"b","text":"«المريضُ» مفعولٌ به و«المستشفى» نائب فاعل"},{"id":"c","text":"«المريضُ» نائب فاعلٍ مرفوع، و«في المستشفى» جارٌّ ومجرور"},{"id":"d","text":"«المريضُ» فاعلٌ ظاهر"}]'::jsonb, 'c', 'بُني الفعلُ للمجهول، فناب «المريضُ» عن الفاعل وارتفع. و«في المستشفى» جارٌّ ومجرور يبيّنُ المكان، لا نائبَ فاعل.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('628fba66-a70b-5cd2-99fc-017bb31448c6', '2350474f-c25c-521b-8814-fc0091fdf3a2', 'أيُّ تحويلٍ خاطئٌ للمبنيّ للمجهول؟', '[{"id":"a","text":"كَتَبَ الدرسَ ← كُتِبَ الدرسُ"},{"id":"b","text":"فَتَحَ البابَ ← فُتِحَ البابُ"},{"id":"c","text":"أكلَ الطعامَ ← أُكِلَ الطعامُ"},{"id":"d","text":"شَرِبَ الماءَ ← شَرِبَ الماءَ (بلا تغيير)"}]'::jsonb, 'd', 'الخطأُ في (د): تُرك الفعلُ بلا ضبطٍ وبقيَ المفعولُ منصوبًا، فلم يُبنَ للمجهول. الصواب «شُرِبَ الماءُ» (ضمُّ الأوّل ورفعُ النائب). الباقي تحويلٌ صحيح.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bb3f6378-f016-59b1-9112-22fa332139b9', '2350474f-c25c-521b-8814-fc0091fdf3a2', 'في جملة «يُكَافأُ المخلصونَ على إخلاصِهم»، ما إعرابُ «المخلصونَ»؟', '[{"id":"a","text":"مفعولٌ به منصوب"},{"id":"b","text":"نائب فاعلٍ مرفوع بالواو (جمعُ مذكّرٍ سالم)"},{"id":"c","text":"مبتدأٌ"},{"id":"d","text":"فاعلٌ ظاهر"}]'::jsonb, 'b', 'بُني المضارعُ للمجهول «يُكافأُ»، فناب «المخلصونَ» عن الفاعل وارتفع بالواو لأنّه جمعُ مذكّرٍ سالم. و«على إخلاصِهم» جارٌّ ومجرور.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('6306401c-a35e-559b-93e8-9c519c8a4d23', '57dd16e4-005a-5fce-8728-72cd20178ebd', 'arabic-5eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: سيّدُ البناء والنيابة', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
