  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ddb2e19a-9b1d-5dd4-81b2-257c92409fa3', '6306401c-a35e-559b-93e8-9c519c8a4d23', 'في جملة «أُعطِيَ الفقيرُ صدقةً»، أعرب «الفقيرُ» و«صدقةً».', '[{"id":"a","text":"كلاهما منصوب"},{"id":"b","text":"«الفقيرُ» مفعولٌ به و«صدقةً» نائب فاعل"},{"id":"c","text":"«الفقيرُ» نائب فاعلٍ مرفوع (المفعول الأوّل)، و«صدقةً» مفعولٌ به ثانٍ منصوب"},{"id":"d","text":"لا نائب فاعل"}]'::jsonb, 'c', '«أعطى» يتعدّى لمفعولين؛ لمّا بُني للمجهول ناب الأوّلُ «الفقيرُ» عن الفاعل فارتفع، وبقي الثاني «صدقةً» منصوبًا. هذا حكمُ ما تعدّى لمفعولين عند البناء للمجهول.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('21ba6af4-4ee5-5b30-9623-d8915c78e083', '6306401c-a35e-559b-93e8-9c519c8a4d23', 'ابنِ للمجهول: «شاهدَ الجمهورُ المباراةَ»، ثمّ أعرب الناتج.', '[{"id":"a","text":"شوهِدَتِ المباراةُ — «المباراةُ» نائب فاعلٍ مرفوع"},{"id":"b","text":"شاهدَ المباراةَ — بلا تغيير"},{"id":"c","text":"شُوهِدَ المباراةَ — «المباراةَ» مفعولٌ منصوب"},{"id":"d","text":"يشاهدُ الجمهورُ"}]'::jsonb, 'a', 'نبني «شاهدَ» للمجهول «شوهِدَ» ونلحقُ تاءَ التأنيث لأنّ النائب مؤنّث «شوهِدَتْ»، ونرفعُ «المباراةُ» نائبَ فاعل. فالصواب «شوهِدَتِ المباراةُ» بالرفع.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d8297056-05d7-5d4c-840a-59a1107f6d42', '6306401c-a35e-559b-93e8-9c519c8a4d23', 'في جملة «يُسافَرُ ليلًا في الصحراءِ»، الفعلُ مبنيٌّ للمجهول من فعلٍ لازم. أين نائب الفاعل؟', '[{"id":"a","text":"«ليلًا» نائب الفاعل"},{"id":"b","text":"«الصحراءِ» نائب الفاعل"},{"id":"c","text":"«يُسافَرُ» نائب الفاعل"},{"id":"d","text":"ناب الظرفُ/الجارُّ والمجرور عن الفاعل لأنّ الفعل لازمٌ لا مفعولَ له («ليلًا» ظرفٌ نائبٌ، أو «في الصحراءِ»)"}]'::jsonb, 'd', 'إذا بُني الفعلُ اللازمُ للمجهول ولا مفعولَ له، نابَ عن الفاعل الظرفُ أو الجارُّ والمجرور أو المصدر. هنا ناب الظرفُ «ليلًا» (أو الجارُّ والمجرور «في الصحراءِ»). فلا يلزمُ وجودُ مفعولٍ به للبناء للمجهول.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b19924b3-58e1-5034-b459-5a4687a12418', '6306401c-a35e-559b-93e8-9c519c8a4d23', 'ميّز الصوابَ: «عُيِّنَ المهندسُ مديرًا».', '[{"id":"a","text":"«المهندسُ» مفعولٌ منصوب"},{"id":"b","text":"«المهندسُ» نائب فاعلٍ مرفوع، و«مديرًا» مفعولٌ به ثانٍ منصوب"},{"id":"c","text":"كلاهما مرفوع"},{"id":"d","text":"لا نائب فاعل"}]'::jsonb, 'b', '«عيّنَ» يتعدّى لمفعولين؛ عند البناء للمجهول ناب الأوّلُ «المهندسُ» عن الفاعل فارتفع، وبقي الثاني «مديرًا» منصوبًا. ضبطُهما مختلف: رفعٌ ثمّ نصب.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('48367f4f-39ef-54eb-b749-9311902c890a', '6306401c-a35e-559b-93e8-9c519c8a4d23', 'ما المبنيّ للمجهول الصحيح من المضارع المعتلّ «يقولُ»؟', '[{"id":"a","text":"يَقولُ كما هو"},{"id":"b","text":"يُقاوِلُ"},{"id":"c","text":"يُقالُ"},{"id":"d","text":"قُلْ"}]'::jsonb, 'c', 'في المضارع المعتلّ الأجوف «يقولُ» يُبنى للمجهول بضمّ أوّله وقلب حرف العلّة ألفًا: يقولُ ← يُقالُ. فنقول «يُقالُ الحقُّ».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e5faea1a-c593-59d7-bd4f-b5abbfa3a7af', '6306401c-a35e-559b-93e8-9c519c8a4d23', 'في جملة «حُفِظَتِ الحقوقُ وصينَتِ الكرامةُ»، كم نائبَ فاعلٍ في الجملة؟', '[{"id":"a","text":"نائبا فاعلٍ: «الحقوقُ» لـ«حُفِظَتْ»، و«الكرامةُ» لـ«صينَتْ»"},{"id":"b","text":"نائب فاعلٍ واحد"},{"id":"c","text":"لا نائب فاعل"},{"id":"d","text":"ثلاثةُ نوّاب"}]'::jsonb, 'a', 'في الجملة فعلان مبنيّان للمجهول: «حُفِظَتْ» نائبُ فاعله «الحقوقُ»، و«صينَتْ» نائبُ فاعله «الكرامةُ». فهما نائبا فاعلٍ مرفوعان.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

