  ('bc4903ab-739a-5c14-a4a6-5b091a401d5d', '57dd16e4-005a-5fce-8728-72cd20178ebd', 'arabic-5eme', '🛡️ تدريب ⭐⭐⭐: المعلوم والمجهول (مراجعة شاملة)', 3, 120, 30, 'boss', 'admin', 5)
