INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eccc7d0e-e3af-5690-9fd3-249181fd1a34', 'bc4903ab-739a-5c14-a4a6-5b091a401d5d', 'الفعل المبنيّ للمعلوم هو الذي:', '[{"id":"a","text":"حُذف فاعلُه"},{"id":"b","text":"لا مفعول له"},{"id":"c","text":"يكون أمرًا"},{"id":"d","text":"ذُكِرَ فاعلُه في الجملة"}]'::jsonb, 'd', 'المبنيّ للمعلوم فعلٌ فاعلُه مذكورٌ معلوم، مثل «كتبَ التلميذُ الدرسَ».', 1)
