INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0a3c510d-f7e5-59e3-aa6b-7bb11524979d', 'bc4903ab-739a-5c14-a4a6-5b091a401d5d', 'نبني الماضيَ للمجهول بـ:', '[{"id":"a","text":"فتح أوّله وضمّ آخره"},{"id":"b","text":"ضمّ أوّله وكسر ما قبل آخره"},{"id":"c","text":"حذف أوّله"},{"id":"d","text":"تشديد وسطه"}]'::jsonb, 'b', 'قاعدةُ بناء الماضي للمجهول: ضمُّ الحرف الأوّل وكسرُ ما قبل الآخر: نَصَرَ ← نُصِرَ.', 2)
