INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('88c71b7d-e01a-5815-9298-4b0f1abcb2ae', 'bc4903ab-739a-5c14-a4a6-5b091a401d5d', 'حوّل «يقطفُ الأطفالُ الأزهارَ» إلى المبنيّ للمجهول.', '[{"id":"a","text":"تُقطَفُ الأزهارُ"},{"id":"b","text":"يقطفُ الأزهارَ"},{"id":"c","text":"اقطفِ الأزهارَ"},{"id":"d","text":"يَقطفُ الأطفالُ"}]'::jsonb, 'a', 'نحذفُ الفاعلَ، ونبني المضارعَ للمجهول مع تأنيث الفعل لأنّ النائب جمعٌ مؤنّثٌ مجازيّ «تُقطَفُ»، ونرفعُ «الأزهارُ» نائبَ فاعل: «تُقطَفُ الأزهارُ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1ad7ca11-cf51-5541-88a6-fef12314204b', 'bc4903ab-739a-5c14-a4a6-5b091a401d5d', 'في جملة «كُرِّمَ الفائزونَ في الحفلِ»، أعرب «الفائزونَ».', '[{"id":"a","text":"مفعولٌ به منصوب بالياء"},{"id":"b","text":"مبتدأٌ"},{"id":"c","text":"نائب فاعلٍ مرفوع بالواو (جمعُ مذكّرٍ سالم)"},{"id":"d","text":"حالٌ"}]'::jsonb, 'c', 'بُني «كرّمَ» للمجهول، فناب «الفائزونَ» عن الفاعل وارتفع بالواو لأنّه جمعُ مذكّرٍ سالم. و«في الحفلِ» جارٌّ ومجرور.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cc42c624-c42b-55d9-a5a5-33b699b0cfbe', 'bc4903ab-739a-5c14-a4a6-5b091a401d5d', 'ما الخطأُ في «نُظِّفَتِ الشوارعَ»؟', '[{"id":"a","text":"نائبُ الفاعل «الشوارعَ» يجبُ رفعُه: «الشوارعُ» (مرفوعٌ لا منصوب)"},{"id":"b","text":"لا خطأَ فيه"},{"id":"c","text":"الفعلُ يجبُ أن يكون أمرًا"},{"id":"d","text":"يجبُ حذفُ الفعل"}]'::jsonb, 'a', 'بعد البناء للمجهول يرتفعُ المفعولُ نائبَ فاعل؛ فالصواب «نُظِّفَتِ الشوارعُ» بالرفع لا «الشوارعَ» بالنصب. وهو خطأٌ شائعٌ في ضبط نائب الفاعل.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6742588e-ae6f-58eb-b14b-21d6f4c3ebb3', 'bc4903ab-739a-5c14-a4a6-5b091a401d5d', 'في جملة «يُمنَحُ المتفوّقُ شهادةً تقديريّةً»، حدّد نائبَ الفاعل والمفعول الباقي.', '[{"id":"a","text":"نائب الفاعل: شهادةً، والمفعول: المتفوّقُ"},{"id":"b","text":"نائب الفاعل: المتفوّقُ (مرفوع)، والمفعول الباقي: شهادةً (منصوب)"},{"id":"c","text":"لا نائب فاعل"},{"id":"d","text":"كلاهما منصوب"}]'::jsonb, 'b', '«منحَ» يتعدّى لمفعولين؛ عند البناء للمجهول ناب المفعولُ الأوّل «المتفوّقُ» عن الفاعل فارتفع، وبقي الثاني «شهادةً» منصوبًا (ونعتُها «تقديريّةً» منصوبٌ تبعًا له).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('e43111b5-534d-5d29-9773-d33bd5b8774a', '82efdbaa-46e7-5eed-968c-d4f3a9d355f3', 'arabic-5eme', 'اختبار فهم الدرس ⭐ (فهم)', 1, 20, 5, 'quiz', 'admin', 0)
