INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4bccbb91-b142-5ac1-92c0-441468291ce8', 'e43111b5-534d-5d29-9773-d33bd5b8774a', 'المفعول فيه (الظرف) يدلُّ على:', '[{"id":"a","text":"سبب الفعل"},{"id":"b","text":"زمان الفعل أو مكانه"},{"id":"c","text":"هيئة الفاعل"},{"id":"d","text":"عدد الفاعلين"}]'::jsonb, 'b', 'المفعول فيه ظرفٌ يبيّنُ زمانَ الفعل (صباحًا) أو مكانَه (تحتَ)، ويتضمّنُ معنى «في». أمّا السببُ فللمفعول لأجله، والهيئةُ للحال.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0ce9bf0d-2e4f-5cd7-a824-f6ae2eed8236', 'e43111b5-534d-5d29-9773-d33bd5b8774a', 'في جملة «وقفَ التلاميذُ احترامًا للمعلّمِ»، ما إعرابُ «احترامًا»؟', '[{"id":"a","text":"مفعولٌ فيه"},{"id":"b","text":"حالٌ"},{"id":"c","text":"مفعولٌ لأجله (سبب الوقوف) منصوب"},{"id":"d","text":"فاعلٌ"}]'::jsonb, 'c', '«احترامًا» مصدرٌ يبيّنُ سببَ الوقوف (لماذا وقفوا؟ احترامًا)، فهو مفعولٌ لأجله منصوب.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b281de29-7483-50e9-94a4-84ada07d160e', 'e43111b5-534d-5d29-9773-d33bd5b8774a', 'في جملة «رجعَ الجيشُ منتصرًا»، ما إعرابُ «منتصرًا»؟', '[{"id":"a","text":"حالٌ منصوب (يبيّنُ هيئةَ الجيش)"},{"id":"b","text":"مفعولٌ به"},{"id":"c","text":"مفعولٌ مطلق"},{"id":"d","text":"ظرفٌ"}]'::jsonb, 'a', '«منتصرًا» يبيّنُ هيئةَ الجيش حين الرجوع (كيف رجع؟ منتصرًا)، فهو حالٌ منصوبٌ وصاحبُه «الجيشُ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b3d832b4-6882-53fe-9e9b-e04832273fbd', 'e43111b5-534d-5d29-9773-d33bd5b8774a', 'في جملة «فرحَ الفائزُ فرحًا»، ما إعرابُ «فرحًا»؟', '[{"id":"a","text":"مفعولٌ فيه"},{"id":"b","text":"حالٌ"},{"id":"c","text":"مفعولٌ لأجله"},{"id":"d","text":"مفعولٌ مطلق (مصدرٌ من لفظ الفعل يؤكّدُه)"}]'::jsonb, 'd', '«فرحًا» مصدرٌ من لفظ الفعل «فرحَ»، ذُكر لتوكيد الفعل، فهو مفعولٌ مطلق منصوب.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bc64643a-6a30-52cc-a57d-2beecfb07afa', 'e43111b5-534d-5d29-9773-d33bd5b8774a', 'أيُّ متمّمٍ يجيبُ عن سؤال «لماذا؟»؟', '[{"id":"a","text":"المفعول فيه"},{"id":"b","text":"المفعول لأجله"},{"id":"c","text":"الحال"},{"id":"d","text":"المفعول المطلق"}]'::jsonb, 'b', 'المفعول لأجله يبيّنُ سببَ الفعل ويجيبُ عن «لماذا؟»، مثل «سافرَ طلبًا للعلمِ». أمّا «متى/أين» فللظرف، و«كيف» للحال.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

