INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0aee3645-0e66-577a-9d68-e76210cb283a', '33b03854-5782-531d-93e9-a76d63302d45', 'في جملة «سافرَ أبي صباحًا»، ما إعرابُ «صباحًا»؟', '[{"id":"a","text":"مفعولٌ به"},{"id":"b","text":"حالٌ"},{"id":"c","text":"مفعولٌ فيه (ظرف زمان) منصوب"},{"id":"d","text":"فاعلٌ"}]'::jsonb, 'c', '«صباحًا» يدلُّ على زمان السفر (متى سافر؟ صباحًا)، فهو مفعولٌ فيه (ظرف زمان) منصوب.', 1)
