INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a2cdae2c-acf1-5dc4-b259-437cd21c30fe', '33b03854-5782-531d-93e9-a76d63302d45', 'في جملة «جلسَ القطُّ تحتَ الطاولةِ»، ما إعرابُ «تحتَ»؟', '[{"id":"a","text":"مفعولٌ فيه (ظرف مكان) منصوب"},{"id":"b","text":"مفعولٌ به"},{"id":"c","text":"فاعلٌ"},{"id":"d","text":"حرفُ جرّ"}]'::jsonb, 'a', '«تحتَ» يدلُّ على مكان الجلوس (أين جلس؟ تحتَ)، فهو مفعولٌ فيه (ظرف مكان) منصوب.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('19c09792-eb17-59b4-8449-a16e68efd724', '33b03854-5782-531d-93e9-a76d63302d45', 'أيُّ كلمةٍ تصلحُ حالًا (تبيّنُ هيئةَ صاحبها)؟', '[{"id":"a","text":"صباحًا"},{"id":"b","text":"ضاحكًا"},{"id":"c","text":"تحتَ"},{"id":"d","text":"احترامًا"}]'::jsonb, 'b', '«ضاحكًا» تبيّنُ هيئةَ صاحبها (جاء كيف؟ ضاحكًا)، فهي حال. أمّا «صباحًا» فظرف، و«تحتَ» ظرفُ مكان، و«احترامًا» مفعولٌ لأجله.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1cfe3a2e-5fc2-510d-8a96-64b90a86fe85', '33b03854-5782-531d-93e9-a76d63302d45', 'في جملة «قامَ الطلابُ إجلالًا لأستاذِهم»، ما إعرابُ «إجلالًا»؟', '[{"id":"a","text":"مفعولٌ فيه"},{"id":"b","text":"حالٌ"},{"id":"c","text":"ظرفُ مكان"},{"id":"d","text":"مفعولٌ لأجله (سبب القيام) منصوب"}]'::jsonb, 'd', '«إجلالًا» مصدرٌ يبيّنُ سببَ القيام (لماذا قاموا؟ إجلالًا)، فهو مفعولٌ لأجله منصوب.', 4)
ON CONFLICT (id) DO UPDATE SET
