  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('493d693b-8263-527c-805f-ad929086faf6', '33b03854-5782-531d-93e9-a76d63302d45', 'في جملة «دارَ اللاعبُ دورتينِ»، ما إعرابُ «دورتينِ»؟', '[{"id":"a","text":"حالٌ"},{"id":"b","text":"مفعولٌ فيه"},{"id":"c","text":"مفعولٌ مطلق (يبيّنُ عددَ الدوران)"},{"id":"d","text":"فاعلٌ"}]'::jsonb, 'c', '«دورتينِ» مصدرُ مرّةٍ من لفظ الفعل يبيّنُ عددَ الدوران (كم دار؟ دورتينِ)، فهو مفعولٌ مطلق منصوبٌ بالياء (مثنّى).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('94d03f48-e3e1-583c-ad14-ced2912e554d', '33b03854-5782-531d-93e9-a76d63302d45', 'في جملة «وصلَ الضيوفُ مساءً»، «مساءً» تجيبُ عن سؤال:', '[{"id":"a","text":"متى؟ (فهي ظرف زمان / مفعول فيه)"},{"id":"b","text":"لماذا؟"},{"id":"c","text":"كيف؟"},{"id":"d","text":"كم؟"}]'::jsonb, 'a', '«مساءً» تجيبُ عن «متى وصلوا؟»، فهي ظرفُ زمان (مفعول فيه) منصوب. سؤالُ «لماذا» للمفعول لأجله و«كيف» للحال.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

