  ('1724d61b-20c1-50a4-8593-7fe0855425bb', '82efdbaa-46e7-5eed-968c-d4f3a9d355f3', 'arabic-5eme', '⚔️ زعيم الفصل ⭐⭐⭐: حارسُ المتمّمات (صعب)', 3, 120, 30, 'boss', 'admin', 2)
