INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a2452a18-5601-558b-b596-95b42eb2b1d4', '1724d61b-20c1-50a4-8593-7fe0855425bb', 'ما القاسمُ المشتركُ بين المفعول فيه والمطلق ولأجله والحال؟', '[{"id":"a","text":"كلُّها منصوبة"},{"id":"b","text":"كلُّها مرفوعة"},{"id":"c","text":"كلُّها أفعال"},{"id":"d","text":"كلُّها حروف"}]'::jsonb, 'a', 'المفعول فيه والمطلق ولأجله والحال كلُّها متمّماتٌ **منصوبة** تُثري المعنى. اختلافُها في وظيفتها (الزمان/المكان، التوكيد، السبب، الهيئة) لا في النصب.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7c4b788c-a405-52f2-a428-40a2492e8bfd', '1724d61b-20c1-50a4-8593-7fe0855425bb', 'في جملة «انتظرتُكَ ساعةً أمامَ المدرسةِ»، أعرب «ساعةً» و«أمامَ».', '[{"id":"a","text":"كلاهما حال"},{"id":"b","text":"«ساعةً» مفعولٌ به و«أمامَ» فاعل"},{"id":"c","text":"«ساعةً» مفعولٌ فيه (ظرف زمان) و«أمامَ» مفعولٌ فيه (ظرف مكان)، وكلاهما منصوب"},{"id":"d","text":"كلاهما مفعولٌ مطلق"}]'::jsonb, 'c', '«ساعةً» تبيّنُ زمانَ الانتظار (مفعول فيه/ظرف زمان)، و«أمامَ» تبيّنُ مكانَه (مفعول فيه/ظرف مكان)، وكلاهما منصوب.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('274d241e-578d-50e7-a108-1868bc80ae2b', '1724d61b-20c1-50a4-8593-7fe0855425bb', 'في جملة «أكلَ الطفلُ التفاحةَ ناضجةً»، ما إعرابُ «ناضجةً» وصاحبُها؟', '[{"id":"a","text":"مفعولٌ به ثانٍ"},{"id":"b","text":"مفعولٌ مطلق"},{"id":"c","text":"ظرفٌ"},{"id":"d","text":"حالٌ منصوبة، وصاحبُها المفعول به «التفاحةَ»"}]'::jsonb, 'd', '«ناضجةً» تبيّنُ هيئةَ التفاحة حين الأكل (كيف كانت؟ ناضجةً)، فهي حالٌ منصوبة، وصاحبُها هنا المفعول به «التفاحةَ» لا الفاعل.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bb7aa078-50ce-5a00-8848-6e192e07c2ff', '1724d61b-20c1-50a4-8593-7fe0855425bb', 'ميّز نوعَ المنصوب في: «سعى التاجرُ سعيًا حثيثًا طمعًا في الربحِ».', '[{"id":"a","text":"«سعيًا» حالٌ و«طمعًا» ظرف"},{"id":"b","text":"«سعيًا» مفعولٌ مطلق (مصدرٌ من لفظ الفعل)، و«طمعًا» مفعولٌ لأجله (سبب)"},{"id":"c","text":"كلاهما مفعولٌ به"},{"id":"d","text":"كلاهما مفعولٌ فيه"}]'::jsonb, 'b', '«سعيًا» مصدرٌ من لفظ الفعل «سعى» يؤكّدُه ويبيّنُ نوعَه (بنعته «حثيثًا») فهو مفعولٌ مطلق. و«طمعًا» يبيّنُ سببَ السعي (لماذا؟) فهو مفعولٌ لأجله. ولكلٍّ وظيفةٌ مختلفة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f3df9874-9a69-5e45-a70c-e23facf83845', '1724d61b-20c1-50a4-8593-7fe0855425bb', 'في جملة «خرجَ المسافرونَ من المدينةِ ليلًا خائفينَ»، أعرب «ليلًا» و«خائفينَ».', '[{"id":"a","text":"«ليلًا» مفعولٌ فيه (ظرف زمان) منصوب، و«خائفينَ» حالٌ منصوبة بالياء"},{"id":"b","text":"كلاهما مفعولٌ به"},{"id":"c","text":"«ليلًا» حالٌ و«خائفينَ» ظرف"},{"id":"d","text":"كلاهما فاعل"}]'::jsonb, 'a', '«ليلًا» يبيّنُ زمانَ الخروج فهو مفعولٌ فيه منصوب. و«خائفينَ» يبيّنُ هيئةَ المسافرين فهو حالٌ، وهو جمعُ مذكّرٍ سالم منصوبٌ بالياء.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('770ce4fc-8aba-5fa1-89ea-12b3c711758c', '1724d61b-20c1-50a4-8593-7fe0855425bb', 'لماذا «صبرًا» في «صبرتُ صبرًا جميلًا» مفعولٌ مطلق لا مفعولٌ لأجله؟', '[{"id":"a","text":"لأنّها ظرفُ زمان"},{"id":"b","text":"لأنّها حال"},{"id":"c","text":"لأنّها مصدرٌ من لفظ الفعل «صبرتُ» تؤكّدُه وتبيّنُ نوعَه، لا تبيّنُ سببًا"},{"id":"d","text":"لأنّها مرفوعة"}]'::jsonb, 'c', '«صبرًا» مصدرٌ من جنس الفعل «صبرتُ»، جاءت لتوكيده وبيان نوعه (بنعتها «جميلًا»)، فهي مفعولٌ مطلق. ولو بيّنت سببًا لكانت مفعولًا لأجله، لكنّها هنا مؤكّدةٌ للفعل.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

