INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ac7e33e0-8cc4-51c1-a7c2-86e0fa161fd3', 'e503f41c-7cde-51c2-95d1-7cbae079d9e6', 'الحال تجيبُ عن سؤال:', '[{"id":"a","text":"متى؟"},{"id":"b","text":"أين؟"},{"id":"c","text":"لماذا؟"},{"id":"d","text":"كيف (هيئة صاحبها)؟"}]'::jsonb, 'd', 'الحال وصفٌ منصوبٌ يبيّنُ هيئةَ صاحبه حين الفعل، فتجيبُ عن «كيف؟». أمّا «متى/أين» فللظرف و«لماذا» للمفعول لأجله.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e3fcba70-8d03-5883-b1a4-95ce0ddbacb9', 'e503f41c-7cde-51c2-95d1-7cbae079d9e6', 'المفعول المطلق هو:', '[{"id":"a","text":"اسمٌ يدلّ على المكان"},{"id":"b","text":"مصدرٌ من لفظ الفعل يؤكّدُه أو يبيّنُ نوعَه أو عدده"},{"id":"c","text":"وصفٌ يبيّنُ الهيئة"},{"id":"d","text":"اسمٌ يبيّنُ السبب"}]'::jsonb, 'b', 'المفعول المطلق مصدرٌ منصوبٌ من جنس الفعل، يُذكرُ لتأكيده (فرحًا) أو بيان نوعه (سيرَ الكرامِ) أو عدده (دقّتينِ).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5e9bb9b0-5aec-50f7-9bae-03a1b51edcd1', 'e503f41c-7cde-51c2-95d1-7cbae079d9e6', 'في جملة «سافرَ الطالبُ طلبًا للعلمِ»، «طلبًا» نوعُها:', '[{"id":"a","text":"مفعولٌ فيه"},{"id":"b","text":"حالٌ"},{"id":"c","text":"مفعولٌ لأجله (سبب السفر)"},{"id":"d","text":"مفعولٌ مطلق"}]'::jsonb, 'c', '«طلبًا» مصدرٌ يبيّنُ سببَ السفر (لماذا سافر؟ طلبًا للعلم)، فهو مفعولٌ لأجله منصوب.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('77db0ea1-19c1-5aeb-9a07-86f23c937161', 'e503f41c-7cde-51c2-95d1-7cbae079d9e6', 'في جملة «عادَ المسافرُ مسرورًا»، صاحبُ الحال «مسرورًا» هو:', '[{"id":"a","text":"المسافرُ (الفاعل)"},{"id":"b","text":"عادَ"},{"id":"c","text":"مسرورًا نفسُها"},{"id":"d","text":"لا صاحبَ لها"}]'::jsonb, 'a', 'الحالُ «مسرورًا» تبيّنُ هيئةَ مَن عاد، وهو الفاعل «المسافرُ». فصاحبُ الحال هو الفاعل «المسافرُ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c654ff72-0a0a-508d-bcc3-f39f23b58e59', 'e503f41c-7cde-51c2-95d1-7cbae079d9e6', 'ميّز نوعَ «يومَ» في «سأزورُكَ يومَ الجمعةِ».', '[{"id":"a","text":"حالٌ"},{"id":"b","text":"مفعولٌ به"},{"id":"c","text":"مفعولٌ لأجله"},{"id":"d","text":"مفعولٌ فيه (ظرف زمان) منصوب، و«الجمعةِ» مضافٌ إليه"}]'::jsonb, 'd', '«يومَ» ظرفُ زمانٍ يبيّنُ متى الزيارة (مفعول فيه منصوب)، و«الجمعةِ» مضافٌ إليه مجرور. فهو مفعولٌ فيه لا مفعولٌ به.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5e8ed69c-9ee4-5ec4-86b4-f7551235a0fa', 'e503f41c-7cde-51c2-95d1-7cbae079d9e6', 'في جملة «اعتذرَ الطالبُ خجلًا»، حدّد نوعَ «خجلًا» والفرقَ بينها وبين الحال.', '[{"id":"a","text":"حالٌ لأنّها تبيّنُ الهيئة"},{"id":"b","text":"مفعولٌ لأجله؛ تبيّنُ سببَ الاعتذار (لماذا؟ خجلًا)، لا هيئةَ الفاعل"},{"id":"c","text":"مفعولٌ فيه"},{"id":"d","text":"مفعولٌ مطلق"}]'::jsonb, 'b', '«خجلًا» مصدرٌ يبيّنُ سببَ الاعتذار، فهو مفعولٌ لأجله. ولو أردنا الهيئةَ لقلنا «اعتذرَ خجلانَ» (حال). الفرقُ: السببُ (لأجله) لا الهيئة (الحال).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('97a39205-40ac-57e6-aeb8-6d6317e35af7', '82efdbaa-46e7-5eed-968c-d4f3a9d355f3', 'arabic-5eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: سيّدُ المتمّمات', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('db26f4e9-9259-5dea-9c15-f80470316fb3', '97a39205-40ac-57e6-aeb8-6d6317e35af7', 'في جملة «وقفَ الجنودُ صفًّا واحدًا تحيّةً للعَلَمِ صباحًا»، أعرب «تحيّةً» و«صباحًا».', '[{"id":"a","text":"كلاهما حال"},{"id":"b","text":"كلاهما مفعولٌ مطلق"},{"id":"c","text":"«تحيّةً» مفعولٌ لأجله (سبب الوقوف)، و«صباحًا» مفعولٌ فيه (ظرف زمان)، وكلاهما منصوب"},{"id":"d","text":"كلاهما مفعولٌ به"}]'::jsonb, 'c', '«تحيّةً» تبيّنُ سببَ الوقوف (لماذا؟) فهي مفعولٌ لأجله. و«صباحًا» تبيّنُ زمانَه (متى؟) فهي مفعولٌ فيه. لكلٍّ وظيفةٌ مختلفة وإن اشتركا في النصب.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8e23d68c-ec9f-5bbd-9c0c-ba668a5755a7', '97a39205-40ac-57e6-aeb8-6d6317e35af7', 'في جملة «كافأَ المعلّمُ التلميذَ المجتهدَ تشجيعًا له»، حدّد الحالَ (إن وُجدت) والمفعولَ لأجله.', '[{"id":"a","text":"لا حالَ في الجملة؛ «تشجيعًا» مفعولٌ لأجله (سبب المكافأة)، و«المجتهدَ» نعتٌ للمفعول به"},{"id":"b","text":"«المجتهدَ» حالٌ و«تشجيعًا» ظرف"},{"id":"c","text":"«تشجيعًا» حالٌ"},{"id":"d","text":"لا مفعولَ لأجله"}]'::jsonb, 'a', '«المجتهدَ» نعتٌ للمفعول به «التلميذَ» يتبعُه في النصب (وصفٌ ثابتٌ لا هيئةٌ عارضة فليس حالًا). و«تشجيعًا» مصدرٌ يبيّنُ سببَ المكافأة فهو مفعولٌ لأجله. فلا حالَ هنا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4000e070-e178-5e34-929e-c51ae714c822', '97a39205-40ac-57e6-aeb8-6d6317e35af7', 'ميّز المتمّمات في «جرى المتسابقُ جريًا سريعًا حولَ الملعبِ رغبةً في الفوزِ».', '[{"id":"a","text":"«جريًا» ظرف، «حولَ» حال، «رغبةً» مفعولٌ به"},{"id":"b","text":"كلُّها مفعولٌ مطلق"},{"id":"c","text":"كلُّها مفعولٌ به"},{"id":"d","text":"«جريًا» مفعولٌ مطلق، «حولَ» مفعولٌ فيه (ظرف مكان)، «رغبةً» مفعولٌ لأجله"}]'::jsonb, 'd', '«جريًا» مصدرٌ من لفظ الفعل (مفعول مطلق)، «حولَ» ظرفُ مكان (مفعول فيه)، «رغبةً» سببُ الجري (مفعول لأجله). ثلاثُ متمّماتٍ منصوبةٍ مختلفةُ الوظيفة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('372301d3-ed17-5e04-91b4-7ffed24dc2b8', '97a39205-40ac-57e6-aeb8-6d6317e35af7', 'في جملة «طلعت الشمسُ صافيةً سماؤُها»، ما إعرابُ «صافيةً»؟', '[{"id":"a","text":"مفعولٌ مطلق"},{"id":"b","text":"حالٌ منصوبة (تبيّنُ هيئةَ الشمس عند الطلوع)"},{"id":"c","text":"مفعولٌ به"},{"id":"d","text":"ظرفٌ"}]'::jsonb, 'b', '«صافيةً» تبيّنُ هيئةَ الشمس حين الطلوع (كيف طلعت؟ صافيةً) فهي حالٌ منصوبة، وصاحبُها الفاعل «الشمسُ»، و«سماؤُها» فاعلٌ للحال (الحال السببيّة).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cf6f63fd-1d5f-544a-b78d-bc48fdca40ee', '97a39205-40ac-57e6-aeb8-6d6317e35af7', 'في جملة «دقَّ العاملُ المسمارَ دقّاتٍ قويّةً إتقانًا للعملِ»، أعرب «دقّاتٍ» و«إتقانًا».', '[{"id":"a","text":"كلاهما ظرف"},{"id":"b","text":"«دقّاتٍ» مفعولٌ به ثانٍ و«إتقانًا» حال"},{"id":"c","text":"«دقّاتٍ» مفعولٌ مطلق (يبيّنُ العدد، منصوبٌ بالكسرة جمعَ مؤنّثٍ سالم)، و«إتقانًا» مفعولٌ لأجله"},{"id":"d","text":"كلاهما فاعل"}]'::jsonb, 'c', '«دقّاتٍ» مصدرٌ يبيّنُ عددَ الدقّ (مفعول مطلق)، وهو جمعُ مؤنّثٍ سالم يُنصبُ بالكسرة. و«إتقانًا» يبيّنُ سببَ الدقّ (مفعول لأجله). لكلٍّ وظيفةٌ منصوبة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('70827a0d-0d84-5e64-b4d3-0e4645971ca3', '97a39205-40ac-57e6-aeb8-6d6317e35af7', 'أيُّ جملةٍ تحوي مفعولًا فيه ومفعولًا مطلقًا وحالًا معًا؟', '[{"id":"a","text":"غرّدَ البلبلُ صباحًا تغريدًا عذبًا فرِحًا"},{"id":"b","text":"قرأَ الطالبُ الكتابَ"},{"id":"c","text":"ذهبَ الرجلُ إلى السوقِ"},{"id":"d","text":"البحرُ واسعٌ"}]'::jsonb, 'a', 'في (أ): «صباحًا» مفعولٌ فيه (ظرف زمان)، «تغريدًا» مفعولٌ مطلق (مصدرٌ من لفظ الفعل)، «فرِحًا» حالٌ (هيئة البلبل). فاجتمعت الثلاثةُ. الباقي يخلو من بعضها أو كلِّها.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('8eff0309-9ee7-5ab4-ac02-645b5e37655f', '82efdbaa-46e7-5eed-968c-d4f3a9d355f3', 'arabic-5eme', '🛡️ تدريب ⭐⭐⭐: المفاعيل والحال (مراجعة شاملة)', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6cf064ba-9589-5434-821a-f8e501c89210', '8eff0309-9ee7-5ab4-ac02-645b5e37655f', 'المفعول فيه يتضمّنُ معنى:', '[{"id":"a","text":"اللام"},{"id":"b","text":"في (الظرفيّة)"},{"id":"c","text":"من"},{"id":"d","text":"عن"}]'::jsonb, 'b', 'المفعول فيه ظرفٌ يتضمّنُ معنى «في» الدالّة على الزمان أو المكان: «جلسَ تحتَ» = جلسَ في تحتٍ، «سافرَ ليلًا» = في ليلٍ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6d9d7a8b-139e-5ab3-b41e-ff0a8563e942', '8eff0309-9ee7-5ab4-ac02-645b5e37655f', 'في جملة «رجعَ الأطفالُ ضاحكينَ»، نوعُ «ضاحكينَ»:', '[{"id":"a","text":"مفعولٌ فيه"},{"id":"b","text":"مفعولٌ مطلق"},{"id":"c","text":"مفعولٌ لأجله"},{"id":"d","text":"حالٌ منصوبة بالياء (جمعُ مذكّرٍ سالم)"}]'::jsonb, 'd', '«ضاحكينَ» تبيّنُ هيئةَ الأطفال حين الرجوع (كيف رجعوا؟) فهي حال، وهي جمعُ مذكّرٍ سالم منصوبٌ بالياء.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2a4adc94-a058-56f7-a4ed-9c517be31e10', '8eff0309-9ee7-5ab4-ac02-645b5e37655f', 'في جملة «انتصرَ الجيشُ انتصارًا عظيمًا»، «انتصارًا» نوعُها:', '[{"id":"a","text":"مفعولٌ مطلق (مصدرٌ من لفظ الفعل يؤكّدُه)"},{"id":"b","text":"حالٌ"},{"id":"c","text":"مفعولٌ فيه"},{"id":"d","text":"مفعولٌ لأجله"}]'::jsonb, 'a', '«انتصارًا» مصدرٌ من لفظ الفعل «انتصرَ»، جاءت لتوكيده وبيان نوعه (بنعتها «عظيمًا»)، فهي مفعولٌ مطلق منصوب.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b5a04b96-0771-5009-97fc-01ea042306c1', '8eff0309-9ee7-5ab4-ac02-645b5e37655f', 'في جملة «بكى الطفلُ خوفًا من الظلامِ»، «خوفًا» نوعُها:', '[{"id":"a","text":"ظرفُ زمان"},{"id":"b","text":"حالٌ"},{"id":"c","text":"مفعولٌ لأجله (سبب البكاء)"},{"id":"d","text":"مفعولٌ مطلق"}]'::jsonb, 'c', '«خوفًا» مصدرٌ يبيّنُ سببَ البكاء (لماذا بكى؟ خوفًا)، فهو مفعولٌ لأجله منصوب. وليس مصدرًا من لفظ الفعل «بكى» فلا يكون مفعولًا مطلقًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ff487248-27d8-566c-a992-0ffb0b096b12', '8eff0309-9ee7-5ab4-ac02-645b5e37655f', 'في جملة «سارَ الجنديُّ ميلًا أمامَ القائدِ مطمئنًّا»، أعرب الكلمات الثلاث: «ميلًا»، «أمامَ»، «مطمئنًّا».', '[{"id":"a","text":"«ميلًا» مفعولٌ به، «أمامَ» حال، «مطمئنًّا» ظرف"},{"id":"b","text":"«ميلًا» مفعولٌ فيه (ظرف مكان مقدارٌ للمسافة)، «أمامَ» مفعولٌ فيه (ظرف مكان)، «مطمئنًّا» حال"},{"id":"c","text":"كلُّها حال"},{"id":"d","text":"كلُّها مفعولٌ مطلق"}]'::jsonb, 'b', '«ميلًا» ظرفُ مكانٍ يبيّنُ مقدارَ المسافة المقطوعة (مفعول فيه)، «أمامَ» ظرفُ مكان (مفعول فيه)، «مطمئنًّا» يبيّنُ هيئةَ الجنديّ (حال). ثلاثُ منصوباتٍ مختلفةِ الوظيفة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('95abfc41-a009-5c0d-bf70-7433610fef16', '8eff0309-9ee7-5ab4-ac02-645b5e37655f', 'ميّز الفرقَ: في «نامَ الطفلُ نومًا هادئًا» و«نامَ الطفلُ هادئًا»، ما نوعُ «نومًا» و«هادئًا»؟', '[{"id":"a","text":"كلاهما حال"},{"id":"b","text":"كلاهما مفعولٌ مطلق"},{"id":"c","text":"كلاهما مفعولٌ لأجله"},{"id":"d","text":"«نومًا» مفعولٌ مطلق (مصدرٌ من لفظ الفعل)، و«هادئًا» حالٌ (تبيّنُ هيئةَ الطفل)"}]'::jsonb, 'd', '«نومًا» مصدرٌ من لفظ الفعل «نامَ» يؤكّدُه فهو مفعولٌ مطلق. أمّا «هادئًا» فوصفٌ يبيّنُ هيئةَ الطفل حين النوم فهو حال. الفرقُ: المصدرُ المؤكّد (مطلق) مقابل الوصف المبيّن للهيئة (حال).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('d7a14657-4d86-5194-ab0e-6ed4a93e3970', '1f55b2e3-8e5b-5718-9153-a8a2c8e081ff', 'arabic-5eme', 'اختبار فهم الدرس ⭐ (فهم)', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bdb02689-34a0-5336-9e5c-984a9a6f11ea', 'd7a14657-4d86-5194-ab0e-6ed4a93e3970', 'كان وأخواتها تعملُ في الجملة الاسميّة فـ:', '[{"id":"a","text":"تنصبُ الاسمَ وترفعُ الخبر"},{"id":"b","text":"ترفعُهما معًا"},{"id":"c","text":"ترفعُ المبتدأ اسمًا لها وتنصبُ الخبر"},{"id":"d","text":"تنصبُهما معًا"}]'::jsonb, 'c', 'كان وأخواتها ترفعُ المبتدأ اسمًا لها، وتنصبُ الخبر خبرًا لها، مثل «كانتِ السماءُ صافيةً» (السماءُ مرفوع، صافيةً منصوب).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f83237e7-49f9-5a4d-beca-39c2672b0ce9', 'd7a14657-4d86-5194-ab0e-6ed4a93e3970', 'في جملة «إنّ العلمَ نورٌ»، ما إعرابُ «العلمَ»؟', '[{"id":"a","text":"خبرُ إنّ مرفوع"},{"id":"b","text":"اسمُ إنّ منصوب"},{"id":"c","text":"فاعلٌ"},{"id":"d","text":"مفعولٌ به"}]'::jsonb, 'b', 'إنّ تنصبُ المبتدأ اسمًا لها، فـ«العلمَ» اسمُ إنّ منصوبٌ بالفتحة، و«نورٌ» خبرُها مرفوع.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3414edb5-1e4e-5298-bbfe-d82ef8cbf25b', 'd7a14657-4d86-5194-ab0e-6ed4a93e3970', 'أيُّ هذه الكلمات من أخوات «كان»؟', '[{"id":"a","text":"أصبحَ"},{"id":"b","text":"لعلّ"},{"id":"c","text":"كأنّ"},{"id":"d","text":"ليتَ"}]'::jsonb, 'a', '«أصبحَ» فعلٌ ناقصٌ من أخوات كان (ترفعُ الاسمَ وتنصبُ الخبر). أمّا لعلّ وكأنّ وليتَ فمن أخوات إنّ (حروف).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2df2086e-a436-5eb6-8c28-581fa34eedf4', 'd7a14657-4d86-5194-ab0e-6ed4a93e3970', 'في جملة «أصبحَ الجوُّ باردًا»، ما إعرابُ «باردًا»؟', '[{"id":"a","text":"اسمُ أصبحَ مرفوع"},{"id":"b","text":"فاعلٌ"},{"id":"c","text":"مبتدأٌ"},{"id":"d","text":"خبرُ أصبحَ منصوب"}]'::jsonb, 'd', '«أصبحَ» من أخوات كان؛ ترفعُ «الجوُّ» اسمًا لها وتنصبُ «باردًا» خبرًا لها. فـ«باردًا» خبرُ أصبحَ منصوبٌ بالفتحة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fa934f57-3d21-522f-a807-6bf061ab52c2', 'd7a14657-4d86-5194-ab0e-6ed4a93e3970', 'ما الفرقُ بين عمل «كان» وعمل «إنّ»؟', '[{"id":"a","text":"لا فرقَ بينهما"},{"id":"b","text":"كلتاهما تنصبان الاسمَ"},{"id":"c","text":"كان ترفعُ الاسمَ وتنصبُ الخبر، وإنّ تنصبُ الاسمَ وترفعُ الخبر (عكسُها)"},{"id":"d","text":"كلتاهما ترفعان الخبر"}]'::jsonb, 'c', 'كان (فعل) ترفعُ الاسمَ وتنصبُ الخبر، وإنّ (حرف) تنصبُ الاسمَ وترفعُ الخبر. فعملُهما متعاكسٌ في الاسم والخبر.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('9caa2003-fb8e-57af-a640-c16313be832b', '1f55b2e3-8e5b-5718-9153-a8a2c8e081ff', 'arabic-5eme', '⭐ تمرين: النواسخ تدخل (سهل)', 1, 50, 10, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
