  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fdca7bbb-c61c-58a0-941d-b989a184b985', '9caa2003-fb8e-57af-a640-c16313be832b', 'في جملة «كان الطقسُ جميلًا»، ما اسمُ كان؟', '[{"id":"a","text":"الطقسُ"},{"id":"b","text":"جميلًا"},{"id":"c","text":"كان"},{"id":"d","text":"لا اسم لها"}]'::jsonb, 'a', 'كان ترفعُ المبتدأ اسمًا لها، فـ«الطقسُ» اسمُ كان مرفوعٌ بالضمّة، و«جميلًا» خبرُها منصوب.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('82989c30-fec0-5e85-a3f6-69496406d001', '9caa2003-fb8e-57af-a640-c16313be832b', 'في جملة «إنّ الصدقَ منجاةٌ»، ما خبرُ إنّ؟', '[{"id":"a","text":"الصدقَ"},{"id":"b","text":"إنّ"},{"id":"c","text":"منجاةٌ"},{"id":"d","text":"لا خبر لها"}]'::jsonb, 'c', 'إنّ ترفعُ الخبر، فـ«منجاةٌ» خبرُ إنّ مرفوعٌ بالضمّة، و«الصدقَ» اسمُها منصوب.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9c5a1584-573f-5930-8695-1bf30e600f41', '9caa2003-fb8e-57af-a640-c16313be832b', 'أيُّ كلمةٍ من أخوات «إنّ»؟', '[{"id":"a","text":"صارَ"},{"id":"b","text":"لكنّ"},{"id":"c","text":"باتَ"},{"id":"d","text":"ظلَّ"}]'::jsonb, 'b', '«لكنّ» حرفٌ ناسخٌ من أخوات إنّ (للاستدراك). أمّا صارَ وباتَ وظلَّ فأفعالٌ من أخوات كان.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('abfc3b25-602f-5ac6-baa1-646655b33e46', '9caa2003-fb8e-57af-a640-c16313be832b', 'في جملة «صارَ الحديدُ سيفًا»، ما إعرابُ «سيفًا»؟', '[{"id":"a","text":"اسمُ صارَ مرفوع"},{"id":"b","text":"فاعلٌ"},{"id":"c","text":"مبتدأٌ"},{"id":"d","text":"خبرُ صارَ منصوب"}]'::jsonb, 'd', '«صارَ» من أخوات كان؛ ترفعُ «الحديدُ» اسمًا لها وتنصبُ «سيفًا» خبرًا لها. فـ«سيفًا» خبرُ صارَ منصوب.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5225f0b6-1e0c-5aca-987d-2db0b66605a8', '9caa2003-fb8e-57af-a640-c16313be832b', 'حوّل «المطرُ غزيرٌ» بإدخال «كان».', '[{"id":"a","text":"كان المطرُ غزيرًا"},{"id":"b","text":"كان المطرَ غزيرٌ"},{"id":"c","text":"كان المطرُ غزيرٌ"},{"id":"d","text":"كان المطرَ غزيرًا"}]'::jsonb, 'a', 'كان ترفعُ الاسمَ وتنصبُ الخبر: «المطرُ» يبقى مرفوعًا اسمًا لها، و«غزيرٌ» يُنصبُ خبرًا لها «غزيرًا». فالصواب «كان المطرُ غزيرًا».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9d254d50-d6c5-5b0d-89a8-635ad30f3338', '9caa2003-fb8e-57af-a640-c16313be832b', 'حوّل «القمرُ منيرٌ» بإدخال «إنّ».', '[{"id":"a","text":"إنّ القمرُ منيرٌ"},{"id":"b","text":"إنّ القمرَ منيرًا"},{"id":"c","text":"إنّ القمرَ منيرٌ"},{"id":"d","text":"إنّ القمرُ منيرًا"}]'::jsonb, 'c', 'إنّ تنصبُ الاسمَ وترفعُ الخبر: «القمرَ» يُنصبُ اسمًا لها، و«منيرٌ» يبقى مرفوعًا خبرًا لها. فالصواب «إنّ القمرَ منيرٌ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('e119f82f-3f60-5c02-a55d-0e5221e6cad2', '1f55b2e3-8e5b-5718-9153-a8a2c8e081ff', 'arabic-5eme', '⚔️ زعيم الفصل ⭐⭐⭐: حارسُ النواسخ (صعب)', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d3e203c0-a949-5be1-b056-47030da12b91', 'e119f82f-3f60-5c02-a55d-0e5221e6cad2', 'لماذا سُمّيت «كان وأخواتها» أفعالًا ناقصة؟', '[{"id":"a","text":"لأنّها لا تأخذ فاعلًا"},{"id":"b","text":"لأنّها لا تكتفي بالاسم المرفوع، بل تحتاج خبرًا منصوبًا يتمُّ به المعنى"},{"id":"c","text":"لأنّها قصيرةٌ في الكتابة"},{"id":"d","text":"لأنّها حروف"}]'::jsonb, 'b', 'سُمّيت ناقصةً لأنّها لا تكتفي بمرفوعها (اسمها) كالأفعال التامّة، بل تطلبُ خبرًا منصوبًا يتمُّ به المعنى: «كان الجوُّ ...» ناقصةٌ حتّى نقول «باردًا».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5c5c6602-7c94-585a-89a5-18239a3eb9f1', 'e119f82f-3f60-5c02-a55d-0e5221e6cad2', 'في جملة «ليتَ الشبابَ عائدٌ»، أعرب «الشبابَ» و«عائدٌ».', '[{"id":"a","text":"«الشبابَ» فاعلٌ و«عائدٌ» مفعول"},{"id":"b","text":"كلاهما مرفوع"},{"id":"c","text":"«الشبابَ» مرفوع و«عائدٌ» منصوب"},{"id":"d","text":"«الشبابَ» اسمُ ليتَ منصوب، و«عائدٌ» خبرُ ليتَ مرفوع"}]'::jsonb, 'd', '«ليتَ» من أخوات إنّ (للتمنّي)؛ تنصبُ الاسمَ «الشبابَ» وترفعُ الخبر «عائدٌ». فالاسمُ منصوبٌ والخبرُ مرفوع.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1088d9f4-debd-52e7-adc0-3b09c753ac4f', 'e119f82f-3f60-5c02-a55d-0e5221e6cad2', 'في جملة «ما زالَ التلميذُ مجتهدًا»، ما إعرابُ «مجتهدًا»؟', '[{"id":"a","text":"خبرُ ما زالَ منصوب (ما زالَ من أخوات كان)"},{"id":"b","text":"اسمُ ما زالَ مرفوع"},{"id":"c","text":"مفعولٌ به"},{"id":"d","text":"حالٌ"}]'::jsonb, 'a', '«ما زالَ» من أخوات كان (تدلّ على الاستمرار)؛ ترفعُ «التلميذُ» اسمًا لها وتنصبُ «مجتهدًا» خبرًا لها. فهو خبرُ ما زالَ منصوب.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ea74959d-b03f-5f33-9dd7-24e18f023e53', 'e119f82f-3f60-5c02-a55d-0e5221e6cad2', 'ما الخطأُ في «إنّ المؤمنونَ إخوةٌ»؟', '[{"id":"a","text":"لا خطأَ فيه"},{"id":"b","text":"يجبُ رفعُ «إخوةٌ» فقط"},{"id":"c","text":"اسمُ إنّ «المؤمنونَ» يجبُ نصبُه بالياء: «إنّ المؤمنينَ إخوةٌ»"},{"id":"d","text":"يجبُ حذفُ إنّ"}]'::jsonb, 'c', 'إنّ تنصبُ اسمَها؛ و«المؤمنينَ» جمعُ مذكّرٍ سالم يُنصبُ بالياء. فالصواب «إنّ المؤمنينَ إخوةٌ» لا «المؤمنونَ». والخبرُ «إخوةٌ» مرفوعٌ صحيح.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5ba15254-f9e0-547b-97b1-bcd6b5eca453', 'e119f82f-3f60-5c02-a55d-0e5221e6cad2', 'في جملة «كأنّ القمرَ مصباحٌ معلّقٌ»، حدّد اسمَ كأنّ وخبرَها.', '[{"id":"a","text":"اسمُها «مصباحٌ» وخبرُها «القمرَ»"},{"id":"b","text":"اسمُها «القمرَ» منصوب، وخبرُها «مصباحٌ» مرفوع (ونعتُه «معلّقٌ»)"},{"id":"c","text":"كلاهما منصوب"},{"id":"d","text":"لا اسم ولا خبر"}]'::jsonb, 'b', '«كأنّ» من أخوات إنّ (للتشبيه)؛ تنصبُ الاسمَ «القمرَ» وترفعُ الخبر «مصباحٌ». ونعتُ الخبر «معلّقٌ» مرفوعٌ تبعًا له.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a6a8f0b7-ca06-51cf-83ed-3afed8cb889f', 'e119f82f-3f60-5c02-a55d-0e5221e6cad2', 'أعرب: «لعلّ النجاحَ قريبٌ».', '[{"id":"a","text":"«النجاحَ» مبتدأٌ و«قريبٌ» خبر"},{"id":"b","text":"«النجاحَ» فاعلٌ"},{"id":"c","text":"«النجاحَ» مفعولٌ به"},{"id":"d","text":"«النجاحَ» اسمُ لعلّ منصوب، و«قريبٌ» خبرُ لعلّ مرفوع"}]'::jsonb, 'd', '«لعلّ» من أخوات إنّ (للترجّي)؛ تنصبُ الاسمَ «النجاحَ» وترفعُ الخبر «قريبٌ». فالاسمُ منصوبٌ والخبرُ مرفوع، لا مبتدأٌ ولا فاعلٌ ولا مفعول.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

