INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0a3457e3-03b3-5e0b-bcbc-19767727beb7', '97bb6b3b-a613-5cce-9493-b150ad0095cc', 'إنّ وأخواتها:', '[{"id":"a","text":"ترفعُ الاسمَ وتنصبُ الخبر"},{"id":"b","text":"ترفعُهما معًا"},{"id":"c","text":"تنصبُ الاسمَ وترفعُ الخبر"},{"id":"d","text":"تنصبُهما معًا"}]'::jsonb, 'c', 'إنّ وأخواتها حروفٌ ناسخةٌ تنصبُ المبتدأ اسمًا لها وترفعُ الخبر خبرًا لها، مثل «إنّ العلمَ نورٌ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4d8427dd-1e1f-5ad5-94a6-db5df9278d10', '97bb6b3b-a613-5cce-9493-b150ad0095cc', '«ليسَ» من أخوات:', '[{"id":"a","text":"كان (فعلٌ ناسخٌ يفيد النفي)"},{"id":"b","text":"إنّ"},{"id":"c","text":"الحروف الناصبة للفعل"},{"id":"d","text":"حروف الجرّ"}]'::jsonb, 'a', '«ليسَ» فعلٌ ناقصٌ من أخوات كان يفيد النفي؛ يرفعُ الاسمَ وينصبُ الخبر، مثل «ليسَ الجوُّ حارًّا».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d1db02c2-b8ab-543b-8604-1b29c47f075c', '97bb6b3b-a613-5cce-9493-b150ad0095cc', 'في جملة «باتَ الحارسُ يقظًا»، ما إعرابُ «الحارسُ»؟', '[{"id":"a","text":"خبرُ باتَ"},{"id":"b","text":"مفعولٌ به"},{"id":"c","text":"مبتدأٌ"},{"id":"d","text":"اسمُ باتَ مرفوع"}]'::jsonb, 'd', '«باتَ» من أخوات كان؛ ترفعُ «الحارسُ» اسمًا لها وتنصبُ «يقظًا» خبرًا لها. فـ«الحارسُ» اسمُ باتَ مرفوع.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3d6434dc-fc61-506e-b9fb-1070260c633d', '97bb6b3b-a613-5cce-9493-b150ad0095cc', 'حوّل «الحديقةُ واسعةٌ» بإدخال «أصبحَ» مرّةً و«إنّ» مرّةً.', '[{"id":"a","text":"أصبحتِ الحديقةَ واسعةٌ / إنّ الحديقةُ واسعةً"},{"id":"b","text":"أصبحتِ الحديقةُ واسعةً / إنّ الحديقةَ واسعةٌ"},{"id":"c","text":"أصبحتِ الحديقةُ واسعةٌ / إنّ الحديقةَ واسعةً"},{"id":"d","text":"أصبحتِ الحديقةَ واسعةً / إنّ الحديقةُ واسعةٌ"}]'::jsonb, 'b', 'أصبحَ (كأخوات كان) ترفعُ الاسمَ وتنصبُ الخبر: «الحديقةُ واسعةً». وإنّ تنصبُ الاسمَ وترفعُ الخبر: «الحديقةَ واسعةٌ». فهما متعاكستان في العمل.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4c5ab7c2-01ca-5b68-a9fd-d2bb1fd075ef', '97bb6b3b-a613-5cce-9493-b150ad0095cc', 'في جملة «إنّ في الحديقةِ أزهارًا»، ما إعرابُ «أزهارًا»؟', '[{"id":"a","text":"خبرُ إنّ المتقدّم"},{"id":"b","text":"فاعلٌ"},{"id":"c","text":"مبتدأٌ"},{"id":"d","text":"اسمُ إنّ المؤخّر منصوب (والخبرُ شبهُ الجملة «في الحديقةِ» متقدّم)"}]'::jsonb, 'd', 'تقدّم خبرُ إنّ شبهُ الجملة «في الحديقةِ»، وتأخّر اسمُها «أزهارًا» منصوبًا. فهو اسمُ إنّ المؤخّر المنصوب، والخبرُ هو شبهُ الجملة المتقدّم.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('94256fc7-9bc3-5f1a-9eac-1ff9bd4e2521', '97bb6b3b-a613-5cce-9493-b150ad0095cc', 'ما الخطأُ في «ما زالَ المسافرونَ متعبينَ» إن قيل «المسافرينَ»؟', '[{"id":"a","text":"الصواب «المسافرونَ» بالواو لأنّه اسمُ ما زالَ المرفوع (لا «المسافرينَ»)"},{"id":"b","text":"الصواب نصبُ «المسافرينَ» لأنّه اسمُها"},{"id":"c","text":"يجبُ رفعُ «متعبينَ»"},{"id":"d","text":"لا فرقَ بين الصيغتين"}]'::jsonb, 'a', '«ما زالَ» من أخوات كان ترفعُ الاسمَ؛ فاسمُها «المسافرونَ» مرفوعٌ بالواو (جمعُ مذكّرٍ سالم). أمّا «متعبينَ» فخبرُها منصوبٌ بالياء. فلا يصحّ نصبُ الاسم «المسافرينَ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('13d36580-2e07-5217-84de-9d65ac9d7b6f', '1f55b2e3-8e5b-5718-9153-a8a2c8e081ff', 'arabic-5eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: سيّدُ النواسخ', 4, 300, 60, 'challenge', 'admin', 4)
