INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9b5691dd-7a91-5b4e-9b29-5299f33f53ab', '13d36580-2e07-5217-84de-9d65ac9d7b6f', 'في جملة «كان المعلّمونَ مخلصينَ»، أعرب «المعلّمونَ» و«مخلصينَ».', '[{"id":"a","text":"كلاهما مرفوع بالواو"},{"id":"b","text":"«المعلّمونَ» اسمُ كان مرفوع بالواو، و«مخلصينَ» خبرُ كان منصوب بالياء"},{"id":"c","text":"«المعلّمونَ» خبرٌ و«مخلصينَ» اسم"},{"id":"d","text":"كلاهما منصوب بالياء"}]'::jsonb, 'b', 'كان ترفعُ الاسمَ وتنصبُ الخبر. «المعلّمونَ» اسمُها مرفوعٌ بالواو (جمعُ مذكّرٍ سالم)، و«مخلصينَ» خبرُها منصوبٌ بالياء. فلكلٍّ علامتُه الفرعيّة المختلفة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5ad3ed09-1767-5f3c-955a-98a96839ebea', '13d36580-2e07-5217-84de-9d65ac9d7b6f', 'ادخل «إنّ» على «الطلابُ المجتهدونَ ناجحونَ» وأعرب الناتج.', '[{"id":"a","text":"إنّ الطلابُ المجتهدونَ ناجحونَ"},{"id":"b","text":"إنّ الطلابَ المجتهدينَ ناجحينَ"},{"id":"c","text":"إنّ الطلابُ المجتهدينَ ناجحونَ"},{"id":"d","text":"إنّ الطلابَ المجتهدينَ ناجحونَ"}]'::jsonb, 'd', 'إنّ تنصبُ الاسمَ «الطلابَ» (بالفتحة، مفردُه جمعُ تكسير) ونعتُه «المجتهدينَ» منصوبٌ بالياء تبعًا له، وترفعُ الخبر «ناجحونَ» بالواو. فالصواب «إنّ الطلابَ المجتهدينَ ناجحونَ».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f8543f95-58c3-5307-b3e6-96d2d8cc0929', '13d36580-2e07-5217-84de-9d65ac9d7b6f', 'في جملة «أصبحَ العاملُ نشيطًا عملُه»، ما إعرابُ «نشيطًا» و«عملُه»؟', '[{"id":"a","text":"«نشيطًا» خبرُ أصبحَ منصوب، و«عملُه» فاعلٌ للصفة المشبّهة «نشيطًا» مرفوع"},{"id":"b","text":"«نشيطًا» اسمُ أصبحَ و«عملُه» خبرُها"},{"id":"c","text":"كلاهما منصوب"},{"id":"d","text":"كلاهما خبر"}]'::jsonb, 'a', '«العاملُ» اسمُ أصبحَ مرفوع، و«نشيطًا» خبرُها منصوب، و«عملُه» فاعلٌ سدَّ مسدَّ الخبر للصفة المشبّهة «نشيطًا» مرفوعٌ بالضمّة. فلكلٍّ موقعُه الدقيق.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c1792964-c70a-5222-b76a-005801f9ccef', '13d36580-2e07-5217-84de-9d65ac9d7b6f', 'ميّز الناسخَ ونوعَ عمله في: «لكنّ الجوَّ ماطرٌ» و«ظلَّ الجوُّ ماطرًا».', '[{"id":"a","text":"كلاهما يرفع الاسم وينصب الخبر"},{"id":"b","text":"كلاهما ينصب الاسم ويرفع الخبر"},{"id":"c","text":"«لكنّ» حرفٌ (نصبت الاسمَ «الجوَّ» ورفعت الخبرَ «ماطرٌ»)، و«ظلَّ» فعلٌ (رفع الاسمَ «الجوُّ» ونصب الخبرَ «ماطرًا»)"},{"id":"d","text":"كلاهما حرف"}]'::jsonb, 'c', '«لكنّ» من أخوات إنّ (حرف): نصبت الاسمَ «الجوَّ» ورفعت الخبر «ماطرٌ». و«ظلَّ» من أخوات كان (فعل): رفع الاسمَ «الجوُّ» ونصب الخبر «ماطرًا». فعملُهما متعاكس.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6b305d11-5aa0-5dee-baf7-d14567b113c2', '13d36580-2e07-5217-84de-9d65ac9d7b6f', 'في جملة «إنّ اللهَ غفورٌ رحيمٌ»، ما إعرابُ «رحيمٌ»؟', '[{"id":"a","text":"اسمُ إنّ ثانٍ منصوب"},{"id":"b","text":"نعتٌ منصوب"},{"id":"c","text":"مفعولٌ به"},{"id":"d","text":"خبرٌ ثانٍ لإنّ مرفوع (تعدّد الخبر)"}]'::jsonb, 'd', '«اللهَ» اسمُ إنّ منصوب، و«غفورٌ» خبرُها الأوّل مرفوع، و«رحيمٌ» خبرُها الثاني مرفوع (يجوز تعدّدُ خبر إنّ). فكلا الخبرين مرفوع.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('902d5190-150f-5e78-b2f5-1c21b8c3dbea', '13d36580-2e07-5217-84de-9d65ac9d7b6f', 'حوّل «كان الأطفالُ نائمينَ» إلى جملةٍ بإنّ مع المحافظة على المعنى الاسميّ.', '[{"id":"a","text":"إنّ الأطفالُ نائمونَ"},{"id":"b","text":"إنّ الأطفالَ نائمونَ"},{"id":"c","text":"إنّ الأطفالُ نائمينَ"},{"id":"d","text":"إنّ الأطفالَ نائمينَ"}]'::jsonb, 'b', 'بحذف «كان» نعودُ للجملة الاسميّة ثمّ ندخلُ «إنّ»: تنصبُ الاسمَ «الأطفالَ» (بالفتحة جمعَ تكسير) وترفعُ الخبر «نائمونَ» بالواو. فالصواب «إنّ الأطفالَ نائمونَ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

