INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('033dc9fe-582c-5d2e-bcec-7d0ef4d5284f', 'feab89af-a823-50b4-9e5d-a6074d439726', 'خبرُ «إنّ» يكون:', '[{"id":"a","text":"منصوبًا"},{"id":"b","text":"مرفوعًا"},{"id":"c","text":"مجرورًا"},{"id":"d","text":"مجزومًا"}]'::jsonb, 'b', 'إنّ وأخواتها تنصبُ الاسمَ وترفعُ الخبر، فخبرُها مرفوع. مثل «إنّ الصبرَ مفتاحُ الفرجِ» (مفتاحُ خبرٌ مرفوع).', 2)
