INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e6e0f101-af33-5d96-98bc-3c2a6eda3599', 'feab89af-a823-50b4-9e5d-a6074d439726', 'في جملة «ليسَ الكسلانُ محبوبًا»، ما إعرابُ «محبوبًا»؟', '[{"id":"a","text":"خبرُ ليسَ منصوب (ليسَ من أخوات كان)"},{"id":"b","text":"اسمُ ليسَ مرفوع"},{"id":"c","text":"مفعولٌ به"},{"id":"d","text":"حالٌ"}]'::jsonb, 'a', '«ليسَ» من أخوات كان؛ ترفعُ «الكسلانُ» اسمًا لها وتنصبُ «محبوبًا» خبرًا لها. فهو خبرُ ليسَ منصوب.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9a653e1b-284b-5b6c-afcf-217cd4a8cc40', 'feab89af-a823-50b4-9e5d-a6074d439726', 'في جملة «إنّ الحقَّ منتصرٌ»، لو أردنا توكيدَ الجملة بـ«اللام المزحلقة» على الخبر، نقول:', '[{"id":"a","text":"إنّ الحقُّ لمنتصرٌ"},{"id":"b","text":"إنّ الحقَّ لمنتصرًا"},{"id":"c","text":"إنّ الحقَّ لمنتصرٌ"},{"id":"d","text":"إنّ الحقُّ منتصرًا"}]'::jsonb, 'c', 'تبقى «الحقَّ» اسمَ إنّ منصوبًا، و«منتصرٌ» خبرَها مرفوعًا، وتدخلُ اللامُ المزحلقةُ على الخبر للتوكيد: «لمنتصرٌ». فالصواب «إنّ الحقَّ لمنتصرٌ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f04e28f8-2a60-596d-bd46-e91b3d507d15', 'feab89af-a823-50b4-9e5d-a6074d439726', 'في جملة «ما دامَ الطالبُ مواظبًا فالنجاحُ حليفُه»، ما عملُ «ما دامَ» في «الطالبُ» و«مواظبًا»؟', '[{"id":"a","text":"نصبتْ «الطالبُ» ورفعتْ «مواظبًا»"},{"id":"b","text":"رفعتْهما معًا"},{"id":"c","text":"حرفُ جرٍّ لا عمل لها"},{"id":"d","text":"رفعتْ «الطالبُ» اسمًا لها ونصبتْ «مواظبًا» خبرًا لها (ما دامَ من أخوات كان)"}]'::jsonb, 'd', '«ما دامَ» من أخوات كان (تفيد الظرفيّة الزمنيّة)؛ رفعت «الطالبُ» اسمًا لها ونصبت «مواظبًا» خبرًا لها، كعمل كان تمامًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0d9292e7-5442-572f-99e3-1b2795c98816', 'feab89af-a823-50b4-9e5d-a6074d439726', 'ميّز الصوابَ في «كأنّ البحرَ مرآةٌ صافيةٌ صفاؤُها».', '[{"id":"a","text":"«البحرَ» خبرُ كأنّ و«مرآةٌ» اسمُها"},{"id":"b","text":"«البحرَ» اسمُ كأنّ منصوب، و«مرآةٌ» خبرُها مرفوع، و«صافيةٌ» نعتٌ للخبر مرفوع"},{"id":"c","text":"كلُّها منصوبة"},{"id":"d","text":"«كأنّ» فعلٌ يرفع الاسم وينصب الخبر"}]'::jsonb, 'b', '«كأنّ» حرفٌ من أخوات إنّ؛ تنصبُ الاسمَ «البحرَ» وترفعُ الخبر «مرآةٌ»، و«صافيةٌ» نعتٌ للخبر مرفوعٌ تبعًا له، و«صفاؤُها» فاعلٌ للصفة. فالاسمُ منصوبٌ والخبرُ مرفوع.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

