INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('88cec90f-62e2-5351-9c39-66e3dbc32ec0', '27ebed4c-4311-5338-bfde-9fe5a325d91f', 'الفعل الثلاثيّ المجرّد هو الذي:', '[{"id":"a","text":"زِيدَ عليه حرفان"},{"id":"b","text":"حروفُه كلُّها أصليّة (ثلاثة) لا زيادةَ فيه"},{"id":"c","text":"يبدأ بهمزة وصل"},{"id":"d","text":"ينتهي بألف"}]'::jsonb, 'b', 'الفعل الثلاثيّ المجرّد حروفُه الثلاثةُ كلُّها أصليّة، لا زيادةَ فيه، ووزنُه فَعَلَ، مثل «كَتَبَ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('02e3ba48-82c4-51f2-9a95-b148a294c173', '27ebed4c-4311-5338-bfde-9fe5a325d91f', 'ما وزنُ الفعل «جَلَسَ»؟', '[{"id":"a","text":"فعَّلَ"},{"id":"b","text":"أفعَلَ"},{"id":"c","text":"فَعَلَ"},{"id":"d","text":"استفعَلَ"}]'::jsonb, 'c', '«جَلَسَ» ثلاثيٌّ مجرّد: الجيمُ فاء، اللامُ عين، السينُ لام، بنفس الحركات، فوزنُه «فَعَلَ».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('05c663b4-5222-5a6a-b545-f8f73959d691', '27ebed4c-4311-5338-bfde-9fe5a325d91f', 'ما وزنُ الفعل «أكرمَ»؟', '[{"id":"a","text":"أفعَلَ"},{"id":"b","text":"فَعَلَ"},{"id":"c","text":"فعَّلَ"},{"id":"d","text":"تفعّلَ"}]'::jsonb, 'a', '«أكرمَ» مزيدٌ بحرفٍ واحد (الهمزة في أوّله)، وأصلُه «كرم». فوزنُه «أفعَلَ» (الهمزةُ زائدةٌ تُكتبُ كما هي).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('32de45dc-e7a0-5e9a-bf31-02cf67cf8823', '27ebed4c-4311-5338-bfde-9fe5a325d91f', 'ما وزنُ الفعل «علَّمَ»؟', '[{"id":"a","text":"فاعَلَ"},{"id":"b","text":"انفعَلَ"},{"id":"c","text":"استفعَلَ"},{"id":"d","text":"فعَّلَ"}]'::jsonb, 'd', '«علَّمَ» مزيدٌ بتضعيف العين (اللام مشدّدة)، وأصلُه «علم». نزِنُ الشدّةَ بتكرار العين: «فعَّلَ».', 4)
