INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f2e3802a-be1c-5f4c-a7e9-1cd29fd55fbe', '27ebed4c-4311-5338-bfde-9fe5a325d91f', 'أيُّ هذه الأفعال مزيدٌ (طرأت عليه زيادة)؟', '[{"id":"a","text":"كَتَبَ"},{"id":"b","text":"استقبلَ"},{"id":"c","text":"نَصَرَ"},{"id":"d","text":"شَرِبَ"}]'::jsonb, 'b', '«استقبلَ» مزيدٌ بثلاثة أحرف (همزةُ وصل + سين + تاء)، وأصلُه «قبل»، وزنُه «استفعَلَ». أمّا كَتَبَ ونَصَرَ وشَرِبَ فمجرّدةٌ على فَعَلَ/فَعِلَ.', 5)
ON CONFLICT (id) DO UPDATE SET
