INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('58f82c9c-62e1-5375-b3e0-3ff6b8bd2767', 'e9d6311d-91de-5a0f-8c00-e24dc16c3153', 'حروفُ الميزان الصرفيّ الثلاثة هي:', '[{"id":"a","text":"أ ب ت"},{"id":"b","text":"م ن س"},{"id":"c","text":"ف ع ل"},{"id":"d","text":"ق ر أ"}]'::jsonb, 'c', 'الميزان الصرفيّ يقوم على الحروف النموذجيّة «ف ع ل»: الفاءُ للحرف الأوّل، والعينُ للثاني، واللامُ للثالث.', 1)
