INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f88f0613-0476-5c78-8c24-505fd1221aa2', 'e9d6311d-91de-5a0f-8c00-e24dc16c3153', 'كم حرفًا أصليًّا في الفعل الثلاثيّ المجرّد؟', '[{"id":"a","text":"حرفان"},{"id":"b","text":"ثلاثة"},{"id":"c","text":"أربعة"},{"id":"d","text":"خمسة"}]'::jsonb, 'b', 'الفعل الثلاثيّ المجرّد حروفُه ثلاثةٌ كلُّها أصليّة، فيقابلُها في الميزان ثلاثةُ حروف: ف ع ل.', 3)
