INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e528926c-c2ec-5538-8f0e-8119fef110b5', 'e9d6311d-91de-5a0f-8c00-e24dc16c3153', 'أيُّ فعلٍ منها مجرّدٌ (لا زيادةَ فيه)؟', '[{"id":"a","text":"شَرِبَ"},{"id":"b","text":"أرسلَ"},{"id":"c","text":"انكسرَ"},{"id":"d","text":"استعملَ"}]'::jsonb, 'a', '«شَرِبَ» ثلاثيٌّ مجرّد على «فَعِلَ» (لا زيادة). أمّا أرسلَ (أفعل) وانكسرَ (انفعل) واستعملَ (استفعل) فمزيدةٌ بحروفٍ زائدة.', 6)
