INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d9abbf6c-0869-509f-b7a2-535467680896', 'e23db367-6309-520f-9214-313fdb85bccd', 'كيف نزِنُ الحرفَ المشدّدَ في الفعل المزيد؟', '[{"id":"a","text":"نحذفُه من الميزان"},{"id":"b","text":"نضعُ مكانه همزة"},{"id":"c","text":"نضعُ مكانه ألفًا"},{"id":"d","text":"نكرّرُ الحرفَ المقابلَ له في الميزان (الشدّةُ حرفان)"}]'::jsonb, 'd', 'الحرفُ المشدّدُ أصلُه حرفان؛ فنزِنُه بتكرار الحرف المقابل في الميزان: «قدَّم» العينُ مشدّدةٌ ← «فعَّل».', 1)
