INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5a69db8c-cb40-52df-bd69-b4f47ac98b00', 'e23db367-6309-520f-9214-313fdb85bccd', 'ما الأحرفُ الأصليّةُ في الفعل «استخرجَ»، وما وزنُه؟', '[{"id":"a","text":"الأصلُ «خرج» والوزنُ «استفعَلَ» (الهمزةُ والسينُ والتاءُ زوائد)"},{"id":"b","text":"الأصلُ «استخ» والوزنُ «فَعَلَ»"},{"id":"c","text":"الأصلُ «سخر» والوزنُ «فعَّلَ»"},{"id":"d","text":"لا أصلَ له"}]'::jsonb, 'a', 'نجرّدُ الزوائدَ (همزةُ الوصل + السين + التاء) فيبقى الأصلُ «خرج»: الخاءُ فاء، الراءُ عين، الجيمُ لام. فالوزنُ «استفعَلَ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e88d14f2-3437-549a-b718-d7a0d5ea9d2e', 'e23db367-6309-520f-9214-313fdb85bccd', 'أيُّ فعلين يتّفقان في الوزن؟', '[{"id":"a","text":"كَتَبَ وأكرمَ"},{"id":"b","text":"علَّمَ واستقبلَ"},{"id":"c","text":"جلسَ وانكسرَ"},{"id":"d","text":"قدَّمَ وعلَّمَ (كلاهما على فعَّلَ)"}]'::jsonb, 'd', '«قدَّمَ» و«علَّمَ» كلاهما مزيدٌ بتضعيف العين، فوزنُهما «فعَّلَ». أمّا الأزواجُ الأخرى فمختلفةُ الأوزان (فَعَلَ مع أفعَلَ…).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3b51505f-c400-5191-aeec-6653878fb735', 'e23db367-6309-520f-9214-313fdb85bccd', 'ما وزنُ الفعل «اخضرَّ» (صارَ أخضرَ)؟', '[{"id":"a","text":"افعَلَّ (همزةُ وصل + تضعيف اللام)"},{"id":"b","text":"فاعَلَ"},{"id":"c","text":"تفاعلَ"},{"id":"d","text":"استفعَلَ"}]'::jsonb, 'a', '«اخضرَّ» أصلُه «خضر»، زِيدت همزةُ الوصل في أوّله وشُدّدت اللام (الراء). فوزنُه «افعَلَّ» (نزِنُ الشدّةَ بتكرار اللام).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('75790878-75f3-51d1-89fd-bdfb3015775d', 'eb28b668-2a4c-57aa-b6bf-3e730fedc84e', 'arabic-5eme', '📝 مراجعة ⭐⭐: المجرّد والمزيد (متوسط)', 2, 75, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
