INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3b212051-8701-5aba-8d80-226c37a0c9a7', '75790878-75f3-51d1-89fd-bdfb3015775d', 'وزنُ الفعل المزيد يختلفُ عن «فَعَلَ» لأنّ:', '[{"id":"a","text":"حروفَه الزائدةَ تُضاف إلى الميزان كما هي"},{"id":"b","text":"حركاتِه تُحذف"},{"id":"c","text":"أصلَه يصير حرفين"},{"id":"d","text":"الميزانَ يتغيّر إلى ق ر أ"}]'::jsonb, 'a', 'في المزيد نزيدُ في الميزان مثلَ الزيادة في الفعل: الهمزةُ والتاءُ والسينُ والنونُ تُكتبُ في الميزان كما هي، مثل «أكرمَ ← أفعَلَ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('862436b8-c30f-5e80-8e6d-6c1e8b70cc61', '75790878-75f3-51d1-89fd-bdfb3015775d', 'ما وزنُ الفعل «نَزَلَ»؟', '[{"id":"a","text":"أفعَلَ"},{"id":"b","text":"تفعّلَ"},{"id":"c","text":"فَعَلَ"},{"id":"d","text":"افتعَلَ"}]'::jsonb, 'c', '«نَزَلَ» ثلاثيٌّ مجرّد: النونُ فاء، الزايُ عين، اللامُ لام، بنفس الفتحات، فوزنُه «فَعَلَ».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3b7e2817-1aad-551c-adbf-b1777440dbd5', '75790878-75f3-51d1-89fd-bdfb3015775d', 'ما وزنُ الفعل «تكاتبَ»؟', '[{"id":"a","text":"فعَّلَ"},{"id":"b","text":"أفعَلَ"},{"id":"c","text":"استفعَلَ"},{"id":"d","text":"تفاعلَ"}]'::jsonb, 'd', '«تكاتبَ» مزيدٌ بحرفين: التاء في أوّله والألف بعد الفاء، وأصلُه «كتب». فوزنُه «تفاعلَ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('213db28a-d6d1-56eb-8d24-5721b0c04aca', '75790878-75f3-51d1-89fd-bdfb3015775d', 'ما وزنُ الفعل «أنزلَ»؟', '[{"id":"a","text":"فَعَلَ"},{"id":"b","text":"أفعَلَ"},{"id":"c","text":"فاعَلَ"},{"id":"d","text":"تفعّلَ"}]'::jsonb, 'b', '«أنزلَ» مزيدٌ بهمزةٍ في أوّله، وأصلُه «نزل». فوزنُه «أفعَلَ» (الهمزةُ زائدةٌ والنونُ فاء والزايُ عين واللامُ لام).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2a1e28d7-9a89-50de-a2e0-d5cf44b4f500', '75790878-75f3-51d1-89fd-bdfb3015775d', 'رتّب الأفعال حسب عدد حروف الزيادة (من المجرّد إلى الأكثر زيادة): «فتحَ، استفتحَ، فتّحَ».', '[{"id":"a","text":"فتحَ (مجرّد) ← فتّحَ (زيادة حرف) ← استفتحَ (زيادة ثلاثة أحرف)"},{"id":"b","text":"استفتحَ ← فتّحَ ← فتحَ"},{"id":"c","text":"فتّحَ ← فتحَ ← استفتحَ"},{"id":"d","text":"كلُّها متساوية"}]'::jsonb, 'a', '«فتحَ» مجرّدٌ (فَعَلَ) لا زيادة. «فتّحَ» (فعَّلَ) زيادةُ حرفٍ واحد (تضعيف). «استفتحَ» (استفعَلَ) زيادةُ ثلاثة أحرف. فالترتيب الصاعد كما في (أ).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3da9282a-8d83-52c2-8582-012769643404', '75790878-75f3-51d1-89fd-bdfb3015775d', 'ما وزنُ الفعل «تدحرجَ» (وهو من «دحرج» الرباعيّ)؟', '[{"id":"a","text":"تفعّلَ"},{"id":"b","text":"أفعَلَ"},{"id":"c","text":"تفعللَ (من فعلل الرباعيّ بزيادة التاء)"},{"id":"d","text":"استفعَلَ"}]'::jsonb, 'c', 'أصلُه «دحرج» رباعيٌّ مجرّدٌ وزنُه «فعللَ» (بلامين)، وبزيادة التاء صار «تدحرجَ» على «تفعللَ». فلا يُوزنُ بـ«تفعّلَ» لأنّ أصله أربعةُ أحرف لا ثلاثة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

