INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9e11d322-7a83-5088-b14d-ba8c54155aa4', '4138c027-563f-5271-b611-34337f11efe3', 'ما وزنُ الفعل «اطمأنَّ»؟', '[{"id":"a","text":"افتعَلَّ"},{"id":"b","text":"افعَلَلَّ (همزةُ وصل + تضعيف، من الرباعيّ «طمأن»)"},{"id":"c","text":"استفعَلَ"},{"id":"d","text":"تفعّلَ"}]'::jsonb, 'b', 'أصلُه الرباعيّ «طمأن» (فعلل)، زِيدت همزةُ الوصل في أوّله وشُدّدت النون. فوزنُه «افعَلَلَّ» على بناء الرباعيّ المزيد، لا «افتعل» الثلاثيّ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
