INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ac170bdd-4240-5153-bbe0-6678f519fb8a', '4138c027-563f-5271-b611-34337f11efe3', 'فعلان وزنُهما واحدٌ رغم اختلاف حروفهما: «استعملَ» و……؟', '[{"id":"a","text":"علّمَ"},{"id":"b","text":"كتبَ"},{"id":"c","text":"قاتلَ"},{"id":"d","text":"استخرجَ (كلاهما على استفعَلَ)"}]'::jsonb, 'd', '«استعملَ» (أصلُه عمل) و«استخرجَ» (أصلُه خرج) كلاهما مزيدٌ بهمزة وصلٍ وسينٍ وتاء، فوزنُهما «استفعَلَ». أمّا علّمَ (فعَّل) وكتبَ (فَعَلَ) وقاتلَ (فاعَلَ) فمختلفة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eab3d701-d72d-5b02-a00e-c8bd9d1e161c', '4138c027-563f-5271-b611-34337f11efe3', 'زِنِ الفعل «اعتمدَ» وبيّن الزائدَ والأصليّ.', '[{"id":"a","text":"الوزنُ «افتعَلَ»: الهمزةُ والتاءُ زائدتان، والأصلُ «عمد» (العينُ فاء، الميمُ عين، الدالُ لام)"},{"id":"b","text":"الوزنُ «أفعَلَ» والأصلُ «عتمد»"},{"id":"c","text":"الوزنُ «فعَّلَ» والأصلُ «عتم»"},{"id":"d","text":"الوزنُ «فَعَلَ» لا زيادةَ فيه"}]'::jsonb, 'a', 'نجرّدُ الزوائدَ (همزةُ الوصل + التاء بعد الفاء) فيبقى الأصلُ «عمد». فالوزنُ «افتعَلَ»، والتاءُ من أحرف الزيادة في هذا الوزن.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('10143fcd-d366-5ee5-adaf-330c7ca74d63', '4138c027-563f-5271-b611-34337f11efe3', 'ما وزنُ الفعل «ازدحمَ»؟ (انتبه لإبدال تاء الافتعال)', '[{"id":"a","text":"استفعَلَ"},{"id":"b","text":"فاعَلَ"},{"id":"c","text":"افتعَلَ (أصلُه «زحم»، وأُبدلت تاءُ الافتعال دالًا بعد الزاي)"},{"id":"d","text":"تفعّلَ"}]'::jsonb, 'c', 'أصلُه «زحم»، وعلى وزن «افتعَلَ» تصير «ازتحم»، لكنّ تاءَ الافتعال تُبدلُ دالًا بعد الزاي فتصير «ازدحمَ». فالوزنُ «افتعَلَ» مع إبدالٍ صوتيّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0db77778-cc6e-59a8-b6e2-5a7dc5c5cc27', '4138c027-563f-5271-b611-34337f11efe3', 'أيُّ المجموعات كلُّ أفعالها مزيدةٌ بحرفٍ واحدٍ فقط؟', '[{"id":"a","text":"قدّمَ، أكرمَ، شاركَ (فعَّل، أفعَل، فاعَل)"},{"id":"b","text":"كتبَ، جلسَ، شربَ"},{"id":"c","text":"استقبلَ، انكسرَ، تعلّمَ"},{"id":"d","text":"ازدحمَ، اطمأنَّ، اخضرَّ"}]'::jsonb, 'a', '«قدّمَ» (فعَّل: تضعيف) و«أكرمَ» (أفعَل: همزة) و«شاركَ» (فاعَل: ألف) كلُّها زيادةُ حرفٍ واحد. (ب) مجرّدة، و(ج) و(د) زيادةُ حرفين أو أكثر.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bbf0b3fb-c911-5c7a-90ec-51de9f8d9c3e', '4138c027-563f-5271-b611-34337f11efe3', 'حوّل «علِمَ» إلى صيغةٍ على وزن «استفعَلَ» مع بيان المعنى.', '[{"id":"a","text":"أعلمَ"},{"id":"b","text":"علّمَ"},{"id":"c","text":"تعلّمَ"},{"id":"d","text":"استعلمَ (طلبَ العلمَ والمعرفةَ، على وزن استفعَلَ)"}]'::jsonb, 'd', 'بزيادة همزة الوصل والسين والتاء على الأصل «علم» نحصلُ على «استعلمَ» (طلبَ العلمَ) على وزن «استفعَلَ». أمّا أعلمَ (أفعَل) وعلّمَ (فعَّل) وتعلّمَ (تفعّل) فأوزانٌ أخرى.', 6)
ON CONFLICT (id) DO UPDATE SET
