INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f47eb7e6-f831-51dc-a422-3fd2104bcb7e', '4ea17e9b-f964-5c21-8462-c6d4781b58cb', 'نقابلُ الحرفَ الثاني من الفعل في الميزان بـ:', '[{"id":"a","text":"الفاء"},{"id":"b","text":"اللام"},{"id":"c","text":"العين"},{"id":"d","text":"الميم"}]'::jsonb, 'c', 'في الميزان الصرفيّ نقابلُ الحرفَ الأوّل بالفاء، والثاني بالعين، والثالث باللام. فالحرفُ الثاني يقابلُه العين.', 1)
