INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('733ae60d-f71b-5caa-8183-ecac67a3409d', '4ea17e9b-f964-5c21-8462-c6d4781b58cb', 'ما وزنُ الفعل «اجتمعَ»؟', '[{"id":"a","text":"أفعَلَ"},{"id":"b","text":"فاعَلَ"},{"id":"c","text":"فعَّلَ"},{"id":"d","text":"افتعَلَ"}]'::jsonb, 'd', '«اجتمعَ» أصلُه «جمع»، زِيدت همزةُ الوصل والتاءُ بعد الفاء. فالجيمُ فاء، التاءُ زائدة، الميمُ عين، العينُ لام، فوزنُه «افتعَلَ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e9daabc4-9e82-5c23-9312-d5efabe59603', '4ea17e9b-f964-5c21-8462-c6d4781b58cb', 'ما وزنُ الفعل «انطلقَ»؟', '[{"id":"a","text":"استفعَلَ"},{"id":"b","text":"انفعَلَ"},{"id":"c","text":"فاعَلَ"},{"id":"d","text":"تفعّلَ"}]'::jsonb, 'b', '«انطلقَ» أصلُه «طلق»، زِيدت همزةُ الوصل والنونُ في أوّله. فالطاءُ فاء، اللامُ عين، القافُ لام، فوزنُه «انفعَلَ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('77e60ab3-c2da-57ad-a4ae-92277277309c', '4ea17e9b-f964-5c21-8462-c6d4781b58cb', 'زِنِ الفعل «استقبلَ» وبيّن أحرفَ الزيادة.', '[{"id":"a","text":"الوزنُ «أفعَلَ» والزائدُ الهمزة"},{"id":"b","text":"الوزنُ «افتعَلَ» والزائدُ التاء"},{"id":"c","text":"الوزنُ «استفعَلَ»؛ الزوائدُ همزةُ الوصل والسينُ والتاء، والأصلُ «قبل»"},{"id":"d","text":"الوزنُ «فَعَلَ» لا زيادةَ فيه"}]'::jsonb, 'c', 'نجرّدُ الزوائدَ (همزةُ الوصل + السين + التاء) فيبقى الأصلُ «قبل»: القافُ فاء، الباءُ عين، اللامُ لام. فالوزنُ «استفعَلَ».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('41ac4fe9-f9bd-5787-877a-c978228d979b', '4ea17e9b-f964-5c21-8462-c6d4781b58cb', 'أيُّ فعلٍ وزنُه «تفاعلَ»؟', '[{"id":"a","text":"تبادلَ (أصلُه بدل، بزيادة التاء والألف)"},{"id":"b","text":"أرسلَ"},{"id":"c","text":"علّمَ"},{"id":"d","text":"استعلمَ"}]'::jsonb, 'a', '«تبادلَ» أصلُه «بدل»، زِيدت التاءُ في أوّله والألفُ بعد الفاء، فوزنُه «تفاعلَ». أمّا أرسلَ (أفعَل) وعلّمَ (فعَّل) واستعلمَ (استفعَل) فأوزانٌ مختلفة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

