INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bbb8907e-8d2e-5a6a-928a-f0559db2f2fe', '27221f95-e443-564c-baab-2ed65395bd3b', 'همزة الوصل هي التي:', '[{"id":"a","text":"تُنطقُ في البدء والوصل معًا"},{"id":"b","text":"تُنطقُ في البدء وتسقطُ في الوصل"},{"id":"c","text":"تُكتبُ دائمًا على ياء"},{"id":"d","text":"تأتي في آخر الكلمة"}]'::jsonb, 'b', 'همزة الوصل تُنطقُ إذا بدأنا بها وتسقطُ في درج الكلام (الوصل)، وتُكتبُ ألفًا بلا همزة، مثل «اكتُبْ» و«ال».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3bbe6d06-7b61-5cc5-aa15-25e709f77fe0', '27221f95-e443-564c-baab-2ed65395bd3b', 'أيُّ كلمةٍ همزتُها همزةُ قطع؟', '[{"id":"a","text":"اكتُبْ"},{"id":"b","text":"استمعَ"},{"id":"c","text":"أكلَ"},{"id":"d","text":"انطلقَ"}]'::jsonb, 'c', '«أكلَ» فعلٌ ماضٍ ثلاثيٌّ، همزتُه قطعٌ تُنطقُ بدءًا ووصلًا (وَأَكلَ). أمّا اكتُبْ واستمعَ وانطلقَ فهمزاتُ وصلٍ تسقطُ في الوصل.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4abf5210-91d0-5ce8-88b6-970e9f3ce8b7', '27221f95-e443-564c-baab-2ed65395bd3b', 'على أيّ حرفٍ تُكتبُ الهمزة المتوسّطة في «سُئِلَ»؟', '[{"id":"a","text":"على ياء (ئ) لأنّ الكسرة أقوى الحركتين"},{"id":"b","text":"على واو"},{"id":"c","text":"على ألف"},{"id":"d","text":"على السطر"}]'::jsonb, 'a', 'في «سُئِلَ» الهمزةُ مكسورةٌ وقبلها ضمّة؛ والكسرةُ أقوى من الضمّة، وما يناسبُ الكسرةَ الياء. فتُكتبُ على ياء «ئ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('95a1e90f-de01-5af5-b0e5-07fc0ec3a68a', '27221f95-e443-564c-baab-2ed65395bd3b', 'على أيّ حرفٍ تُكتبُ الهمزة المتطرّفة في «شاطِئ»؟', '[{"id":"a","text":"على ألف"},{"id":"b","text":"على واو"},{"id":"c","text":"على السطر"},{"id":"d","text":"على ياء لأنّ ما قبلها مكسور"}]'::jsonb, 'd', 'الهمزة المتطرّفة تُكتبُ على حرفٍ يناسبُ حركةَ ما قبلها. في «شاطِئ» ما قبل الهمزة مكسورٌ (الطاء)، والكسرةُ يناسبُها الياء، فتُكتبُ على ياء.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5d294b4d-3fab-50ac-b6e6-196ee0fec7df', '27221f95-e443-564c-baab-2ed65395bd3b', 'على أيّ حرفٍ تُكتبُ الهمزة المتوسّطة في «مُؤمن»؟', '[{"id":"a","text":"على ألف"},{"id":"b","text":"على واو لأنّ الضمّة أقوى من السكون"},{"id":"c","text":"على ياء"},{"id":"d","text":"على السطر"}]'::jsonb, 'b', 'في «مُؤمن» الهمزةُ ساكنةٌ وقبلها ضمّة؛ والضمّةُ أقوى من السكون، وما يناسبُ الضمّةَ الواو. فتُكتبُ على واو «ؤ».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

