  ('8860b9be-dc27-507f-87ec-dab96ab8f4a0', '218119ae-33b7-5780-8f1e-a7a09425af1d', 'arabic-5eme', '⭐ تمرين: همزة الوصل والقطع (سهل)', 1, 50, 10, 'practice', 'admin', 1)
