INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8915b2e8-337c-5b6f-ad5e-619d26a28c01', '8860b9be-dc27-507f-87ec-dab96ab8f4a0', 'أيُّ كلمةٍ همزتُها همزةُ وصل؟', '[{"id":"a","text":"اسمٌ"},{"id":"b","text":"أحمدُ"},{"id":"c","text":"إبراهيمُ"},{"id":"d","text":"أرسلَ"}]'::jsonb, 'a', '«اسم» من الأسماء التي همزتُها وصلٌ تسقطُ في الوصل (وسْم). أمّا أحمد وإبراهيم وأرسل فهمزاتُ قطعٍ تُنطقُ دائمًا.', 1)
