INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1bfdc45e-279f-552c-8d0a-b94c9db2454a', '8860b9be-dc27-507f-87ec-dab96ab8f4a0', 'كيف نتأكّدُ أنّ الهمزة همزةُ قطع؟', '[{"id":"a","text":"نعدُّ حروفَ الكلمة"},{"id":"b","text":"ننظرُ إلى آخر الكلمة"},{"id":"c","text":"نضعُ قبلها واوًا وننطقها موصولةً؛ فإن نُطقت الهمزةُ فهي قطع"},{"id":"d","text":"نحذفُ أوّل الكلمة"}]'::jsonb, 'c', 'نختبرُ الهمزةَ بوصلها بما قبلها (واو/فاء)؛ فإن بقيت منطوقةً فهي قطع (وَأكلَ)، وإن سقطت فهي وصل (وكْتُبْ).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('55d53e57-e613-5af8-9856-eb31044b54c3', '8860b9be-dc27-507f-87ec-dab96ab8f4a0', 'أمرُ الفعل الثلاثيّ «كتبَ» هو «اكتُبْ»، وهمزتُه:', '[{"id":"a","text":"همزةُ قطع"},{"id":"b","text":"همزةُ وصل (تسقطُ في الوصل)"},{"id":"c","text":"همزةٌ متطرّفة"},{"id":"d","text":"لا همزةَ فيه"}]'::jsonb, 'b', 'أمرُ الفعل الثلاثيّ همزتُه وصلٌ تُكتبُ ألفًا بلا همزة وتسقطُ في الوصل: «وكْتُبْ». فهمزةُ «اكتُبْ» وصل.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('be0799a7-1768-541a-a4bc-33b8581c77e2', '8860b9be-dc27-507f-87ec-dab96ab8f4a0', 'على أيّ حرفٍ تُكتبُ الهمزة المتوسّطة في «رَأْس»؟', '[{"id":"a","text":"على ياء"},{"id":"b","text":"على واو"},{"id":"c","text":"على السطر"},{"id":"d","text":"على ألف لأنّ الفتحة أقوى الحركتين هنا"}]'::jsonb, 'd', 'في «رَأْس» الهمزةُ ساكنةٌ وقبلها فتحة؛ والفتحةُ أقوى من السكون، وما يناسبُ الفتحةَ الألف. فتُكتبُ على ألف «أ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bfc6e3c3-f130-545a-8fb4-4838f85da29a', '8860b9be-dc27-507f-87ec-dab96ab8f4a0', 'ما الكتابةُ الصحيحةُ لأمر الفعل «جلسَ»؟', '[{"id":"a","text":"اجلِسْ (بهمزة وصلٍ، ألفٌ بلا همزة)"},{"id":"b","text":"إجلِسْ (بهمزة قطعٍ مكسورة)"},{"id":"c","text":"أجلِسْ (بهمزة قطعٍ مفتوحة)"},{"id":"d","text":"ءجلِسْ"}]'::jsonb, 'a', 'أمرُ الثلاثيّ همزتُه وصلٌ تُكتبُ ألفًا مجرّدةً بلا همزة: «اجلِسْ». كتابتُها بهمزة قطعٍ («إجلِسْ» أو «أجلِسْ») خطأٌ شائع.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7c59e9da-a1ad-50ce-befe-22cdd1344add', '8860b9be-dc27-507f-87ec-dab96ab8f4a0', 'على أيّ حرفٍ تُكتبُ الهمزة المتطرّفة في «قرأَ»؟', '[{"id":"a","text":"على ياء"},{"id":"b","text":"على واو"},{"id":"c","text":"على ألف لأنّ ما قبلها مفتوح"},{"id":"d","text":"على السطر"}]'::jsonb, 'c', 'الهمزة المتطرّفة تُكتبُ على حرفٍ يناسبُ حركةَ ما قبلها. في «قرأَ» ما قبل الهمزة مفتوحٌ (الراء)، والفتحةُ يناسبُها الألف، فتُكتبُ على ألف.', 6)
