INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3b04bc11-c49a-5951-b2cc-c5bb029d4618', '4842ba31-b0f6-512c-a9e2-12722ba68c26', 'ما ترتيبُ الحركات من الأقوى إلى الأضعف في كتابة الهمزة المتوسّطة؟', '[{"id":"a","text":"الفتحة ← الضمّة ← الكسرة ← السكون"},{"id":"b","text":"السكون ← الفتحة ← الضمّة ← الكسرة"},{"id":"c","text":"الضمّة ← الكسرة ← الفتحة ← السكون"},{"id":"d","text":"الكسرة ← الضمّة ← الفتحة ← السكون"}]'::jsonb, 'd', 'قوّةُ الحركات للهمزة المتوسّطة: الكسرةُ أقوى، ثمّ الضمّة، ثمّ الفتحة، ثمّ السكون. ونكتبُ الهمزةَ على حرفٍ يناسبُ أقواها.', 1)
