INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9b8ddb83-9f0b-5606-80aa-5597554d0b14', '4842ba31-b0f6-512c-a9e2-12722ba68c26', 'على أيّ حرفٍ تُكتبُ الهمزة المتطرّفة في «دفْء»؟', '[{"id":"a","text":"على ألف"},{"id":"b","text":"على ياء"},{"id":"c","text":"على السطر لأنّ ما قبلها ساكن"},{"id":"d","text":"على واو"}]'::jsonb, 'c', 'الهمزة المتطرّفة بعد ساكنٍ صحيح تُكتبُ على السطر. في «دفْء» ما قبل الهمزة ساكنٌ (الفاء)، فتُكتبُ على السطر «ء».', 3)
