  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('283fe9ff-7175-53cc-9f44-2dd1c96afd41', '4842ba31-b0f6-512c-a9e2-12722ba68c26', 'ما الكلمةُ المكتوبةُ خطأً؟ (الصواب همزةٌ على واو)', '[{"id":"a","text":"لُئْلُؤ"},{"id":"b","text":"بئر"},{"id":"c","text":"شاطئ"},{"id":"d","text":"مسْأَلة"}]'::jsonb, 'a', '«لؤلؤ» همزتُها الأولى ساكنةٌ وقبلها ضمّة، والضمّةُ أقوى، فتُكتبُ على واو «ؤ» لا على ياء؛ فالصواب «لُؤْلُؤ» لا «لُئْلُؤ». الباقي صحيح.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4e3d7b02-a8b8-50ce-834b-89bb9dd63b0e', '4842ba31-b0f6-512c-a9e2-12722ba68c26', 'على أيّ حرفٍ تُكتبُ الهمزة المتطرّفة في «تباطؤ»؟', '[{"id":"a","text":"على ألف"},{"id":"b","text":"على ياء"},{"id":"c","text":"على السطر"},{"id":"d","text":"على واو لأنّ ما قبلها مضموم"}]'::jsonb, 'd', 'الهمزة المتطرّفة تُكتبُ على حرفٍ يناسبُ حركةَ ما قبلها. في «تباطؤ» ما قبل الهمزة مضمومٌ (الطاء)، والضمّةُ يناسبُها الواو، فتُكتبُ على واو «ؤ».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4036dc5c-62b6-5179-b086-3947f490f488', '4842ba31-b0f6-512c-a9e2-12722ba68c26', 'لماذا تُكتبُ همزةُ «تساءَل» على السطر لا على ألف؟', '[{"id":"a","text":"خطأٌ، بل تُكتبُ على ياء"},{"id":"b","text":"لأنّها مفتوحةٌ وقبلها ألفٌ ساكنة، فلا تُكتبُ على ألفٍ ثانيةٍ بل على السطر"},{"id":"c","text":"لأنّ ما قبلها مكسور"},{"id":"d","text":"لأنّها همزةُ وصل"}]'::jsonb, 'b', 'في «تساءَل» الهمزةُ مفتوحةٌ وقبلها ألفٌ (مدّ). كراهةَ توالي ألفين، تُكتبُ الهمزةُ على السطر «ء» لا على ألف. فهذه حالةٌ خاصّةٌ للمتوسّطة المفتوحة بعد ألف.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

