INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4da74382-d395-59d4-83b3-4223d1bfb5bb', 'f934d559-f935-5661-902c-1d21e69e4364', 'الهمزة المتطرّفة تُكتبُ على حرفٍ يناسبُ:', '[{"id":"a","text":"حركةَ الهمزة نفسها"},{"id":"b","text":"أوّلَ الكلمة"},{"id":"c","text":"حركةَ الحرف الذي قبلها"},{"id":"d","text":"آخرَ حرفٍ في الجملة"}]'::jsonb, 'c', 'الهمزة المتطرّفة (في آخر الكلمة) تُكتبُ على حرفٍ يناسبُ حركةَ ما قبلها فقط: فتحة←ألف، ضمّة←واو، كسرة←ياء، ساكن←السطر.', 1)
