  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0b02cf36-e81c-5725-b42c-3dc953538f3e', 'f934d559-f935-5661-902c-1d21e69e4364', 'أيُّ كلمةٍ همزتُها همزةُ قطع؟', '[{"id":"a","text":"إنَّ"},{"id":"b","text":"استمعَ"},{"id":"c","text":"ابنٌ"},{"id":"d","text":"اثنانِ"}]'::jsonb, 'a', '«إنَّ» حرفٌ همزتُه قطعٌ تُنطقُ دائمًا وتُكتبُ بهمزة. أمّا استمعَ وابن واثنان فهمزاتُ وصلٍ تسقطُ في الوصل.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
