  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('63c3d1eb-cc5f-5da1-9868-00c0a2a3f155', 'f934d559-f935-5661-902c-1d21e69e4364', 'على أيّ حرفٍ تُكتبُ الهمزة المتوسّطة في «سَأَلَ»؟', '[{"id":"a","text":"على ياء"},{"id":"b","text":"على واو"},{"id":"c","text":"على السطر"},{"id":"d","text":"على ألف لأنّ الحركتين فتحتان"}]'::jsonb, 'd', 'في «سَأَلَ» الهمزةُ مفتوحةٌ وقبلها فتحة؛ والفتحةُ يناسبُها الألف. فتُكتبُ على ألف «أ».', 3)
