INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('349e261b-bd50-5729-ba24-ef84751d3200', 'f934d559-f935-5661-902c-1d21e69e4364', 'على أيّ حرفٍ تُكتبُ الهمزة المتطرّفة في «ماء»؟', '[{"id":"a","text":"على ألف"},{"id":"b","text":"على السطر لأنّ قبلها ألفًا ساكنة (حرف مدّ)"},{"id":"c","text":"على واو"},{"id":"d","text":"على ياء"}]'::jsonb, 'b', 'الهمزة المتطرّفة بعد حرف مدٍّ ساكن (الألف) تُكتبُ على السطر. في «ماء» قبل الهمزة ألفٌ ساكنة، فتُكتبُ على السطر «ء».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
