  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('18e190cc-f9d3-563b-bf7c-c9d9d4f731d3', 'f934d559-f935-5661-902c-1d21e69e4364', 'اختر الكلمةَ المكتوبةَ صوابًا (همزةٌ متوسّطةٌ على ألف).', '[{"id":"a","text":"سُؤال"},{"id":"b","text":"بِئر"},{"id":"c","text":"مَسْأَلة"},{"id":"d","text":"لؤلؤ"}]'::jsonb, 'c', '«مَسْأَلة» الهمزةُ مفتوحةٌ وقبلها ساكنٌ، والفتحةُ أقوى من السكون فتُكتبُ على ألف «أ». أمّا سؤال (على واو) وبئر (على ياء) ولؤلؤ (على واو) فعلى حروفٍ أخرى.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a17c03df-45e7-5f29-8197-e0dfc94a9265', 'f934d559-f935-5661-902c-1d21e69e4364', 'لماذا تُكتبُ همزةُ «جزءان» على السطر؟', '[{"id":"a","text":"لأنّها متوسّطةٌ مفتوحةٌ وقبلها ساكنٌ صحيح (الزاي)، فتناسبُها كتابةُ السطر"},{"id":"b","text":"لأنّها همزةُ قطع"},{"id":"c","text":"لأنّ ما قبلها مضموم"},{"id":"d","text":"لأنّها في أوّل الكلمة"}]'::jsonb, 'a', 'بإضافة ألف التثنية صارت همزةُ «جزء» متوسّطةً مفتوحةً وقبلها ساكنٌ صحيح (الزاي الساكنة)، فتُكتبُ على السطر «ء»: «جزءان». فهي حالةُ المتوسّطة المفتوحة بعد ساكن.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

