INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f3eff613-f994-56b6-9219-437d4721ccd9', '46132aa8-adc9-5587-82a0-5e91e4999cfe', 'في «رُؤوس»، الهمزةُ متوسّطةٌ مضمومةٌ وقبلها مضموم. على أيّ حرفٍ تُكتب؟', '[{"id":"a","text":"على ياء"},{"id":"b","text":"على واو (الضمّةُ أقوى الحركتين هنا، والضمّةُ يناسبُها الواو)"},{"id":"c","text":"على ألف"},{"id":"d","text":"على السطر"}]'::jsonb, 'b', 'في «رُؤوس» الهمزةُ مضمومةٌ وقبلها ضمّة، فأقوى الحركتين الضمّة، وما يناسبُها الواو. فتُكتبُ على واو «ؤ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6cfbac07-f18b-5688-9688-282c5399bf5f', '46132aa8-adc9-5587-82a0-5e91e4999cfe', 'اختر الكتابةَ الصحيحةَ لكلمة فيها همزةٌ متوسّطةٌ مكسورةٌ بعد ساكن.', '[{"id":"a","text":"أسْؤِلة"},{"id":"b","text":"أسْأِلة"},{"id":"c","text":"أسْءِلة"},{"id":"d","text":"أسْئِلة (الكسرةُ أقوى فتُكتبُ على ياء)"}]'::jsonb, 'd', 'في «أسْئِلة» الهمزةُ مكسورةٌ وقبلها ساكن؛ والكسرةُ أقوى من السكون، وما يناسبُ الكسرةَ الياء. فتُكتبُ على ياء «ئ»: «أسئلة».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
