INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1fe933d5-a1c6-55c8-a021-39e7651e4162', '46132aa8-adc9-5587-82a0-5e91e4999cfe', 'في «شيء»، لماذا تُكتبُ الهمزةُ المتطرّفةُ على السطر؟', '[{"id":"a","text":"لأنّ قبلها ياءً ساكنةً (حرف مدّ)، فتُكتبُ على السطر «ء»"},{"id":"b","text":"لأنّ ما قبلها مفتوح"},{"id":"c","text":"لأنّها همزةُ وصل"},{"id":"d","text":"لأنّها في وسط الكلمة"}]'::jsonb, 'a', 'الهمزة المتطرّفة بعد حرف مدٍّ ساكن تُكتبُ على السطر. في «شيء» قبل الهمزة ياءٌ ساكنة، فتُكتبُ على السطر «ء».', 3)
ON CONFLICT (id) DO UPDATE SET
