INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6d622cbe-a121-5f38-bf70-86fb50ca30fd', '46132aa8-adc9-5587-82a0-5e91e4999cfe', 'أيُّ كلمةٍ كُتبت همزتُها المتطرّفةُ خطأً؟', '[{"id":"a","text":"قارِئ"},{"id":"b","text":"بدأَ"},{"id":"c","text":"مُبتدِئ (الصواب على ياء لأنّ ما قبلها مكسور، وهي صحيحةٌ هكذا) — والخطأُ في «جُرْؤ» إذ تُكتبُ «جَرُؤ»"},{"id":"d","text":"ماء"}]'::jsonb, 'c', 'قارِئ وبدأَ وماء كُتبت صحيحةً (ياء بعد كسرة، ألف بعد فتحة، السطر بعد مدّ). أمّا الفعلُ «جَرُؤ» فما قبل همزته مضمومٌ فتُكتبُ على واو «جَرُؤ» لا «جُرْؤ». فالكتابةُ المعيبةُ هي «جُرْؤ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('476f966b-6698-5ffa-aa6d-e0768e7d816a', '46132aa8-adc9-5587-82a0-5e91e4999cfe', 'ادخل ألفَ التثنية على «بناء» (المنتهية بهمزة بعد ألف) لتصير مثنّى. ما الصواب؟', '[{"id":"a","text":"بناءَين بهمزةٍ على ألف"},{"id":"b","text":"بناءانِ (تبقى الهمزةُ على السطر لأنّها مفتوحةٌ بعد ألف)"},{"id":"c","text":"بناوان"},{"id":"d","text":"بنايان"}]'::jsonb, 'b', 'همزةُ «بناء» بعد ألفٍ؛ في التثنية تصير متوسّطةً مفتوحةً بعد ألف، فتبقى على السطر كراهةَ توالي الألفين: «بناءان». فلا تُكتبُ على ألفٍ ولا تُبدلُ واوًا أو ياء.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('05bf6096-c4d3-5a3f-a18d-65ebeac8c241', '46132aa8-adc9-5587-82a0-5e91e4999cfe', 'رتّب القاعدتين: المتوسّطة تُكتبُ بحسب ……، والمتطرّفة تُكتبُ بحسب ……', '[{"id":"a","text":"كلتاهما بحسب حركة الهمزة فقط"},{"id":"b","text":"المتوسّطة بحسب حركة ما قبلها فقط، والمتطرّفة بحسب أقوى الحركتين"},{"id":"c","text":"كلتاهما بحسب أوّل الكلمة"},{"id":"d","text":"المتوسّطة بحسب أقوى الحركتين (حركتها وحركة ما قبلها)، والمتطرّفة بحسب حركة ما قبلها وحدها"}]'::jsonb, 'd', 'القاعدةُ الجامعة: المتوسّطة نراعي فيها أقوى الحركتين (حركة الهمزة وما قبلها)، أمّا المتطرّفة فنراعي حركةَ ما قبلها وحدها لا حركتها. هذا هو الفرقُ الجوهريّ بينهما.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

