INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5fb40819-14b4-5cea-ad67-cab9e409f085', '7c4c1e49-ec44-5149-acbb-f1bbcefcddc5', 'همزة القطع تُنطقُ:', '[{"id":"a","text":"في البدء والوصل معًا"},{"id":"b","text":"في الوصل فقط"},{"id":"c","text":"لا تُنطقُ أبدًا"},{"id":"d","text":"في آخر الكلمة فقط"}]'::jsonb, 'a', 'همزة القطع تُنطقُ سواءٌ بدأنا بها أو وصلناها بما قبلها، مثل «أكلَ / وَأكلَ»، وتُكتبُ بهمزةٍ على ألف.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('208a335b-4dae-5477-a63e-53780eaf3968', '7c4c1e49-ec44-5149-acbb-f1bbcefcddc5', 'أيُّ كلمةٍ همزتُها وصل؟', '[{"id":"a","text":"أرسلَ"},{"id":"b","text":"إبراهيمُ"},{"id":"c","text":"انكسرَ"},{"id":"d","text":"أكلَ"}]'::jsonb, 'c', '«انكسرَ» فعلٌ خماسيّ همزتُه وصلٌ تسقطُ في الوصل (وَنكسرَ). أمّا أرسلَ وإبراهيم وأكلَ فهمزاتُ قطعٍ تُنطقُ دائمًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4eac0aa2-198d-5da6-a315-033ec0016e13', '7c4c1e49-ec44-5149-acbb-f1bbcefcddc5', 'على أيّ حرفٍ تُكتبُ الهمزة المتوسّطة في «فِئة»؟', '[{"id":"a","text":"على ألف"},{"id":"b","text":"على ياء لأنّ الكسرة (قبلها) أقوى من الفتحة"},{"id":"c","text":"على واو"},{"id":"d","text":"على السطر"}]'::jsonb, 'b', 'في «فِئة» الهمزةُ مفتوحةٌ وقبلها كسرة؛ والكسرةُ أقوى من الفتحة، وما يناسبُ الكسرةَ الياء. فتُكتبُ على ياء «ئ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7749c8c8-1662-5822-bad3-328e643fdb2f', '7c4c1e49-ec44-5149-acbb-f1bbcefcddc5', 'على أيّ حرفٍ تُكتبُ الهمزة المتطرّفة في «جُزء»؟', '[{"id":"a","text":"على ألف"},{"id":"b","text":"على ياء"},{"id":"c","text":"على واو"},{"id":"d","text":"على السطر لأنّ ما قبلها ساكن (الزاي)"}]'::jsonb, 'd', 'الهمزة المتطرّفة بعد ساكنٍ صحيح تُكتبُ على السطر. في «جُزء» ما قبل الهمزة ساكنٌ (الزاي)، فتُكتبُ على السطر «ء».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e12a4e6c-f5d6-52a2-b26f-387223b5e913', '7c4c1e49-ec44-5149-acbb-f1bbcefcddc5', 'اختر الكتابةَ الصحيحةَ لجمع «بئر» على «آبار» مع همزةٍ متوسّطة: «المياهُ في …».', '[{"id":"a","text":"الآبار (بمدّةٍ على الألف، لا همزةَ متوسّطةَ فيها بل همزتان في الأصل أُدغمتا مدًّا)"},{"id":"b","text":"الأابار"},{"id":"c","text":"الءابار"},{"id":"d","text":"الاآبار"}]'::jsonb, 'a', 'أصلُ «آبار»: همزةٌ مفتوحةٌ بعدها ألفُ مدٍّ ساكنة، فتُكتبان مدّةً على الألف «آ»: «الآبار». فلا نكتبُ همزتين متتاليتين ولا همزةً على السطر هنا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dcaaf0ef-cbe5-5121-a72a-8ddc821f66cc', '7c4c1e49-ec44-5149-acbb-f1bbcefcddc5', 'ما القاعدةُ الجامعةُ التي تحكمُ كتابةَ الهمزة المتوسّطة؟', '[{"id":"a","text":"تُكتبُ دائمًا على ألف"},{"id":"b","text":"تُكتبُ بحسب أوّل الكلمة"},{"id":"c","text":"تُكتبُ على حرفٍ يناسبُ أقوى الحركتين: حركة الهمزة وحركة ما قبلها (الكسرة فالضمّة فالفتحة فالسكون)"},{"id":"d","text":"تُكتبُ بحسب آخر الكلمة"}]'::jsonb, 'c', 'القاعدةُ الجامعةُ للهمزة المتوسّطة: ننظرُ إلى حركتها وحركة ما قبلها، ونختارُ الأقوى (الكسرة←ياء، الضمّة←واو، الفتحة←ألف، السكون←السطر). هذا المبدأُ يحلُّ معظمَ الحالات.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

